INSERT INTO `admin_contents` (`id`, `content_type`, `title`, `body`, `is_enabled`, `deleted_at`, `created_at`, `updated_at`) VALUES (1, 'disclaimer', '免责声明', '重要提示：本产品不能替代专业医疗、心理咨询、心理治疗或医学诊断。\\n\\n精神避难所是一个社交媒体焦虑分析工具，旨在帮助用户认识和理解社交媒体引发的焦虑情绪，提供心理学知识和方法参考。\\n\\n核心声明：\\n1. 本产品不替代专业医疗\\n2. 本产品不替代心理咨询\\n3. 本产品不替代心理治疗\\n4. 本产品不提供医学诊断\\n5. 严重风险时请寻求专业帮助\\n\\n如果您正在经历强烈的痛苦或危险想法，请立即联系医院、专业医生、心理咨询师或当地紧急求助渠道。', 1, NULL, '2026-06-15 15:15:16', '2026-06-19 13:20:28');
INSERT INTO `admin_contents` (`id`, `content_type`, `title`, `body`, `is_enabled`, `deleted_at`, `created_at`, `updated_at`) VALUES (2, 'product_intro', '产品说明', '# 精神避难所 — 产品说明\\n\\n精神避难所是一个面向社交媒体焦虑的网站工具。\\n\\n**核心功能：**\\n- 上传社交媒体截图，获得 AI 结构化分析\\n- 识别截图中的人设包装、隐藏信息和比较陷阱\\n- 结合心理学方法（CBT、正念等）提供情绪解释\\n- 百宝箱知识库帮助建立长期抵抗比较焦虑的能力\\n\\n**使用方式：**\\n1. 注册账号并登录\\n2. 上传朋友圈、小红书等平台的截图\\n3. 可选填写你的感受和焦虑强度\\n4. AI 为你生成结构化分析结果\\n5. 阅读分析、提交反馈、查看历史记录\\n\\n**适合人群：**\\n所有在使用社交媒体过程中产生焦虑、困惑、不安、比较、自我否定等负面情绪，并希望获得解释、拆解和帮助的人。', 1, NULL, '2026-06-15 15:15:16', '2026-06-15 15:15:16');
INSERT INTO `admin_contents` (`id`, `content_type`, `title`, `body`, `is_enabled`, `deleted_at`, `created_at`, `updated_at`) VALUES (3, 'tutorial', '新手教程', '# 新手教程\\n\\n**欢迎来到精神避难所！**\\n\\n这是一个帮助你从社交媒体焦虑中抽离出来的工具。\\n\\n**快速上手：**\\n1. **首页** — 浏览温暖的名言和推荐，搜索你需要的内容\\n2. **中间相机按钮** — 点击上传社交媒体截图，开始分析\\n3. **百宝箱** — 浏览知识库，了解焦虑类型、人设套路和应对方法\\n4. **我的** — 查看历史记录、个人笔记、修改账号设置\\n\\n**提示：**\\n- 分析完成后记得提交反馈，帮助我们改进\\n- 可以在历史详情页添加备注和标签，记录你的思考\\n- 使用个人笔记记录你的成长和反思', 1, NULL, '2026-06-15 15:15:16', '2026-06-15 15:15:16');
INSERT INTO `admin_contents` (`id`, `content_type`, `title`, `body`, `is_enabled`, `deleted_at`, `created_at`, `updated_at`) VALUES (4, 'greeting', '首页问候', '今天想聊聊哪条截图？', 1, NULL, '2026-06-15 15:15:16', '2026-06-15 15:15:16');
INSERT INTO `admin_contents` (`id`, `content_type`, `title`, `body`, `is_enabled`, `deleted_at`, `created_at`, `updated_at`) VALUES (5, 'coming_soon', 'Coming Soon', '这个功能还在准备中，第一版暂不开放。我们会在后续版本中逐步推出更多功能，感谢你的耐心和支持。', 1, NULL, '2026-06-15 15:15:16', '2026-06-15 15:15:16');
INSERT INTO `admin_users` (`id`, `user_id`, `role`, `created_at`, `updated_at`) VALUES (1, 1, 'super_admin', '2026-06-19 13:26:36', '2026-06-19 13:26:36');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (13, '你不必在每一次比较里证明自己。', '日迹', 1, 0, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (14, '生活不是排行榜，慢一点也仍然是在生活。', '日迹', 1, 1, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (15, '别人抵达的地方，不一定是你该出发的方向。', '日迹', 1, 2, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (16, '你看到的是别人的片段，不是自己的判决书。', '日迹', 1, 3, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (17, '今天没有赢，也不等于今天作废。', '日迹', 1, 4, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (18, '允许自己羡慕，也允许自己不因此贬低自己。', '日迹', 1, 5, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (19, '真正需要照顾的，不是面子，是那个被刺激到的自己。', '日迹', 1, 6, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (20, '你可以不完美，也可以继续被认真对待。', '日迹', 1, 7, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (21, '情绪来得很急，不代表你必须马上行动。', '日迹', 1, 8, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (22, '先把手机放下，再把自己捡回来。', '日迹', 1, 9, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (23, '有些答案不是想出来的，是安静下来后慢慢出现的。', '日迹', 1, 10, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (24, '不要用一个夜晚的情绪，给整个人生下结论。', '日迹', 1, 11, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (25, '你现在的慌张，不等于事情已经失控。', '日迹', 1, 12, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (26, '被忽略的感觉很痛，但它不能定义你的价值。', '日迹', 1, 13, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (27, '关系需要回应，但你不必用反复检查换取安全。', '日迹', 1, 14, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (28, '沉默有很多原因，不一定都是拒绝。', '日迹', 1, 15, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (29, '你可以在没有被点赞的时候，仍然真实存在。', '日迹', 1, 16, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (30, '数据会波动，人的价值不该跟着后台曲线起落。', '日迹', 1, 17, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (31, '不是所有被看见的东西，都比没被看见的东西重要。', '日迹', 1, 18, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (32, '你不需要把生活拍得很好，才算真的过着生活。', '日迹', 1, 19, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (33, '真正属于你的进步，未必适合发成动态。', '日迹', 1, 20, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (34, '有些努力安静得不像成果，但它们依然算数。', '日迹', 1, 21, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (35, '别人的高光不是你的低谷证明。', '日迹', 1, 22, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (36, '你可以承认落差，同时不把自己打碎。', '日迹', 1, 23, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (37, '慢不是失败，可能只是你在走一条更长的路。', '日迹', 1, 24, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (38, '不要因为别人跑得快，就否定自己正在走。', '日迹', 1, 25, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (39, '你的生活不需要随时向观众交代。', '日迹', 1, 26, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (40, '能不发布，也是一种拥有生活的方式。', '日迹', 1, 27, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (41, '你不是素材，也不是人设，你是一个正在生活的人。', '日迹', 1, 28, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (42, '比起表现得稳定，更重要的是慢慢稳定下来。', '日迹', 1, 29, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (43, '有些疲惫不是懒，是身体在提醒你停一停。', '日迹', 1, 30, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (44, '你可以休息，不必先证明自己已经足够努力。', '日迹', 1, 31, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (45, '不是每一次停下，都是退步。', '日迹', 1, 32, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (46, '恢复也是一种进展，只是它不总是显眼。', '日迹', 1, 33, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (47, '你可以先活过今天，再讨论远方。', '日迹', 1, 34, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (48, '未来很大，但你现在只需要走下一步。', '日迹', 1, 35, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (49, '焦虑会催你立刻解决一生，但生活通常只要求下一件事。', '日迹', 1, 36, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (50, '不要把一次失败，扩写成整个人的失败。', '日迹', 1, 37, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (51, '有些事没做好，只说明那件事没做好。', '日迹', 1, 38, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (52, '你可以改进自己，但不必恨自己才开始。', '日迹', 1, 39, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (53, '真正的成长，不该只靠羞辱来启动。', '日迹', 1, 40, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (54, '如果一句话只会把你打垮，它就不是提醒。', '日迹', 1, 41, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (55, '温柔不是纵容，是给改变留出空间。', '日迹', 1, 42, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (56, '你可以对自己诚实，也可以对自己善良。', '日迹', 1, 43, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (57, '承认难受，不等于承认自己输了。', '日迹', 1, 44, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (58, '哭不是退化，是情绪终于找到了出口。', '日迹', 1, 45, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (59, '你不必解释所有难过，才配得到安慰。', '日迹', 1, 46, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (60, '有些痛苦没有漂亮名字，但它依然是真的。', '日迹', 1, 47, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (61, '先别急着讨厌自己，先看看你经历了什么。', '日迹', 1, 48, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (62, '人不是因为脆弱才难过，而是因为真的在乎。', '日迹', 1, 49, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (63, '在乎不是错，失去边界才会让你受伤。', '日迹', 1, 50, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (64, '喜欢一个人，不该让你完全失去自己。', '日迹', 1, 51, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (65, '被爱不该只靠猜，表达也不该只靠试探。', '日迹', 1, 52, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (66, '有些消息可以晚点回，有些决定也可以晚点做。', '日迹', 1, 53, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (67, '当你很想证明自己被爱，先确认自己是否正在害怕。', '日迹', 1, 54, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (68, '安全感不能全靠刷新来获得。', '日迹', 1, 55, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (69, '如果你一直在等一个提示音，可能更需要一次真实对话。', '日迹', 1, 56, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (70, '手机会显示已读，却不会显示全部原因。', '日迹', 1, 57, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (71, '不要把对方的一次延迟，直接翻译成不爱。', '日迹', 1, 58, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (72, '你可以渴望回应，也可以不被等待吞掉。', '日迹', 1, 59, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (73, '一段关系的质量，不只藏在屏幕通知里。', '日迹', 1, 60, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (74, '真正重要的人，也需要现实里的相处来确认。', '日迹', 1, 61, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (75, '不要让一张合照，替你判断整段友谊。', '日迹', 1, 62, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (76, '你缺席了一次聚会，不等于被生活除名。', '日迹', 1, 63, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (77, '别人的热闹，不自动说明你的孤独失败了。', '日迹', 1, 64, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (78, '孤独不是空白，它有时是在给自己留位置。', '日迹', 1, 65, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (79, '一个人的夜晚，也可以不是被世界丢下。', '日迹', 1, 66, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (80, '你可以想被看见，但不用把自己交给所有目光。', '日迹', 1, 67, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (81, '表达不是考试，不必预判每一个观众。', '日迹', 1, 68, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (82, '你可以删掉一条动态，也可以不删掉自己。', '日迹', 1, 69, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (83, '旧内容证明你曾经那样想过，不证明你永远只能那样。', '日迹', 1, 70, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (84, '成长有时就是，允许过去的自己不够成熟。', '日迹', 1, 71, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (85, '你不需要把每个版本的自己都审判一遍。', '日迹', 1, 72, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (86, '变化不是背叛自己，可能是在更接近自己。', '日迹', 1, 73, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (87, '买下一个东西，未必能买到那个想成为的自己。', '日迹', 1, 74, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (88, '先问问自己想要什么，再问它是否值得付款。', '日迹', 1, 75, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (89, '限时不等于必须，错过也不等于失败。', '日迹', 1, 76, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (90, '不是每一种精致生活，都适合成为你的生活。', '日迹', 1, 77, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (91, '有些向往只是被刺激出来的，不必立刻执行。', '日迹', 1, 78, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (92, '热搜很急，但你的神经系统也需要休息。', '日迹', 1, 79, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (93, '关注世界，不等于要用自己的睡眠抵押。', '日迹', 1, 80, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (94, '你可以关心灾难，也可以保护自己的功能。', '日迹', 1, 81, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (95, '不是反复观看痛苦，才算有同情心。', '日迹', 1, 82, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (96, '真正的关心，常常需要行动，也需要停止围观。', '日迹', 1, 83, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (97, '算法会继续推送，但你可以决定何时停下。', '日迹', 1, 84, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (98, '连续出现不等于到处都是，可能只是系统记住了你的停留。', '日迹', 1, 85, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (99, '你不是没有自制力，你可能只是被设计成很难停下。', '日迹', 1, 86, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (100, '能停下，不一定靠意志，也可以靠环境。', '日迹', 1, 87, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (101, '把应用移远一点，也是在把自己拉近一点。', '日迹', 1, 88, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (102, '睡前少一点屏幕，明天就多一点完整的自己。', '日迹', 1, 89, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (103, '真正需要回复的，不一定是屏幕，也可能是身体。', '日迹', 1, 90, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (104, '你不用把所有空白都交给信息流。', '日迹', 1, 91, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (105, '无聊不是敌人，它有时是在邀请你回到自己。', '日迹', 1, 92, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (106, '当你不知道做什么，先做一件很小的真实事情。', '日迹', 1, 93, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (107, '喝水、洗脸、出门走两分钟，也算重新连接现实。', '日迹', 1, 94, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (108, '身体先落地，想法才有地方慢下来。', '日迹', 1, 95, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (109, '呼吸不需要完美，舒服一点就够了。', '日迹', 1, 96, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (110, '先不解释人生，先确认你此刻在哪里。', '日迹', 1, 97, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (111, '当想法太大，就把注意力放回一件小事。', '日迹', 1, 98, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
INSERT INTO `home_quotes` (`id`, `text`, `author`, `is_enabled`, `sort_order`, `deleted_at`, `created_at`, `updated_at`) VALUES (112, '你不是必须立刻想明白，才能继续活着。', '日迹', 1, 99, NULL, '2026-06-19 13:05:25', '2026-06-19 13:05:25');
