INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (1, 1, '为什么朋友圈容易制造比较焦虑', '## 为什么朋友圈容易制造比较焦虑\\n\\n朋友圈是一个高度选择性的展示平台。人们通常只发布生活中的"高光时刻"：旅行、聚餐、成就、甜蜜的恋爱瞬间……\\n\\n**关键认知：**\\n- 你看到的是对方精心挑选的片段，不是完整生活\\n- 朋友不会把烦恼、失败、平淡时刻发到朋友圈\\n- 微信好友数量庞大，每天总有人发布精彩内容，但这不代表"所有人都过得比你好"\\n\\n**应对方法：**\\n1. 提醒自己，朋友圈只是"精选集"，不是"完整纪录片"\\n2. 关注自己今天的生活中值得感恩的小事\\n3. 如果某个人持续让你感到焦虑，考虑暂时屏蔽或减少关注', '看到朋友圈中熟人展示的精彩生活时产生焦虑', NULL, 1, 0, NULL, '2026-06-16 14:13:10', '2026-06-15 15:15:15', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (2, 1, '小红书精致生活焦虑', '## 小红书与精致生活焦虑\\n\\n小红书上的内容普遍经过精心策划和制作。博主们投入大量时间拍摄、修图、写文案，创造出来的是一份"作品"，而不是日常记录。\\n\\n**你需要知道的：**\\n- 那些整齐的书桌背后可能只有这一个角落是整洁的\\n- 那个完美的早餐摆拍可能需要花 30 分钟，但博主不会告诉你\\n- 护肤流程看起来高级，但很多是广告合作\\n\\n**关键是区分"内容创作"和"真实生活"。**', '看到小红书上精致的内容产生生活不如人的感觉', NULL, 1, 0, NULL, '2026-06-16 14:13:10', '2026-06-15 15:15:15', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (3, 1, '微博焦虑与信息过载', '## 微博焦虑与信息过载\\n\\n微博的信息更新速度极快，内容混杂了新闻、情绪、八卦、观点。长时间浏览会让人感到烦躁和无力。\\n\\n**焦虑来源：**\\n- 负面新闻过度曝光导致"世界很糟糕"的错觉\\n- 评论区对立和争吵消耗情绪\\n- FOMO（害怕错过）让人不断刷新\\n\\n**建议：限制每天的社交平台使用时间来管理焦虑。**', '刷微博后感到烦躁不安或信息过载', NULL, 1, 0, NULL, '2026-06-16 14:13:10', '2026-06-15 15:15:15', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (4, 1, '抖音短视频与注意力焦虑', '## 抖音短视频与注意力焦虑\\n\\n短视频平台的设计核心是快速刺激多巴胺分泌。每一条视频都是一次即时的情绪奖励。\\n\\n**影响机制：**\\n- 15 秒一刷的模式训练大脑追求即时满足\\n- 看到别人几秒钟展示的"才华""颜值""生活"容易产生错觉\\n- 长时间刷完感到空虚和疲惫是常态\\n\\n**这不是你的错——产品设计师利用了你的注意力和比较心理。**', '刷抖音后感到空虚、焦虑或自我怀疑', NULL, 1, 0, NULL, '2026-06-16 14:13:10', '2026-06-15 15:15:15', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (5, 1, 'B 站内容焦虑', '## B 站内容焦虑\\n\\nB 站上的内容创作者往往展示了非常出色的能力：学霸的学习方法、UP 主的精致日常、技术大佬的编程能力……\\n\\n**容易产生焦虑的原因：**\\n- 把别人的专业水准和自己的日常状态对比\\n- UP 主的内容是他们的"作品"，经过大量剪辑和准备\\n- 学习方法的视频不等于学习习惯的体现\\n\\n**记住：你看到的是一段经过精心制作的视频，不是对方真实的每一分钟。**', '在 B 站看到优秀 UP 主的内容后产生自我怀疑', NULL, 1, 0, NULL, '2026-06-16 14:13:10', '2026-06-15 15:15:15', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (6, 1, '学习/成绩/上岸焦虑', '## 学习/成绩/上岸焦虑\\n\\n这是社交媒体上最常见的焦虑之一。考研上岸、考公成功、拿到 offer、绩点排名……这些内容高频出现在社交平台上。\\n\\n**焦虑的根源：**\\n- 感觉自己在人生的赛道上落后了\\n- 把别人的阶段性成果当成永恒的优势\\n- 忽视了自己的独特节奏和路径\\n\\n**重要认知：人生不是一场赛跑。每个人的起点、方向、节奏都不一样。**', '看到他人晒成绩、上岸消息时产生焦虑', NULL, 1, 0, NULL, '2026-06-16 14:13:10', '2026-06-15 15:15:15', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (7, 1, '消费与生活方式焦虑', '## 消费与生活方式焦虑\\n\\n社交媒体上充斥着旅行、购物、美食、穿搭等内容。这些内容暗示了一种"理想的生活方式"，让人产生"我的生活不够好"的感觉。\\n\\n**看清本质：**\\n- 许多内容背后是品牌合作和广告\\n- 旅行照片不展示舟车劳顿和消费压力\\n- 消费不是衡量生活质量的唯一标准\\n\\n**真正的富足来自内心的满足感，不是购物车的数量。**', '看到他人的消费和旅行内容产生羡慕和焦虑', NULL, 1, 0, NULL, '2026-06-16 14:13:10', '2026-06-15 15:15:15', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (8, 1, '外貌/身材焦虑', '## 外貌/身材焦虑\\n\\n社交媒体上的照片经过了精心选择、修图、滤镜处理。即使知道这一点，反复观看这些图片仍然可能引发对自己外貌的不满。\\n\\n**你需要了解：**\\n- 大多数社交媒体图片经过滤镜和美颜处理\\n- 光线、角度、姿势都对最终效果影响巨大\\n- 健康和自信比迎合某种审美标准重要得多\\n\\n**身体是你生活的基础，不是你用来展示给别人看的作品。**', '看到他人照片后对自己的外貌产生不满', NULL, 1, 0, NULL, '2026-06-16 14:13:10', '2026-06-15 15:15:15', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (9, 1, '恋爱/亲密关系焦虑', '## 恋爱/亲密关系焦虑\\n\\n社交媒体上展示的恋爱关系通常是甜蜜瞬间，不是完整的相处状态。\\n\\n**隐藏的信息：**\\n- 恋爱不是人生的必需品\\n- 每段关系都有磨合和矛盾，只是别人不会晒出来\\n- 合拍的伴侣值得祝福，但单身也完全可以过得充实和幸福\\n\\n**一段好的关系会让两个人都变得更好，但不需要用别人展示的关系标准来衡量自己。**', '看到他人秀恩爱时产生孤独感或焦虑', NULL, 1, 0, NULL, '2026-06-16 14:13:10', '2026-06-15 15:15:15', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (10, 1, '熟人朋友圈比较焦虑', '## 熟人朋友圈比较焦虑\\n\\n熟人带来的压力往往比陌生人更大。你认识他们，知道他们的背景，所以当他们展示成就时，更容易让你产生"为什么我不行"的想法。\\n\\n**理解这种焦虑：**\\n- 你比较的是对方的全部（含优点）和你的劣势\\n- 熟人不会经常在朋友圈展示他们的失败和烦恼\\n- 每个人展示的都是他们希望被看见的一面\\n\\n**你的成长不需要和别人同步。你只需要比昨天的自己更进一步。**', '看到熟人的动态时产生强烈的比较心理', NULL, 1, 0, NULL, '2026-06-16 14:13:10', '2026-06-15 15:15:15', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (11, 1, '事业/成功焦虑', '## 事业/成功焦虑\\n\\n社交媒体上经常能看到同龄人"创业成功""年入百万""大厂升职"等内容。\\n\\n**看到这些内容时，问自己：**\\n1. 这些信息的真实性如何？\\n2. 即使是真的，它定义了我自己的价值吗？\\n3. 我目前在做什么，是否也在进步？\\n\\n**成功有千万种定义，不要让别人替你定义。**', '看到同龄人事业成功时感到压力和焦虑', NULL, 1, 0, NULL, '2026-06-16 14:13:10', '2026-06-15 15:15:15', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (12, 1, '自律人设与松弛感人设焦虑', '## 自律人设与松弛感人设焦虑\\n\\n社交媒体上有两种看似对立的人设：\\n- **自律达人**：每天 5 点起床、健身、学习、工作、读书……\\n- **松弛感生活者**：看起来毫不费力却生活得很好……\\n\\n**两者的共同点：都是人设包装。**\\n- 自律内容只展示执行结果，不展示坚持的痛苦和失败的时候\\n- 松弛内容可能经过了大量准备和取景\\n- 真实的生活在两者之间：有时候很努力，有时候也需要休息', '同时看到自律和松弛两种人设时产生矛盾焦虑', NULL, 1, 0, NULL, '2026-06-16 14:13:10', '2026-06-15 15:15:15', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (13, 2, '精致女生人设', '## "精致女生"人设\\n\\n这是社交媒体上最常见的女性人设之一。展示内容包括：精致的妆容、整洁的房间、健康的美食、自律的作息……\\n\\n**拆解：**\\n- 只展示精心准备后的状态，不是日常\\n- 维持这种精致需要大量时间和金钱\\n- 视频和图片中的"精致"经过剪辑和修饰\\n\\n**不需要为了迎合别人的标准而改变自己。你的生活节奏由你自己决定。**', '识别社交媒体中"精致女生"形象', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (14, 2, '成熟男生人设', '## "成熟男生"人设\\n\\n展示内容包括：西装打扮、高品质消费、稳重谈吐、事业有成……\\n\\n**拆解：**\\n- 这种展示通常是片段化的\\n- "成熟"不等于消费能力或外形\\n- 真正的成熟是情绪管理和责任承担，无法通过几张图片展示', '识别社交媒体中"成熟男生"形象', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (15, 2, '厉害学生/学霸人设', '## "学霸"人设\\n\\n展示：超整洁笔记、每日学习打卡、绩点截图、名校录取……\\n\\n**拆解：**\\n- 学习是长期的、有时枯燥的过程，社交媒体只展示了结果\\n- 学霸也有学不进去、拖延、焦虑的时候\\n- 学习方法和节奏因人而异，盲目模仿反而可能降低效率', '识别社交媒体中"学霸"形象', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (16, 2, '自律达人', '## "自律达人"人设\\n\\n展示：每天 5 点起床、健身 1 小时、读书、冥想、健康饮食……\\n\\n**拆解：**\\n- 这些展示经过了高度筛选，不包含放弃和失败的时刻\\n- 真实的自律不是完美的日程表，而是长期的习惯\\n- 每个人都有懈怠的时候，只是自律博主不会告诉你', '识别社交媒体中"自律达人"形象', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (17, 2, '松弛感生活者', '## "松弛感生活者"人设\\n\\n展示：慵懒的午后、随性的穿搭、不加修饰的日常……\\n\\n**拆解：**\\n- 这种"松弛感"本身可能是精心策划的\\n- 拍摄的环境、光线、构图都经过了选择\\n- 真实的松弛不需要被展示和证明', '识别社交媒体中"松弛感"形象', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (18, 2, '完美恋爱人设', '## "完美恋爱人设"人设\\n\\n展示：甜蜜的合照、昂贵的礼物、浪漫的约会、动人的文案……\\n\\n**拆解：**\\n- 恋爱关系中的冲突、妥协、平淡不会被展示\\n- 礼物和场景不反映关系的真实质量\\n- 用别人的恋爱标准来衡量自己的感情状态是不公平的', '识别社交媒体中"完美恋爱"形象', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (19, 2, '高消费生活方式人设', '## "高消费生活方式"人设\\n\\n展示：名牌包、豪车、高级餐厅、奢华旅行……\\n\\n**拆解：**\\n- 很多内容是商业合作或租赁拍摄\\n- 消费水平不等同于幸福感和生活质量\\n- 社交媒体放大了物质消费的可见度', '识别社交媒体中"高消费"形象', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (20, 2, '事业成功者人设', '## "事业成功者"人设\\n\\n展示：大厂工牌、高薪 offer、创业成功、团队照片……\\n\\n**拆解：**\\n- 成功背后的压力、失败、运气成分不被展示\\n- 多数人的职业道路有起伏，不是一条直线\\n- 职业成就只是人生众多维度中的一个', '识别社交媒体中"事业成功"形象', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (21, 2, '身材/外貌优势人设', '## "身材/外貌优势"人设\\n\\n展示：健身成果、穿搭、自拍、身材对比……\\n\\n**拆解：**\\n- 光线、角度、姿势、修图的作用远超想象\\n- 专业健身博主有教练、营养师、大量训练时间\\n- 健康的美是多样的，不只有一种标准', '识别社交媒体中"身材外貌"形象', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (22, 2, '旅行达人', '## "旅行达人"人设\\n\\n展示：世界各地打卡照、精致酒店、当地美食……\\n\\n**拆解：**\\n- 旅行的真实体验包含疲倦、语言障碍、舟车劳顿\\n- 很多内容是赞助合作，不是自费\\n- 旅行的意义不是打卡数量，而是内心体验', '识别社交媒体中"旅行达人"形象', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (23, 2, '上岸/绩点/成绩优秀人设', '## "上岸/成绩优秀"人设\\n\\n展示：录取通知书、成绩单、排名、证书……\\n\\n**拆解：**\\n- 每一个成功者背后都有大量未被展示的失败者\\n- 幸存者偏差使成功看起来比实际更容易\\n- 你看到的是结果，不是漫长的备考过程', '识别社交媒体中"上岸成功"形象', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (24, 2, '高情商社交达人', '## "高情商社交达人"人设\\n\\n展示：朋友聚会、社交活动、人脉广泛……\\n\\n**拆解：**\\n- 社交达人的照片不代表他们拥有深度的亲密关系\\n- 很多社交圈是工作需要的表面关系\\n- 少而精的亲密关系可能比泛泛之交更令人满足', '识别社交媒体中"社交达人"形象', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (25, 3, '选择性展示的本质', '## 选择性展示的本质\\n\\n社交媒体最核心的特征是：**人们只展示他们想让你看到的部分。**\\n\\n这就像每个人都在拍一部关于自己的"宣传片"，而不是"纪录片"。\\n\\n**理解这一点：**\\n- 你在拿别人的"宣传片"和你的"完整生活"进行比较\\n- 别人也有烦恼、失败、无聊的时刻，只是你不知道\\n- 这不是欺骗，而是人性的自然倾向——我们都希望展示好的一面', '理解社交媒体展示的底层逻辑', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (26, 3, '滤镜与修图文化', '## 滤镜与修图文化\\n\\n现在的手机 App 让任何人都能在几秒钟内美化照片。皮肤、五官、身材、光线都可以调整。\\n\\n**影响：**\\n- 长期看修过的图片会让人对"正常的外貌"产生认知偏差\\n- 你有可能在拿自己的"镜子里的脸"和别人的"精修图"比较\\n- 很多博主公开承认：真人和照片差异很大', '看到精修图片时提醒自己这是处理过的', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (27, 3, '叙事包装与故事线', '## 叙事包装与故事线\\n\\n社交媒体上的内容不只是图片和文字，它们往往包含一个精心设计的"故事线"。\\n\\n**常见叙事模式：**\\n- "从零到一"逆袭故事（省略了中间的反复和挫折）\\n- "日常 Vlog"（每一个镜头都经过了编排）\\n- "随手拍"（其实已经拍了 50 张选了 1 张）\\n\\n**识别这些叙事包装，能帮助你看透内容的本质。**', '识别社交媒体内容的叙事结构', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (28, 3, '算法推荐与情绪喂养', '## 算法推荐与情绪喂养\\n\\n社交平台的推荐算法会分析你的行为，持续推送容易引发情绪反应的内容。\\n\\n**算法的工作方式：**\\n- 你在一个内容上停留更久 → 算法推送更多同类内容\\n- 引发强烈情绪（焦虑、愤怒、羡慕）的内容更容易被传播\\n- 你搜索"焦虑"相关内容 → 算法认为你喜欢这类内容\\n\\n**意识到这一点，你可以主动打破信息茧房。**', '理解为什么总是刷到引发焦虑的内容', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (29, 3, '商业合作与软广识别', '## 商业合作与软广识别\\n\\n大量社交媒体内容背后是商业利益。\\n\\n**识别信号：**\\n- 看起来很自然的推荐，其实是付费广告\\n- 博主展示的"日常用品"可能是品牌赞助\\n- 旅行、体验可能由酒店/品牌提供\\n\\n**当你知道这是一个广告时，它的说服力就会大大降低。**', '识别社交媒体中的软广告和商业合作', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (30, 3, '精心策划的"随手拍"', '## 精心策划的"随手拍"\\n\\n很多图片看起来像是不经意间拍下的，但实际上经过了大量的准备。\\n\\n**常见的策划方法：**\\n- 环境清理：把杂乱的物品移出镜头\\n- 光线调整：选择最佳时间和角度\\n- 多次拍摄：从几十张中选择最好的一张\\n- 后期处理：裁剪、调色、滤镜\\n\\n**"随手"只是一种呈现风格，不是拍摄方式。**', '看穿"随手拍"背后的准备工作', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (31, 3, '人设的一致性与表演成本', '## 人设的一致性与表演成本\\n\\n维持一个社交媒体人设需要持续的努力。发布越多精致内容，对下一次发布的要求就越高。\\n\\n**表演成本：**\\n- 时间成本：策划、拍摄、修图、写文案\\n- 心理成本：担心内容不受欢迎、人设崩塌\\n- 经济成本：服装、场景、设备\\n\\n**与其羡慕别人的人设，不如把精力放在真实的自己身上。**', '理解维持人设需要付出的代价', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (32, 3, '幸存者偏差与可见性偏见', '## 幸存者偏差与可见性偏见\\n\\n社交媒体上存在严重的"幸存者偏差"：你只能看到"成功的"案例，看不到大量"失败的"案例。\\n\\n**例子：**\\n- 100 个考研人中只有 5 个晒了录取通知，但你只看到这 5 个\\n- 创业失败的人很少发帖，成功的人频繁出现\\n- 算法把"成功案例"推到你的首页，让你觉得"所有人都在成功"\\n\\n**记住：你没看到的失败者远多于你看到的成功者。**', '正确看待社交媒体上的成功案例比例', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (33, 4, '事实与推测区分', '## 事实与推测区分\\n\\n这是 CBT 中最基础也最有效的技术之一。\\n\\n**事实（可以验证的）：**\\n- 她发了一条朋友圈展示旅行照片\\n- 她拿到了研究生录取通知\\n\\n**推测（你自己加上去的）：**\\n- 她过得一定很开心\\n- 她的人生一切顺利\\n- 我比不上她\\n\\n**焦虑往往来自把推测当成事实。** 在做出结论之前，先问自己：这是我看到的，还是我推断的？', '任何产生焦虑时进行认知梳理', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (34, 4, '自动化想法识别', '## 自动化想法识别\\n\\n"自动化想法"是指在你看到某些内容时自动冒出来的消极念头。\\n\\n**常见自动化想法：**\\n- "我又落后了"\\n- "我永远做不到"\\n- "为什么我不如别人"\\n\\n**练习步骤：**\\n1. 注意你的情绪变化（焦虑、低落）→ 回溯刚才看了什么\\n2. 捕捉冒出来的那个想法\\n3. 把它写下来，问自己：这是事实还是我的解读？\\n4. 用更客观的想法替代它', '刷社交媒体后感到情绪低落时', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (35, 4, '认知重评技术', '## 认知重评技术\\n\\n认知重评是重新评估和解释一个情境的方法。\\n\\n**当看到引发焦虑的内容时，尝试重评：**\\n\\n| 初始想法 | 重评后的想法 |\\n|---------|------------|\\n| 她过得真好，我不如她 | 她展示了想让人看到的部分 |\\n| 我太差劲了 | 我正在自己的节奏里前进 |\\n| 所有人都在进步只有我在原地 | 每个人面临不同的处境和挑战 |\\n\\n**重评不是自我欺骗，而是用一个更完整的视角看问题。**', '用于情绪被触发后进行理性调整', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (36, 4, '去灾难化技术', '## 去灾难化技术\\n\\n焦虑常常让人把事情想得比实际上更糟糕。\\n\\n**去灾难化的步骤：**\\n1. 识别可怕的想法（"我这辈子完了"）\\n2. 问自己：最坏的情况是什么？发生的概率有多大？\\n3. 即使最坏情况发生，我能做什么？\\n4. 正常情况（更有可能性）会是什么结果？\\n\\n**绝大多数你担心的"灾难"，既不会发生，也没有你想象中那么可怕。**', '焦虑被放大到失控时', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (37, 4, '行为激活：从小事开始', '## 行为激活：从小事开始\\n\\n当焦虑和低落让人提不起劲时，行为激活是一个有效的恢复方法。\\n\\n**原理：**\\n- 焦虑让人回避活动 → 回避让生活缩小 → 产生更多焦虑\\n- 打破循环的方法是从最小的行动开始\\n\\n**很小的行动也能带来变化：**\\n1. 整理一下桌面\\n2. 散十分钟步\\n3. 给朋友发一条消息\\n4. 写下今天一个开心的瞬间\\n\\n**行动产生能量，而不是能量产生行动。**', '焦虑让人不想做任何事时', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:15', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (38, 4, '感恩练习', '## 感恩练习\\n\\n研究显示，有意识地练习感恩可以显著改善情绪和减轻焦虑。\\n\\n**简单练习：**\\n- 每晚写下今天 3 件让你感恩的小事\\n- 可以是非常微小的事：喝到一杯好喝的咖啡、天气很好、收到一条暖心的消息\\n\\n**感恩不是否认困难，而是注意到那些被焦虑掩盖的、生活中正在正常运行的部分。**', '每天睡前或早晨进行', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:16', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (39, 4, '正念呼吸练习', '## 正念呼吸练习\\n\\n正念（Mindfulness）是指有意识地、不加评判地关注当下。\\n\\n**一个简单的 3 分钟正念呼吸练习：**\\n1. 第一分钟：闭上眼睛，注意身体的感觉（坐着的重量、脚的触感）\\n2. 第二分钟：把注意力集中在呼吸上（鼻尖的空气流、胸腹的起伏）\\n3. 第三分钟：将注意力扩展到整个身体，感受当下的存在感\\n\\n**如果走神了，不要批评自己，轻轻地把注意力拉回来就行。反复走神反复拉回，这就是练习的本质。**', '感到焦虑、烦躁、或思维被社交媒体占据时', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:16', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (40, 4, '情绪标签化', '## 情绪标签化\\n\\n给自己的情绪贴上准确的标签，本身就能缓解焦虑。\\n\\n**研究显示，当人们能够准确命名自己的情绪时，大脑杏仁核（负责恐惧反应）的活动水平会下降。**\\n\\n**练习：**\\n- 不只是"我很难受"，而是"我感到焦虑"或"我感到失望"\\n- 进一步细化：是"被比较感压住了"还是"对未来的不确定感"还是"对自己不满"\\n\\n**越具体越好。命名它，你就开始掌控它。**', '任何情绪波动时都可以练习', NULL, 1, 0, NULL, '2026-06-17 14:43:43', '2026-06-15 15:15:16', '2026-06-17 14:43:43');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (41, 5, 'STOP 技术：立刻暂停', '## STOP 技术\\n\\n当你刷到让你特别焦虑的内容时，使用这个简短的技术：\\n\\n- **S（Stop）**：暂停。放下手机，或至少关掉当前 App\\n- **T（Take a breath）**：深呼吸一次。慢慢吸气，缓缓呼出\\n- **O（Observe）**：观察你现在的感受。心跳快了吗？胃不舒服吗？脑子里在想什么？\\n- **P（Proceed）**：带着觉察继续。你可以选择不再看那条内容，转而做一件让你平静的事\\n\\n**整个过程只需要一两分钟，但能打断自动化焦虑反应。**', '刷到触发内容时立刻使用', NULL, 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-15 15:15:16', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (42, 5, '5-4-3-2-1 感官接地法', '## 5-4-3-2-1 感官接地法\\n\\n当你感到被焦虑裹挟时，用这个练习把注意力拉回当下：\\n\\n- **5** — 看到 5 样东西（环顾四周，说出它们的名字）\\n- **4** — 感受 4 种触感（衣服的质感、椅子的表面、皮肤上的空气流动……）\\n- **3** — 听到 3 种声音（空调声、远处的车声、自己的呼吸声……）\\n- **2** — 闻到 2 种气味（房间的味道、窗外吹入的风……）\\n- **1** — 尝到 1 种味道（喝一口水，感受水的清爽）\\n\\n**这个技术与焦虑的本质相反：焦虑把你拖到未来，感官让你回到现在。**', '焦虑严重到感觉脱离现实时', NULL, 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-15 15:15:16', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (43, 5, '深呼吸减压法', '## 深呼吸减压法\\n\\n当焦虑袭来时，身体的生理反应是真实的：心跳加快、呼吸变浅、肌肉紧张。\\n\\n**4-7-8 呼吸法：**\\n1. 用鼻子慢慢吸气，数 4 秒\\n2. 屏住呼吸，数 7 秒\\n3. 用嘴巴缓缓呼出，数 8 秒\\n4. 重复 3-4 次\\n\\n**为什么有效：** 缓慢呼出激活了副交感神经系统，这是身体的"放松开关"。这不是心理暗示，而是生理机制。', '感到生理上的焦虑反应时', NULL, 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-15 15:15:16', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (44, 5, '手机隔离 15 分钟', '## 手机隔离 15 分钟\\n\\n有时候焦虑的源头就是手机本身。把手机放远 15 分钟，让自己获得一段不受打扰的时间。\\n\\n**在这 15 分钟内，你可以：**\\n- 站起来走一走\\n- 看看窗外\\n- 泡一杯茶\\n- 什么都不做，就是发呆\\n\\n**15 分钟不会错过什么重要的事。但你可能会需要不止 15 分钟来恢复平静。如果感觉好多了，不妨再延长一会儿。**', '刷手机刷到停不下来且越来越焦虑时', NULL, 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-15 15:15:16', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (45, 5, '写下你的情绪', '## 写下你的情绪\\n\\n拿出纸笔（或者用手机的备忘录），把此刻的感受写下来。\\n\\n**写作框架：**\\n1. 我刚才看到了什么？（具体描述那条内容）\\n2. 那一瞬间我的感觉是什么？（焦虑？嫉妒？自我否定？）\\n3. 这个感觉让我想到了什么？（对自己哪方面的担心？）\\n4. 如果是一个关心我的朋友，他会怎么对我说？\\n\\n**写作帮助你把混乱的情绪捋顺。写完之后，你可能不会觉得问题都解决了，但通常会感觉好受一些。**', '思绪混乱、无法理清自己感受时', NULL, 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-15 15:15:16', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (46, 5, '换个视角看自己', '## 换个视角看自己\\n\\n当你在比较自己和他人的差距时，不妨试试从未来的自己或关心你的人的角度来看。\\n\\n**练习：**\\n- 想象五年后的你回头看今天，会怎么评价这条让你焦虑的内容？\\n- 想象你的好朋友知道了你今天的感受，会怎么安慰你？\\n\\n**很多时候，我们对别人的善意和宽容，远远超过对自己的。给自己同等的善意。**', '陷入自我批评和比较中时', NULL, 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-15 15:15:16', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (47, 6, '减少社交媒体使用时间', '## 减少社交媒体使用时间\\n\\n最直接的减少焦虑的方法就是减少接触引发焦虑的内容。\\n\\n**具体方法：**\\n1. 设定每天的使用时间上限（例如每天 30 分钟）\\n2. 使用手机的"屏幕时间"功能设置限制\\n3. 把社交 App 放在文件夹深处（增加打开的阻力）\\n4. 在特定的时段不碰手机（吃饭时、睡前一小时）\\n\\n**你没有错过什么，但你会获得更多平静。**', '想要减少社交媒体对自己的影响时', NULL, 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-15 15:15:16', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (48, 6, '整理你的关注列表', '## 整理你的关注列表\\n\\n你的社交媒体体验很大程度上取决于你关注了谁。\\n\\n**清理建议：**\\n1. 取关那些持续让你感到焦虑、嫉妒、自卑的账号\\n2. 保留那些带给你平静、启发、真实感的账号\\n3. 增加关注那些展示"不完美的真实生活"的内容\\n\\n**你的注意力是宝贵的，不要浪费在让你难受的内容上。**', '觉得社交媒体整体让人焦虑时', NULL, 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-15 15:15:16', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (49, 6, '建立自己的成就记录', '## 建立自己的成就记录\\n\\n社交媒体让你关注别人的成就，而忽视了自己的进步。\\n\\n**建立一个简单的"我的成就档案"：**\\n- 写下你过去一年取得的所有进步（大的小的都算）\\n- 包括：学会的技能、克服的困难、坚持的习惯、帮过别人的事\\n- 定期回顾和更新\\n\\n**你会发现自己其实一直在前进，只是没有被你自己注意到。**', '觉得自己一事无成时', NULL, 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-15 15:15:16', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (50, 6, '寻找线下的真实连接', '## 寻找线下的真实连接\\n\\n社交媒体提供的是"弱连接"——大量的浅层互动。而"强连接"——少数深入的面对面关系——对心理健康的保护作用更强。\\n\\n**尝试：**\\n1. 约一个朋友线下见面聊天\\n2. 参加一个线下兴趣小组或活动\\n3. 和家人一起吃顿饭，放下手机\\n\\n**一次真诚的线下对话，可能比刷 100 条动态更能滋养你。**', '感到孤独但不被社交媒体的互动满足时', NULL, 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-15 15:15:16', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (51, 6, '把比较转化为学习', '## 把比较转化为学习\\n\\n同样是看到别人的成就，你可以选择两个完全不同的方向：\\n- **嫉妒模式：** 她好优秀 → 我好差\\n- **学习模式：** 她做对了什么？哪些可以借鉴？\\n\\n**练习转换：**\\n当你发现自己在比较时，主动问自己：\\n1. 她做了什么行动导致了那个结果？\\n2. 其中有没有我可以尝试的部分？\\n3. 我的实际情况和她的有什么不同？\\n\\n**注意：这种转换是有意识的，需要练习。当你太焦虑时，先做好情绪恢复，再考虑学习。**', '看到他人成就时想从负面比较转为正向学习', NULL, 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-15 15:15:16', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (52, 6, '设定自己的目标而非别人的', '## 设定自己的目标而非别人的\\n\\n很多焦虑来源于：你在追求别人认为重要的事，而不是你真正想要的事。\\n\\n**问自己：**\\n1. 如果没有人在看，我还会做现在正在努力的事吗？\\n2. 我现在的目标是我自己选择的，还是社会/家庭/朋友暗示我应该追求的？\\n3. 如果我的目标和别人完全不同，我能接受吗？\\n\\n**真正的满足感来自做适合自己的事，而不是复制别人的路径。**', '对人生方向感到迷茫时', NULL, 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-15 15:15:16', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (53, 7, '反比较：找到你自己的标准', '## 找到你自己的标准\\n\\n比较本身不是问题，问题在于你用了不适合自己的标准。\\n\\n**练习：**\\n1. 列出 3-5 个对你来说真正重要的人生维度（不是别人告诉你的）\\n2. 在每个维度上，写下你自己的满意标准\\n3. 当你看到社交媒体内容时，问自己：这和我自己的标准有关系吗？\\n\\n**一个让你平静的事实：你不需要在别人的游戏里赢。你可以定义自己的游戏。**', '被社会主流标准压得喘不过气时', NULL, 1, 0, NULL, '2026-06-17 15:19:39', '2026-06-15 15:15:16', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (54, 7, '不完美练习', '## 不完美练习\\n\\n社交媒体让我们对"完美"产生了病态的执着。有意识地练习接受不完美，可以减轻这种压力。\\n\\n**练习方法：**\\n1. 发一条没有滤镜的自拍（如果是私人账号）\\n2. 承认自己今天某件事没做好，但没关系\\n3. 做一件不追求结果只追求过程的事\\n\\n**完美是焦虑的燃料，不完美是自由的入口。**', '被完美主义和"精致焦虑"困扰时', NULL, 1, 0, NULL, '2026-06-17 15:19:39', '2026-06-15 15:15:16', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (55, 7, '身体扫描放松法', '## 身体扫描放松法\\n\\n当你感觉焦虑存储在身体里（紧绷的肩膀、攥紧的拳头、咬紧的牙），试着做身体扫描。\\n\\n**方法（5-10 分钟）：**\\n1. 舒服地坐着或躺着，闭上眼睛\\n2. 从脚开始，注意脚的感觉，然后慢慢往上\\n3. 到腿、腹部、胸部、肩膀、手臂、脖子、脸部\\n4. 每到一处，有意识地放松那个部位的肌肉\\n5. 最后感受整个身体的放松状态\\n\\n**这个方法可以帮助你在睡前或任何紧张时刻放松下来。**', '身体紧张、入睡困难时', NULL, 1, 0, NULL, '2026-06-17 15:19:39', '2026-06-15 15:15:16', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (56, 7, '自我对话的三种声音', '## 自我对话的三种声音\\n\\n你的内在对话通常有三种声音，学会区分和调整它们：\\n\\n- **批评者：** "你不够好""你又失败了"→ 这种声音常常夸大和绝对化\\n- **被批评者：** "我好难受""我没办法"→ 这种声音表达的是真实的情绪\\n- **关怀者：** "这很难，但你已经尽力了""每个人都会遇到这种事"→ 这个声音需要被刻意培养\\n\\n**练习：当批评者太大声时，刻意启动关怀者的声音。**', '自我批评严重时', NULL, 1, 0, NULL, '2026-06-17 15:19:39', '2026-06-15 15:15:16', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (57, 7, '创建你的"反焦虑工具包"', '## 创建你的"反焦虑工具包"\\n\\n为自己准备一个随时可用的工具包，当社交媒体焦虑袭来时可以立即使用。\\n\\n**你的工具包可以包括：**\\n- 一段你喜欢的音乐或音频\\n- 几张让你感到平静的照片\\n- 几个你信任的朋友的联系方式\\n- 一句对你有意义的提醒或名言\\n- 一个简单的呼吸练习\\n- 一个让你舒服的小物品（石头、手链、照片等）\\n\\n**当焦虑来袭时，你不需要从零开始想办法，你的工具包已经准备好了。**', '提前准备，用于焦虑发作时', NULL, 1, 0, NULL, '2026-06-17 15:19:39', '2026-06-15 15:15:16', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (58, 8, '案例：朋友圈里的保研通知', '## 案例分析：朋友圈里的保研通知\\n\\n**场景描述（虚构/示例）：**\\n小林刷朋友圈时，看到高中同学发了一条动态，配图是某 985 大学的研究生录取通知书，文案写着"几年的努力终于有了回报"。\\n\\n**小林的即时反应：**\\n心跳加快，胸口发闷，脑子里冒出："她都能保研了，我还在原地……"\\n\\n**分析：**\\n- **事实：** 同学被某大学录取为研究生\\n- **推测：** "她的人生一片光明", "我远远不如她", "我以后怎么办"\\n- **隐藏信息：** 你不知道她的 GPA 有多高、她经历过多少次被拒、她未来的压力有多大。你只知道一个结果。\\n- **比较陷阱：** 你在拿她的一个"高光点"和你的"全部现状"对比\\n\\n**调整后的想法：**\\n"她取得了她的阶段性成果，我也在自己的道路上。每个人的节奏不同。"', '典型的朋友圈比较焦虑场景', NULL, 1, 1, NULL, '2026-06-17 15:19:39', '2026-06-15 15:15:16', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (59, 8, '案例：小红书上的精致房间', '## 案例分析：小红书上的精致房间\\n\\n**场景描述（虚构/示例）：**\\n小陈刷小红书时，看到一位博主展示了自己的出租屋改造。房间干净整洁，柔和的灯光、整齐的书架、漂亮的床单，标题写着"一个人也要好好生活"。\\n\\n**小陈的即时反应：**\\n下意识看了看自己略显凌乱的房间，感到一阵沮丧和愧疚。\\n\\n**分析：**\\n- **事实：** 博主发布了几张精心布置的房间照片\\n- **推测：** "她的生活真的很精致", "我太邋遢了", "我不配好好生活"\\n- **隐藏信息：** 这个博主可能花了几个小时整理和布置，拍照后又花了很久修图。房间在平时可能也不是这个样子。\\n- **比较陷阱：** 把自己的日常起居状态和一个精心策划的展示画面比较\\n\\n**调整后的想法：**\\n"她的房间布置得很漂亮，但这只代表一个拍摄瞬间。我的生活不需要和别人的布景比较。"', '看到精致生活内容产生对自己的不满', NULL, 1, 0, NULL, '2026-06-17 15:19:39', '2026-06-15 15:15:16', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (60, 8, '案例：朋友圈的旅行照', '## 案例分析：朋友圈的旅行照\\n\\n**场景描述（虚构/示例）：**\\n小张在加班时刷到同事的马尔代夫旅行照。碧海蓝天、沙滩长裙，评论区全是"好羡慕""人生赢家"。\\n\\n**小张的即时反应：**\\n看着自己面前的加班盒饭，感到一阵深深的落差和苦涩。\\n\\n**分析：**\\n- **事实：** 同事正在海边度假，拍了几张照片\\n- **推测：** "她的生活好精彩", "我的生活好无聊", "我永远也没机会这样享受"\\n- **隐藏信息：** 旅行只是同事生活中 1% 的时间。她也有加班、烦恼、平淡的日子。而且她可能为了这次旅行花了几个月的积蓄。\\n- **比较陷阱：** 把别人 1% 的高光时刻和自己的 99% 普通时刻比较\\n\\n**调整后的想法：**\\n"她有一个美好的假期，这很好。我的生活不只是这一个加班夜。以后我也能安排自己的旅行。"', '看到他人旅行时产生落差感', NULL, 1, 1, NULL, '2026-06-17 15:19:39', '2026-06-15 15:15:16', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (86, 1, '社交媒体中的向上社会比较焦虑', '## 这是什么\\n\\n向上社会比较，是把自己与看起来更成功、更受欢迎或生活条件更好的人比较。社交媒体让这种比较变得频繁、快速而且难以回避；当比较结果被解释为“我不如别人”时，可能出现自卑、焦虑或失落。\\n\\n## 它通常怎样被触发\\n\\n浏览熟人或陌生人的升学、工作、收入、旅行、外貌和社交成果时，尤其是在自己正经历挫折、疲惫或低自我评价的阶段。\\n\\n## 为什么社交媒体会放大它\\n\\n动态通常呈现经过选择的片段，比较者却容易拿自己的完整生活与别人的可展示部分相比。推荐流还会连续聚合相似的高光内容，使少数突出案例看起来像普遍水平。研究总体支持向上比较与更消极的自我评价有关，但影响存在明显个体差异。\\n\\n**关键认知：**\\n\\n- 被展示出来的高光不等于对方生活的平均状态\\n- 产生羡慕或落差感是常见心理反应，不等于品格有问题\\n- 社交媒体的影响取决于内容、比较方式和个人当时状态\\n\\n## 常见表现\\n\\n- 反复想“别人都比我过得好”\\n- 刷完动态后对自己的能力或生活产生否定\\n- 继续查看比较对象，以确认自己到底落后多少\\n\\n## 需要注意\\n\\n研究常报告平均关联，不能据此判断每个用户都会受到负面影响，也不能把一次比较后的难受直接等同于临床焦虑。', '刷到他人的成功、外貌或生活成果后，开始用单一维度否定自己的整体价值时。', '参考：Vogel等，2014《Social Comparison, Social Media, and Self-Esteem》；McComb等，2023向上比较元分析。', 1, 1, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (87, 1, '创作者数据波动与可见性不确定压力', '## 这是什么\\n\\n创作者可见性压力，是内容发布者因播放量、推荐量、互动量和变现结果不稳定，而持续担心“内容是否还能被看见”的状态。它不只是对数字本身的在意，也可能涉及收入、职业身份和持续创作能力。\\n\\n## 它通常怎样被触发\\n\\n作品投入较多却获得很少推荐，平台规则调整后流量突然变化，或看到其他创作者讨论“限流”“权重下降”时。\\n\\n## 为什么社交媒体会放大它\\n\\n推荐系统通常不完全透明，创作者很难准确知道某次数据变化来自内容质量、受众变化、竞争、发布时间还是平台调整。研究者用“可见性劳动”和“算法传闻”描述创作者为理解和适应算法而投入的持续劳动；这种不可预测性可能增加控制感不足。\\n\\n**关键认知：**\\n\\n- 低数据不能单独证明内容失去价值或账号被处罚\\n- 算法会影响可见性，但不会单独决定作品长期价值\\n- 该主题的研究多为平台与劳动研究，不能直接推断所有创作者都会出现心理障碍\\n\\n## 常见表现\\n\\n- 发布后频繁刷新数据面板\\n- 根据零散经验不断修改发布时间和内容形式\\n- 把短期流量下降解释为个人能力全面退步\\n\\n## 需要注意\\n\\n现有证据较多来自定性研究，能够说明创作者如何感受和应对算法不确定性，但不宜把它描述成经过统一诊断的“算法焦虑症”。', '内容发布后数据异常低迷，开始把流量波动等同于个人能力或职业前途时。', '参考：Cotter，2019《Playing the Visibility Game》；Bishop，2019《Managing Visibility on YouTube Through Algorithmic Gossip》。', 1, 0, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (88, 1, '同龄人人生进度比较焦虑', '## 这是什么\\n\\n人生进度比较焦虑，是把结婚、就业、升职、买房、生育等节点看作统一时间表，并用同龄人的公开进展判断自己是否“落后”。它主要来自社会比较和年龄规范，而不是某个公认的客观人生进度条。\\n\\n## 它通常怎样被触发\\n\\n在毕业季、生日、节日或求职阶段，集中看到同学和朋友公布录取、升职、订婚、买房或生育消息时。\\n\\n## 为什么社交媒体会放大它\\n\\n社交媒体会把不同人的不同里程碑压缩在同一个信息流里。用户可能在一天内看到多个人各自最突出的进展，却忽略这些成果来自不同条件、不同年份和不同代价。由此形成的参照群体并不真实，却容易制造“所有人都在前进”的印象。\\n\\n**关键认知：**\\n\\n- 人生节点并不存在适用于所有人的统一顺序和速度\\n- 信息流把许多人的单项成果叠加成了一个不存在的“完美同龄人”\\n- 落后感可能反映参照标准改变，而不是现实生活突然恶化\\n\\n## 常见表现\\n\\n- 看到同龄人进展后心慌或羞耻\\n- 频繁搜索某年龄应该达到什么水平\\n- 把暂时停顿解释为整个人生失败\\n\\n## 需要注意\\n\\n该名称是便于理解的描述，不是正式诊断。其机制主要来自社会比较研究，对具体人生节点的影响还会受到文化、家庭和经济环境影响。', '连续看到同龄人升学、成家或置业后，感觉自己的人生已经来不及了。', '参考：McComb等，2023向上比较元分析；Meier与Johnson，2022社交媒体比较与嫉妒综述。', 1, 0, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (89, 1, '学业表现比较焦虑', '## 这是什么\\n\\n学业表现比较焦虑，是在看到他人的成绩、学习时长、录取结果或备考计划后，对自己的能力和进度产生持续怀疑。焦虑往往不只来自差距本身，还来自把他人的展示当成完整、可复制的学习标准。\\n\\n## 它通常怎样被触发\\n\\n期末周、考研考公或申请季，刷到高分截图、长时间学习记录、“一次上岸”经验和高度精细的计划表时。\\n\\n## 为什么社交媒体会放大它\\n\\n学习成果适合被数字化展示，困难、走神、失败和反复修改却较少被公开。社交媒体还方便用户主动寻找同龄人的成绩和评价，强化比较与反馈寻求。青少年研究发现，技术媒介中的社会比较和反馈寻求与更高的抑郁症状相关，但研究不能说明比较必然导致心理问题。\\n\\n**关键认知：**\\n\\n- 学习时长和结果截图无法完整反映学习条件与过程\\n- 比较可以提供信息，也可能在低自我评价时被解释成能力判决\\n- 一次成绩或一段低效期不等于稳定的学业能力\\n\\n## 常见表现\\n\\n- 反复计算自己与他人的差距\\n- 看到高分内容后难以继续学习\\n- 制定明显超出实际精力的计划来追赶\\n\\n## 需要注意\\n\\n它与一般考试焦虑、完美主义和现实学业压力可能同时存在。仅凭社交媒体触发场景不能确定主要原因。', '复习受挫时刷到大量高分和高强度学习记录，开始怀疑自己的智力或学习资格。', '参考：Nesi与Prinstein，2015，技术媒介中的社会比较与反馈寻求研究；Vogel等，2014。', 1, 0, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (90, 1, '职业成就比较焦虑', '## 这是什么\\n\\n职业成就比较焦虑，是在社交平台看到他人的职位、项目、薪资线索或职业荣誉后，对自身能力、发展速度和就业安全产生不安。它常见于求职、转行和职业停滞期。\\n\\n## 它通常怎样被触发\\n\\n浏览同龄人的入职公告、晋升消息、获奖经历、行业影响力和“职业复盘”内容时，尤其是在自己求职失败或工作受挫之后。\\n\\n## 为什么社交媒体会放大它\\n\\n职业平台和普通社交平台都鼓励呈现可被认可的成果，而日常重复劳动、运气因素、资源支持和失败经历较少被展示。用户容易把多个不同人的最强项组合成一个过高标准，再用它评判自己的整个职业生涯。\\n\\n**关键认知：**\\n\\n- 职业动态主要是公开履历，不是完整工作体验\\n- 招聘与晋升受行业周期、机会和关系网络等多因素影响\\n- 比较后的焦虑可能来自现实压力与线上参照共同作用\\n\\n## 常见表现\\n\\n- 不断修改个人简介以显得更优秀\\n- 看到他人晋升后否定自己的专业能力\\n- 频繁查看行业动态却更难开始实际任务\\n\\n## 需要注意\\n\\n针对具体职业平台的直接心理学证据仍有限。本条主要依据社会比较、自我呈现和反馈寻求研究进行谨慎解释。', '求职或工作遇到瓶颈时，看到同龄人的职业捷报后产生明显的淘汰感。', '参考：McComb等，2023向上社会比较元分析；Vogel等，2014社交媒体比较与自尊研究。', 1, 0, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (91, 1, '消费与生活方式比较焦虑', '## 这是什么\\n\\n消费与生活方式比较焦虑，是看到他人展示住房、旅行、餐饮、穿搭或昂贵物品后，觉得自己的生活层级不足，并把这种差距解释为个人失败。它常与相对剥夺感和社会比较有关。\\n\\n## 它通常怎样被触发\\n\\n经济压力较大时，连续刷到高消费旅行、奢侈品开箱、精致居住空间或“松弛感生活”内容。\\n\\n## 为什么社交媒体会放大它\\n\\n视觉化平台容易让高消费内容获得关注，商业合作和精心布置也可能被误认为普通日常。信息流把不同人的消费高点并列展示，会扩大用户对“正常生活水平”的估计。现有研究支持社交网络增加比较机会，但具体消费焦虑还受到收入、债务和价值观影响。\\n\\n**关键认知：**\\n\\n- 看到得多不等于这种生活在现实中更普遍\\n- 消费展示可能同时包含工作内容、广告和特殊场合\\n- 焦虑中的“我很贫穷”可能是相对参照变化，不等于客观生活立即恶化\\n\\n## 常见表现\\n\\n- 刷完种草内容后对现有物品明显不满\\n- 为了跟上展示标准而产生超预算冲动\\n- 把消费能力当作人格价值或社会资格\\n\\n## 需要注意\\n\\n本条解释的是比较机制，不判断某次消费是否合理。若已经出现债务或失控购买，需要与单纯的比较情绪分开评估。', '浏览高消费生活内容后，开始觉得自己原本可接受的生活“寒酸、失败或不配”。', '参考：Vogel等，2014；Meier与Johnson，2022社交媒体比较与嫉妒综述。', 1, 0, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (92, 1, '亲密关系展示比较焦虑', '## 这是什么\\n\\n亲密关系展示比较焦虑，是用他人在社交媒体上公开的浪漫互动、礼物、纪念日和家庭生活，衡量自己的恋爱或婚姻质量。比较后可能出现失望、怀疑或对伴侣的不满。\\n\\n## 它通常怎样被触发\\n\\n与伴侣刚发生矛盾、关系进入平淡期，或在节日集中看到求婚、礼物和恩爱照片时。\\n\\n## 为什么社交媒体会放大它\\n\\n公开内容通常更适合呈现可被观看和点赞的时刻，而关系中的协商、无聊、冲突和修复较少被记录。用户容易把他人的展示结果与自己关系的日常过程相比。社会比较研究能解释这种落差，但单条动态无法证明对方关系真实质量。\\n\\n**关键认知：**\\n\\n- 浪漫展示是关系的一部分，不是关系质量的完整测量\\n- 真实关系的稳定性不能由礼物价格或发帖频率单独判断\\n- 比较后的不满可能提示现实需求，也可能来自不完整参照\\n\\n## 常见表现\\n\\n- 看到别人秀恩爱后突然否定自己的关系\\n- 要求伴侣复制网上的表达方式\\n- 反复寻找自己“不被爱”的证据\\n\\n## 需要注意\\n\\n不要仅凭比较后的瞬时情绪判断关系是否应当结束。关系本身是否存在问题，需要结合线下互动和长期体验。', '看到他人的浪漫内容后，突然觉得自己的伴侣和关系处处不合格。', '参考：Chou与Edge，2012，Facebook使用与他人生活评价研究；Muise等，2009，Facebook与关系嫉妒研究。', 1, 0, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (93, 1, '容貌与面部比较焦虑', '## 这是什么\\n\\n容貌比较焦虑，是频繁接触高度修饰或符合主流审美的面部图像后，对自己的五官、皮肤和上镜效果产生不满或担忧。外貌比较是社交媒体影响身体意象的重要机制之一。\\n\\n## 它通常怎样被触发\\n\\n浏览美妆、穿搭、自拍或颜值评价内容，使用前置摄像头、滤镜和修图功能后再看真实镜像时。\\n\\n## 为什么社交媒体会放大它\\n\\n视觉平台提供大量便于直接比较的图像。拍摄角度、光线、筛选和编辑常被隐藏，用户却可能把成片当作他人的自然状态。系统综述和实验研究发现，外貌相关浏览及比较与身体不满意有关，但效应受内容类型和个人比较倾向影响。\\n\\n**关键认知：**\\n\\n- 图片质量和现实容貌不是同一概念\\n- 高频出现的审美形象不代表真实人群分布\\n- 对外貌的不满可能被比较放大，但不说明外貌本身发生了变化\\n\\n## 常见表现\\n\\n- 反复放大照片检查瑕疵\\n- 离开滤镜后觉得自己难以接受\\n- 因担心被评价而回避拍照或见人\\n\\n## 需要注意\\n\\n身体意象研究呈现的是群体层面关系。若外貌担忧持续占据大量时间、明显影响进食或生活，应交由专业人员进一步评估。', '看完高颜值或精修内容后，对自己的真实面部产生强烈厌恶或羞耻。', '参考：Holland与Tiggemann，2016系统综述；Fardouly等，2015实验研究。', 1, 1, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (94, 1, '身材与健身内容比较焦虑', '## 这是什么\\n\\n身材比较焦虑，是看到纤瘦、肌肉或“完美体态”内容后，对自己的体型和运动进度产生不安。它可能表现为身体不满意，也可能把运动从健康活动变成证明价值的考核。\\n\\n## 它通常怎样被触发\\n\\n浏览健身打卡、减脂前后对比、体重数据和强调外形结果的“健身灵感”内容时。\\n\\n## 为什么社交媒体会放大它\\n\\n身材图像容易被选择、摆姿和编辑，推荐流还可能连续呈现同一种理想体型。研究发现，外貌导向和健身理想内容可能增加外貌比较与身体不满意；但健身内容也可能提供信息或动力，影响并非单向。\\n\\n**关键认知：**\\n\\n- 健康、力量和外形是不同维度，不能只用照片判断\\n- 他人的训练结果受时间、基因、资源和展示方式共同影响\\n- 同一内容对不同人可能产生激励或压力\\n\\n## 常见表现\\n\\n- 频繁称重、量围度并与博主对照\\n- 因没有快速变化而自责\\n- 用极端饮食或运动证明自己没有落后\\n\\n## 需要注意\\n\\n本条不用于判断饮食失调或运动成瘾。若出现持续限制进食、补偿行为或身体损伤，应及时寻求专业帮助。', '刷到大量减脂、增肌或体态对比内容后，开始用单一外形标准否定身体。', '参考：Holland与Tiggemann，2016；Prichard等，2020，Instagram健身灵感图像实验。', 1, 0, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (95, 1, '自拍编辑与发布后的外貌评价焦虑', '## 这是什么\\n\\n自拍评价焦虑，是在拍摄、编辑或发布自拍时，过度担心照片是否足够好看、别人如何评价，以及真实外貌与照片之间是否存在落差。它同时涉及身体意象和负面评价担忧。\\n\\n## 它通常怎样被触发\\n\\n反复自拍、修图、选择封面，或发布后等待点赞和评论时。\\n\\n## 为什么社交媒体会放大它\\n\\n自拍过程让用户长时间把注意力集中在可被修改的局部特征上。研究综述指出，拍摄和编辑自拍与更差的身体意象可能有关，而单纯发布本身的影响并不完全一致。公开反馈又把外貌评价转化成可见数字，进一步提高自我监控。\\n\\n**关键认知：**\\n\\n- 编辑越久不一定越接近“真实”，也可能让注意力更集中于缺点\\n- 照片反馈同时受关系、活跃度和平台分发影响\\n- 对照片不满意不等于他人正在负面评价真实的你\\n\\n## 常见表现\\n\\n- 拍很多张仍无法选出一张\\n- 修图后担心线下见面被发现差异\\n- 发布后持续检查谁点赞或是否有人取消点赞\\n\\n## 需要注意\\n\\n它与一般容貌焦虑有重叠，但重点在自拍制作和公开评价过程。研究不能证明所有自拍行为都会损害身体意象。', '自拍或发布照片时反复修改，既怕不好看又怕修得太多被识破。', '参考：Vandenbosch等，2022《Social Media and Body Image》综述；Burrow与Rainone，2016点赞反馈研究。', 1, 0, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (96, 1, '害怕错过（FOMO）', '## 这是什么\\n\\n害怕错过（Fear of Missing Out，FOMO）是担心别人正在经历有价值的活动、信息或关系，而自己没有参与或不知道。它常伴随持续查看动态、难以离线和对群体归属的担忧。\\n\\n## 它通常怎样被触发\\n\\n看到朋友聚会、热门活动、圈内消息，或暂时不能查看手机和社交平台时。\\n\\n## 为什么社交媒体会放大它\\n\\n社交媒体把原本不可见的他人活动持续展示出来，也不断提醒用户还有更多内容尚未查看。FOMO研究认为，基本心理需要满足较低的人可能更容易体验这种担忧；但它并不是正式临床诊断，也不能简单归因于“意志力差”。\\n\\n**关键认知：**\\n\\n- 错过活动是有限时间下的正常结果，不等于被群体抛弃\\n- 平台展示的是参与者视角，无法呈现活动中的无聊和成本\\n- FOMO与问题性使用相关，但两者关系可能相互影响\\n\\n## 常见表现\\n\\n- 明明疲惫仍不愿拒绝邀约\\n- 离线时反复担心群里发生重要事情\\n- 看到别人聚会后立即检查自己是否被排除\\n\\n## 需要注意\\n\\nFOMO是一种连续程度的体验。偶尔遗憾很常见，只有在它持续干扰睡眠、学习或关系时，才需要进一步关注其影响。', '不能参与活动或暂时离线时，强烈担心自己正在错过重要关系和机会。', '参考：Przybylski等，2013，FoMO量表与相关研究；Gupta与Sharma，2021综述。', 1, 1, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (97, 1, '未被邀请或被在线排除的归属焦虑', '## 这是什么\\n\\n在线排除焦虑，是在社交媒体中没有收到邀请、互动或可见反馈时，感觉自己被群体忽视或排斥。它与FOMO不同：FOMO强调错过活动，在线排除更强调“别人是否有意不接纳我”。\\n\\n## 它通常怎样被触发\\n\\n看到朋友聚会却没有自己、发言无人回应、互动明显少于其他成员，或在模拟社交平台中被忽略时。\\n\\n## 为什么社交媒体会放大它\\n\\n线上缺乏语气和情境线索，沉默的原因很难判断。实验研究显示，在线被排除会暂时威胁归属感、自尊和存在感；但现实场景中的无反馈也可能来自信息过载、责任分散或时间不合适。\\n\\n**关键认知：**\\n\\n- 没有反馈不能自动证明对方有意排斥\\n- 在线沉默容易让人用最负面的原因补全信息空白\\n- 排除感是真实体验，但对事件原因的解释仍可能不准确\\n\\n## 常见表现\\n\\n- 反复回看谁互动、谁没有互动\\n- 把一次冷场扩大为整个群体都讨厌自己\\n- 为了测试关系而发更多内容或突然退出群聊\\n\\n## 需要注意\\n\\n实验结果说明排除体验可能带来短期痛苦，不代表每次低互动都构成霸凌或真实关系终止。', '发现他人共同活动中没有自己，或发言长期无人回应，开始确信自己被整个圈子排斥。', '参考：Schneider等，2017《Social Media Ostracism》；Lutz与Schneider，2021在线忽视与拒绝研究。', 1, 0, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (98, 1, '点赞与评论数量带来的评价焦虑', '## 这是什么\\n\\n量化反馈焦虑，是把点赞、评论、转发或收藏数量理解为他人对自己人格、外貌或关系价值的评分。当反馈低于预期时，自我评价可能随之波动。\\n\\n## 它通常怎样被触发\\n\\n发布照片、观点或生活动态后，持续等待反馈，或把本次数据与自己过去及他人的数据比较时。\\n\\n## 为什么社交媒体会放大它\\n\\n社交媒体把模糊的人际反应转换成即时、可见的数字。实验研究发现，获得的点赞数量可以影响当下自尊，尤其是自我价值较依赖外部肯定的人。不过反馈数量也受发布时间、受众规模和平台展示影响，不能直接等同于接受或拒绝。\\n\\n**关键认知：**\\n\\n- 点赞是低成本互动，不是关系质量的完整测量\\n- 数据较少可能来自内容未被看到，而非他人否定\\n- 反馈对自尊的影响因个人稳定感和使用情境而异\\n\\n## 常见表现\\n\\n- 发布后不断刷新页面\\n- 低互动时立即删帖或感到羞耻\\n- 用赞数判断自己是否受欢迎\\n\\n## 需要注意\\n\\n量化反馈可能影响短期感受，但不能据此诊断“低自尊”或社交焦虑。需要区分偶尔在意与长期由数据决定自我价值。', '发帖后反馈少于预期，开始觉得自己不被喜欢或内容令人尴尬。', '参考：Burrow与Rainone，2016《How Many Likes Did I Get?》；Tobin等，2015在线无反馈与归属研究。', 1, 1, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (99, 1, '发帖前的负面评价焦虑', '## 这是什么\\n\\n发帖前评价焦虑，是在分享内容之前，过度担心别人会认为自己奇怪、炫耀、无聊或不专业，因此反复修改、限制可见范围或放弃发布。它属于社交媒体情境中的社会评价担忧。\\n\\n## 它通常怎样被触发\\n\\n准备发布自拍、观点、情绪或工作相关内容，且账号中同时存在同学、家人、同事和陌生人时。\\n\\n## 为什么社交媒体会放大它\\n\\n公开内容会脱离当下情境并被不同受众解读。社交媒体社交焦虑量表把“共享内容焦虑”视为一个独立维度，说明担心发布内容如何被看待是可测量的体验。评价焦虑可能在真实风险存在时发挥保护作用，但过度时会压缩表达空间。\\n\\n**关键认知：**\\n\\n- 谨慎发布不等于虚伪，也可能是合理边界管理\\n- 不同受众确实可能产生不同理解，但无法预先控制所有解释\\n- 焦虑关注的是可能评价，不等于负面评价已经发生\\n\\n## 常见表现\\n\\n- 一段文字反复修改很多次\\n- 担心被误解而完全不分享\\n- 发布后立刻后悔并删除\\n\\n## 需要注意\\n\\n它与隐私担忧、情境崩塌和一般社交焦虑相互关联。不能仅根据少发动态判断一个人存在社交障碍。', '想分享内容却不断预演别人会如何嘲笑或误解，最终不敢发送。', '参考：Alkis等，2017，SAS-SMU量表；Wang等，2024中文版量表修订。', 1, 0, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (100, 1, '线上互动与评论回复焦虑', '## 这是什么\\n\\n互动焦虑，是在评论、私信、群聊或公开讨论中，担心说错话、无法及时回应或被他人否定。它与发帖焦虑不同，重点是来回交流过程中的不确定和即时压力。\\n\\n## 它通常怎样被触发\\n\\n准备回复陌生人评论、进入不熟悉群聊、收到争议性回复，或需要在多人可见的讨论中表达时。\\n\\n## 为什么社交媒体会放大它\\n\\n文字交流缺少表情、语气和即时修复机会，短句可能被多种方式理解。社交媒体社交焦虑研究把互动焦虑列为一个维度；公开可见的回复链还会让用户意识到不只是对方，其他旁观者也可能阅读。\\n\\n**关键认知：**\\n\\n- 线上误解不一定来自表达能力差，也与媒介线索有限有关\\n- 不立即回复不等于失礼，平台交流通常具有异步性\\n- 担忧可能促使谨慎，但反复回避会让互动越来越陌生\\n\\n## 常见表现\\n\\n- 写好回复后迟迟不敢发送\\n- 不断解释和补充以避免被误解\\n- 收到轻微异议后长时间反刍\\n\\n## 需要注意\\n\\n该体验可能与现实社交焦虑相关，也可能只在特定平台、群体或争议话题中出现，需要结合情境理解。', '进入公开评论区或陌生群聊时，因担心说错话而明显紧张和回避。', '参考：Alkis等，2017，社交媒体用户社交焦虑量表；Marwick与boyd，2011受众研究。', 1, 0, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (101, 1, '多重受众重叠造成的表达焦虑', '## 这是什么\\n\\n情境崩塌（context collapse）指原本分开的关系群体，在同一个社交账号中成为共同受众。用户难以同时满足朋友、家人、老师、同事和客户的不同期待，因而产生表达压力。\\n\\n## 它通常怎样被触发\\n\\n想发布带有私人情绪、幽默、观点或生活方式的内容，却想到账号里存在多种关系和身份时。\\n\\n## 为什么社交媒体会放大它\\n\\n线下交流通常依赖场合调整表达，社交平台却把多个场合压缩到同一页面。研究显示，用户会在头脑中构建“想象受众”并据此进行自我呈现；当受众边界不清晰时，更容易使用最保守的表达或完全沉默。\\n\\n**关键认知：**\\n\\n- 面对不同人调整表达是正常社会能力，不必被理解为虚假\\n- 平台受众结构会增加表达难度，而非所有压力都来自个人敏感\\n- 无法设计一条让所有关系都满意的内容\\n\\n## 常见表现\\n\\n- 发布前反复筛选可见人群\\n- 担心工作身份与私人身份冲突\\n- 逐渐只发安全但缺乏个人性的内容\\n\\n## 需要注意\\n\\n情境崩塌是传播学概念，不是焦虑诊断。它能解释结构性压力，但具体风险仍取决于账号关系和内容性质。', '朋友圈或其他账号同时包含家人、同学和工作关系，导致任何内容都不敢发。', '参考：Marwick与boyd，2011《I Tweet Honestly, I Tweet Passionately》。', 1, 0, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (102, 1, '隐私泄露与个人信息暴露焦虑', '## 这是什么\\n\\n隐私暴露焦虑，是担心照片、位置、联系人、浏览信息或私人经历被不希望的人获取、转发或用于其他目的。它可以是合理风险判断，也可能因信息不透明而持续放大。\\n\\n## 它通常怎样被触发\\n\\n准备授权应用权限、公开位置和生活细节，或听到数据泄露、账号被盗、截图转发等事件时。\\n\\n## 为什么社交媒体会放大它\\n\\n用户往往难以直观看到数据如何被收集、保存和共享，平台设置也可能复杂。隐私研究显示，用户的隐私担忧包含对信息收集、未经同意访问和身份滥用等不同顾虑；担忧不一定与实际保护行为完全一致。\\n\\n**关键认知：**\\n\\n- 隐私担忧并非一定是过度反应，部分风险客观存在\\n- 焦虑会在控制范围和数据去向不清楚时上升\\n- 谨慎与完全不敢使用社交功能之间存在很多层次\\n\\n## 常见表现\\n\\n- 反复检查权限和可见范围\\n- 担心普通照片会泄露大量信息\\n- 因害怕数据被利用而避免必要的线上交流\\n\\n## 需要注意\\n\\n本条不判断某个平台是否安全，也不提供法律结论。应把现实安全风险与脱离证据的最坏情景想象区分开。', '发布内容或授权权限时，持续担心私人信息会被陌生人、平台或熟人滥用。', '参考：Buchanan等，2007，网络隐私担忧量表；Alkis等，2017隐私担忧焦虑维度。', 1, 0, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (103, 1, '旧内容与数字足迹暴露担忧', '## 这是什么\\n\\n数字足迹担忧，是害怕过去发布的照片、言论、用户名或互动记录在新的关系和身份阶段被重新发现。它常见于求职、升学、恋爱或公众曝光之前。\\n\\n## 它通常怎样被触发\\n\\n搜索自己的姓名和旧账号，发现多年以前的内容仍可访问，或看到他人因历史言论受到批评时。\\n\\n## 为什么社交媒体会放大它\\n\\n网络内容可能被长期保存、截图和重新传播，原始语境却容易丢失。多重受众和永久记录让用户难以确定未来谁会看到什么。隐私研究可以支持这种担忧具有现实基础，但并不能说明每一条旧内容都会产生严重后果。\\n\\n**关键认知：**\\n\\n- 过去内容需要结合当时语境和成长变化理解\\n- 被保存不等于一定会被搜索、传播或造成后果\\n- 合理清理与持续反复搜索自己的全部痕迹是不同状态\\n\\n## 常见表现\\n\\n- 深夜反复搜索旧账号和用户名\\n- 想到求职调查就持续紧张\\n- 把少年时期的表达视为不可挽回的永久污点\\n\\n## 需要注意\\n\\n它不是正式心理诊断。若存在真实威胁、骚扰或个人信息泄露，应优先按安全和法律问题处理，而不只视为情绪问题。', '进入新的学校、工作或关系阶段，担心过去的网络记录突然被翻出。', '参考：Marwick与boyd，2011情境崩塌研究；Buchanan等，2007网络隐私担忧研究。', 1, 0, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (104, 1, '消息回复延迟引发的关系不确定焦虑', '## 这是什么\\n\\n回复延迟焦虑，是发送消息后因长时间没有回复、看到已读标记或发现对方仍在其他地方活跃，而担心关系受损、自己被讨厌或事情出现问题。\\n\\n## 它通常怎样被触发\\n\\n向伴侣、朋友、老师或同事发送重要消息后，对方没有在预期时间内回应时。\\n\\n## 为什么社交媒体会放大它\\n\\n即时通讯制造了“随时可联系”的期待，同时又保留大量不确定性。已读、在线和正在输入等线索会让等待过程更加可见，却不能解释对方的情境。相关研究发现，是否及时回复受到个人、关系和社会规范影响，在线忽视也可能威胁归属感。\\n\\n**关键认知：**\\n\\n- 已读只说明内容被打开，不能说明对方的态度和可用精力\\n- 回复速度的意义在不同关系和情境中并不相同\\n- 不确定性会诱发负面解释，但解释不等于事实\\n\\n## 常见表现\\n\\n- 反复打开对话框和查看在线状态\\n- 连续补发消息确认对方是否生气\\n- 把一次延迟扩展为关系即将结束\\n\\n## 需要注意\\n\\n真实的长期冷处理与偶发回复延迟需要区分。本条不能替代对具体关系模式的判断。', '重要消息没有及时回复，开始反复检查对方动态并预演关系破裂。', '参考：Mai等，2015《I Know You’ve Seen It!》；Schneider等，2017在线排除研究。', 1, 0, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (105, 1, '必须及时回复的在线可用性压力', '## 这是什么\\n\\n在线可用性压力，是持续觉得自己必须快速回复工作或社交消息，否则就会被认为不负责、不重视关系或错过机会。在工作情境中，相关概念常被称为 workplace telepressure。\\n\\n## 它通常怎样被触发\\n\\n下班后仍收到工作群消息、多人同时私信，或所在群体形成“秒回才算认真”的隐性规范时。\\n\\n## 为什么社交媒体会放大它\\n\\n移动通讯使工作和私人时间边界变得模糊。telepressure研究把它定义为对消息的持续牵挂和迅速回复冲动，并发现其与较差的心理脱离和恢复有关。它与单纯消息多不同，重点是“我必须马上回应”的内在压力。\\n\\n**关键认知：**\\n\\n- 即时通讯的技术可达性不等于个人必须随时可用\\n- 回复规范是群体和组织共同形成的，不应全部归因于个人自控\\n- 快速回复有时必要，但长期保持警戒会占用恢复时间\\n\\n## 常见表现\\n\\n- 休息时仍不断想是否有新消息\\n- 听到提示音立即紧张\\n- 即使没有明确要求也不敢延迟回复\\n\\n## 需要注意\\n\\n该研究主要来自工作通讯，迁移到私人社交场景时需要谨慎。它不是对所有快速回复习惯的病理化描述。', '明明已经休息，却因担心漏回群消息而始终不敢离开手机。', '参考：Barber与Santuzzi，2015《Please Respond ASAP: Workplace Telepressure and Employee Recovery》。', 1, 0, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (106, 1, '“始终在线”的在线警觉焦虑', '## 这是什么\\n\\n在线警觉（online vigilance）是即使没有正在使用手机，注意力仍持续朝向线上消息、内容和互动的状态。它包括反复想到线上事件、对通知高度反应和主动监控更新。\\n\\n## 它通常怎样被触发\\n\\n学习、工作、吃饭或与人交谈时，脑中不断出现查看动态、消息和评论的冲动。\\n\\n## 为什么社交媒体会放大它\\n\\n智能手机让在线内容随时可达，用户也逐渐形成持续连接的预期。在线警觉量表把这种状态分为显著性、反应性和监控性等维度。研究提示，它可能通过走神和难以心理脱离影响幸福感，但关系并非对所有人都相同。\\n\\n**关键认知：**\\n\\n- 屏幕使用时间不高，也可能存在持续的认知牵挂\\n- 想查看不代表必须立即查看，冲动和行动可以分开\\n- 在线警觉是连续特征，不是对注意缺陷疾病的判断\\n\\n## 常见表现\\n\\n- 做事时频繁想起未读消息\\n- 无意识点亮屏幕确认更新\\n- 离开网络后仍反复回想评论和争论\\n\\n## 需要注意\\n\\n不要把在线警觉直接称为“成瘾”或脑损伤。研究更关注认知取向及其与日常状态的关系。', '手机没有响，但工作或学习时仍持续担心线上是否发生了新事情。', '参考：Reinecke等，2018，Online Vigilance Scale；Johannes等，2020在线警觉与日常情绪研究。', 1, 1, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (107, 1, '手机分离与断联焦虑', '## 这是什么\\n\\n手机分离焦虑或无手机恐惧（nomophobia），描述无法使用手机、无法通信、无法获取信息或失去便利时出现的不安。它不是正式临床诊断，而是通过量表研究的数字生活现象。\\n\\n## 它通常怎样被触发\\n\\n手机没电、无信号、遗忘手机，或处在必须上交设备的环境时。\\n\\n## 为什么社交媒体会放大它\\n\\nNMP-Q研究归纳出无法通信、失去连接、无法获取信息和放弃便利等维度。现代手机同时承载社交、支付、导航和工作功能，因此分离时的担忧可能既有现实原因，也有习惯和持续连接期待的影响。\\n\\n**关键认知：**\\n\\n- 手机承担多种现实功能，短暂不安并不自动等于心理问题\\n- 担忧的重点可能是安全、工作、社交或便利，需要分别理解\\n- nomophobia是研究术语，不应被夸大为公认的临床恐惧症\\n\\n## 常见表现\\n\\n- 电量下降时明显坐立不安\\n- 不断确认信号和充电设备\\n- 短暂离开手机就担心错过重要消息\\n\\n## 需要注意\\n\\n需要区分现实应急需求和与风险不相称的持续恐慌。不能只凭“经常带充电宝”判断问题程度。', '手机没电或无法联网时，出现明显不安并反复确认是否恢复连接。', '参考：Yildirim与Correia，2015，NMP-Q开发与验证研究。', 1, 0, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (108, 1, '社交媒体信息过载焦虑', '## 这是什么\\n\\n信息过载焦虑，是接收的新闻、观点、通知和群消息超过自身处理能力后，出现混乱、紧张和难以判断轻重缓急的状态。它不仅取决于信息数量，也取决于矛盾程度和是否要求回应。\\n\\n## 它通常怎样被触发\\n\\n热点事件密集发生、多群同时活跃，或为了弄清真相连续打开大量帖子、视频和评论时。\\n\\n## 为什么社交媒体会放大它\\n\\n社交媒体把信息过载、沟通过载和社交过载叠加在同一设备上。研究发现，这些过载体验与焦虑、信息压力和疲劳存在关联，尤其在公共卫生危机等高不确定场景中更明显。但多数研究为相关性或特定时期调查。\\n\\n**关键认知：**\\n\\n- 更多信息不一定带来更高确定性，矛盾信息可能增加负担\\n- 处理不过来不代表理解能力差，可能是输入超过了当前资源\\n- 过载与焦虑可能互相强化，焦虑也会促使人继续搜索\\n\\n## 常见表现\\n\\n- 多个信息源之间反复切换\\n- 看了很多内容仍觉得完全不知道该相信什么\\n- 因漏看消息而持续紧张\\n\\n## 需要注意\\n\\n不能把公共危机期间的研究结果不加区分地推广到所有日常使用。具体影响还与内容可信度和个人处境有关。', '新闻、群聊和推荐内容同时涌入，越看越混乱却又不敢停止时。', '参考：Li等，2023，社交媒体过载、焦虑与健康自我效能研究；Wang等，2023上海大学生研究。', 1, 0, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (109, 1, '社交媒体疲劳与“应付不动”感', '## 这是什么\\n\\n社交媒体疲劳是对持续浏览、互动、更新和维持关系感到厌倦，表现为注意力下降、情绪耗竭和想暂时退出。它与焦虑不同，但可能与焦虑、强迫性使用和FOMO形成循环。\\n\\n## 它通常怎样被触发\\n\\n平台和群聊过多、信息重复、需要持续回应，或一边觉得累一边担心退出后错过内容时。\\n\\n## 为什么社交媒体会放大它\\n\\n研究使用压力—负荷—结果框架解释：强迫性使用和FOMO可能增加疲劳，而疲劳又与更高的焦虑和抑郁症状相关。由于许多研究为横断面或重复横断面设计，不能简单断言疲劳一定导致焦虑。\\n\\n**关键认知：**\\n\\n- 疲劳可能来自信息、互动、角色管理等不同来源\\n- 想减少使用不等于讨厌所有线上关系\\n- 疲劳和继续使用可以同时存在，这并不矛盾\\n\\n## 常见表现\\n\\n- 打开应用后很快感到烦躁\\n- 不想回复却又担心关系受影响\\n- 删除应用后不久又重新安装\\n\\n## 需要注意\\n\\n疲劳是使用体验，不是单独的医学诊断。需要结合睡眠、工作负荷和现实压力判断主要来源。', '觉得社交平台令人疲惫，却又因为担心错过消息而无法真正离开。', '参考：Dhir等，2018《Online Social Media Fatigue and Psychological Wellbeing》。', 1, 0, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (110, 1, '末日刷屏（Doomscrolling）', '## 这是什么\\n\\n末日刷屏是明知负面新闻会让自己更难受，仍持续滚动、搜索和查看灾难、冲突或危机内容。它通常包含“再看一点也许就能弄清局势”的想法。\\n\\n## 它通常怎样被触发\\n\\n重大灾害、公共卫生事件、战争冲突或经济不确定时期，反复刷新热搜、推荐流和评论区时。\\n\\n## 为什么社交媒体会放大它\\n\\n消极信息更容易吸引注意，而不断更新的信息流又让用户觉得关键消息可能出现在下一条。Doomscrolling Scale研究发现，该行为与心理痛苦、FOMO、社交媒体成瘾指标及较低幸福感相关，但这些发现主要是关联，不能确定单一因果方向。\\n\\n**关键认知：**\\n\\n- 继续刷新不一定能提高判断准确性，可能只增加重复暴露\\n- 担忧会推动搜索，搜索后的内容又可能继续放大担忧\\n- 末日刷屏描述的是行为模式，不是正式疾病名称\\n\\n## 常见表现\\n\\n- 睡前不断刷新坏消息\\n- 停下后仍在脑中反复预演最坏结果\\n- 因为担心漏掉变化而不敢结束浏览\\n\\n## 需要注意\\n\\n需要与合理获取应急信息区分。关键不只是内容负面，而是难以停止、重复暴露和明显影响日常功能。', '突发事件后持续刷新负面信息，越看越焦虑却难以停下。', '参考：Satici等，2022，Doomscrolling Scale及其与心理痛苦和幸福感的研究。', 1, 1, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (111, 1, '灾难影像反复暴露引发的应激焦虑', '## 这是什么\\n\\n灾难媒介暴露焦虑，是普通用户反复观看灾害、暴力和伤亡影像后，出现紧张、侵入性回想、睡眠受扰或安全感下降。它与末日刷屏不同：重点是高强度影像和重复暴露带来的应激反应。\\n\\n## 它通常怎样被触发\\n\\n突发袭击、事故或自然灾害发生后，推荐流连续出现现场视频、受害者画面和循环播放的新闻片段时。\\n\\n## 为什么社交媒体会放大它\\n\\n大型事件研究发现，反复接触相关媒体报道与更高的急性应激症状相关，有些研究中高媒体暴露者的应激甚至高于部分直接暴露者。但这并不意味着观看新闻等同于亲历创伤，也不能把所有难受都称为替代性创伤。\\n\\n**关键认知：**\\n\\n- 画面重复出现会让事件在注意中持续保持活跃\\n- 强烈反应可能与既往经历、暴露时长和内容类型有关\\n- 共情和难受是正常反应，不必因此自我指责\\n\\n## 常见表现\\n\\n- 脑中反复出现看过的画面\\n- 听到相似声音就紧张\\n- 暂时不敢进入相关平台或新闻页面\\n\\n## 需要注意\\n\\n只有专业评估才能判断是否达到创伤相关障碍标准。本文只解释媒体暴露与应激反应的研究关系。', '反复看到灾难现场视频后，出现明显紧张、失眠或画面挥之不去。', '参考：Holman、Garfin与Silver，2014，波士顿马拉松爆炸事件媒体暴露研究。', 1, 0, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (112, 1, '健康信息过载与网络疑病焦虑', '## 这是什么\\n\\n健康信息焦虑，是在社交媒体上接触大量症状、疾病和风险内容后，反复担心自己或家人患病，并持续搜索以获得确定感。网络疑病（cyberchondria）强调在线健康搜索与健康焦虑之间可能形成循环。\\n\\n## 它通常怎样被触发\\n\\n公共卫生事件、身体出现普通不适，或推荐流连续推送疾病自测、罕见病案例和风险警告时。\\n\\n## 为什么社交媒体会放大它\\n\\n健康内容往往信息不完整、来源质量不一，并突出严重案例。纵向研究提示健康焦虑和在线健康搜索可能相互影响；2026年的社交媒体健康信息焦虑研究也指出，事件严重度、信息过载、信息不对称和集体情绪可能共同发挥作用。\\n\\n**关键认知：**\\n\\n- 搜索可以提供信息，也可能在无法获得绝对确定时继续放大担忧\\n- 个案内容不能用于估计自己患病概率\\n- 健康焦虑与真实症状可以同时存在，不能用心理解释排除医学检查\\n\\n## 常见表现\\n\\n- 看到症状视频后立即对号入座\\n- 不断更换关键词搜索严重疾病\\n- 短暂安心后很快再次怀疑\\n\\n## 需要注意\\n\\n本文不提供诊断。出现新的、持续的或严重身体症状时，应依据正规医疗渠道评估，而不是只依赖社交媒体信息。', '刷到疾病或症状内容后，开始反复搜索并确信自己可能患有严重疾病。', '参考：Te Poel等，2016网络疑病纵向研究；Xiao等，2026社交媒体健康信息焦虑研究。', 1, 0, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (113, 1, '网络欺凌或骚扰后的持续警觉', '## 这是什么\\n\\n网络骚扰后的持续警觉，是在经历辱骂、威胁、围攻、跟踪或隐私攻击后，持续担心新的攻击出现，并反复监控账号、评论和现实安全。这里的焦虑与真实伤害事件有关，不应简单归为“太敏感”。\\n\\n## 它通常怎样被触发\\n\\n收到恶意私信、被多人围攻、被持续搜索联系，或个人信息遭到传播之后。\\n\\n## 为什么社交媒体会放大它\\n\\n网络攻击可以跨时间、跨平台重复出现，内容也容易被复制和扩大。儿童青少年网络欺凌综述和成人网络骚扰系统综述都报告了与焦虑、抑郁、压力和生活功能受损的关联。持续警觉在这种情况下可能是一种风险应对反应。\\n\\n**关键认知：**\\n\\n- 存在真实威胁时，安全担忧具有现实基础\\n- 受害者的焦虑不应被解释为网络承受力不足\\n- 评论数量和传播范围会影响压力，但个体反应也有差异\\n\\n## 常见表现\\n\\n- 不断检查是否出现新账号攻击\\n- 对通知声产生明显紧张\\n- 因担心被找到而回避正常社交和出行\\n\\n## 需要注意\\n\\n涉及威胁、人肉、跟踪或隐私泄露时，应作为安全事件处理。心理支持不能替代证据保存、平台举报和必要的法律求助。', '遭遇网暴、威胁或跟踪后，对任何新通知都高度紧张并担心攻击继续。', '参考：Hamm等，2015网络欺凌影响综述；Stevens等，2021成人网络跟踪与骚扰系统综述。', 1, 0, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (114, 1, '伴侣社交媒体监控与嫉妒焦虑', '## 这是什么\\n\\n社交媒体关系嫉妒，是看到伴侣与他人的点赞、评论、好友关系或旧照片后，对关系安全产生怀疑，并通过继续查看获得更多线索。它常形成“越监控、越发现模糊信息、越不安”的循环。\\n\\n## 它通常怎样被触发\\n\\n伴侣新增好友、与特定对象互动、没有公开关系状态，或旧内容中出现前任和暧昧线索时。\\n\\n## 为什么社交媒体会放大它\\n\\n社交媒体提供了大量脱离语境的关系信息，例如一个点赞无法说明互动目的。早期Facebook研究发现，使用程度与平台相关嫉妒有关，并提出信息暴露和监控可能相互强化。研究说明的是关联和循环可能，不等于所有线上互动都代表关系风险。\\n\\n**关键认知：**\\n\\n- 模糊线上线索不能替代直接沟通和长期行为\\n- 监控可能短暂提供信息，也可能制造更多需要解释的细节\\n- 嫉妒感是真实的，但对线索的解释仍可能错误\\n\\n## 常见表现\\n\\n- 反复查看伴侣关注和点赞名单\\n- 根据在线状态推测对方在隐瞒什么\\n- 把普通互动理解为关系背叛\\n\\n## 需要注意\\n\\n若关系中存在控制、欺骗或暴力，需要按现实关系问题处理；本条不应用来否定合理怀疑，也不为监控行为辩护。', '因伴侣的点赞、关注或旧动态产生强烈怀疑，并反复查看其账号活动。', '参考：Muise、Christofides与Desmarais，2009，Facebook与浪漫关系嫉妒研究。', 1, 0, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (115, 1, '拟社会关系中断后的失落与不安', '## 这是什么\\n\\n拟社会关系是受众与媒体人物、主播、博主或虚拟角色形成的单向情感联结。拟社会关系中断，是当对方停更、离开作品、账号消失或形象发生重大变化时，受众产生失落、愤怒或空缺感。\\n\\n## 它通常怎样被触发\\n\\n长期关注的创作者突然退网、节目结束、角色离开，或信任的公众人物出现与既有印象冲突的信息时。\\n\\n## 为什么社交媒体会放大它\\n\\n高频接触、直接镜头表达和生活细节分享会增加熟悉感。拟社会关系研究表明，关系强度和依恋特征与中断后的痛苦程度有关。虽然最早研究来自电视角色，相关机制可谨慎用于理解今天的主播和博主关系。\\n\\n**关键认知：**\\n\\n- 单向关系也可能承载真实情绪和生活意义\\n- 感到难过不等于误把对方当成现实朋友\\n- 网络呈现始终是有限信息，关系中断也可能迫使原有想象发生调整\\n\\n## 常见表现\\n\\n- 反复回看旧内容\\n- 对停更或形象变化感到被抛下\\n- 因觉得自己“不该为陌生人难过”而羞耻\\n\\n## 需要注意\\n\\n应统一使用“拟社会关系”，而不是带有贬义的“寄生关系”。该概念不表示受众愚蠢或创作者一定在欺骗。', '长期陪伴自己的博主、主播或角色突然消失，产生类似告别后的空缺感。', '参考：Cohen，2003拟社会关系中断量表；Cohen，2004拟社会关系中断、依恋与关系强度研究。', 1, 0, NULL, NULL, '2026-06-16 14:13:10', '2026-06-16 14:13:10');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (116, 2, '精致生活与高光日常人设', '## 这种人设是什么\\n\\n这类人设把日常生活呈现为稳定、整洁、审美统一且值得记录的连续画面。常见内容包括布置讲究的房间、精心搭配的餐食、氛围感通勤和被认真安排的周末。它可能是真实生活的一部分，但并不等于发布者每天都处在同样的状态。\\n\\n## 它通常展示什么\\n\\n画面往往集中在适合公开、容易获得认可的时刻，例如完成布置后的房间、光线最好的早餐、已经解决问题后的复盘。不同日期和场景经过持续筛选后，会形成一种“生活一直很顺”的整体印象。\\n\\n## 它容易省略什么\\n\\n准备、返工、家务、经济成本、情绪低谷和普通到不值得拍摄的时段通常较少出现。被省略并不一定是欺骗，而是社交媒体自我呈现天然会优先选择可展示内容。\\n\\n## 为什么看起来很有说服力\\n\\n稳定的视觉风格和连续更新会让零散高光看起来像完整生活。观看者还容易把多个账号的优点叠加成一个不存在的“标准生活”，再与自己的全部日常比较。\\n\\n**观看时需要区分：**\\n\\n- 精致画面可以真实，但通常不是生活的平均切片\\n- 审美一致性反映内容选择，也可能反映时间、金钱与劳动投入\\n- 不应仅凭公开动态判断一个人的幸福程度\\n\\n## 需要注意\\n\\n研究表明，社交媒体自我呈现既可能包含真实表达，也可能带有选择性增强；具体程度因人、平台和受众而异。', '连续刷到整洁、从容、充满仪式感的日常后，开始觉得自己的普通生活粗糙而失败时。', '参考：Fox与Vendemia，2016，照片中的选择性自我呈现；Chou与Edge，2012，社交媒体与他人生活感知。', 1, 1, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (117, 2, '松弛感与“不费力”人设', '## 这种人设是什么\\n\\n松弛感人设强调自然、从容、不急于证明自己，好像工作、外貌、社交和生活品位都能毫不费力地维持。它与传统的炫耀不同，吸引力恰恰来自“看起来没有在经营”。\\n\\n## 它通常展示什么\\n\\n内容常呈现随手拍却构图良好的照片、轻描淡写的成功、不过度解释的消费选择，以及在繁忙生活中仍然保留休闲与审美的状态。\\n\\n## 它容易省略什么\\n\\n形成这种效果所需的筛选、拍摄、经济条件、时间安排和情绪管理通常不会进入画面。发布者也可能确实较为从容，但观看者无法从结果反推出过程毫无压力。\\n\\n## 为什么看起来很有说服力\\n\\n人们往往把明显努力与表演联系起来，而把自然感与真实性联系起来。持续稳定的“随意”风格会削弱观看者对策划程度的感知，使生活优势看起来像性格本身。\\n\\n**观看时需要区分：**\\n\\n- 从容可能是真实特质，也可能只是被选择出来的公开侧面\\n- 看起来不费力，不代表没有准备、资源或他人协助\\n- 松弛感不是衡量心理健康和生活能力的统一标准\\n\\n## 需要注意\\n\\n人设图鉴的目标不是揭穿谁在表演，而是提醒观看者：任何稳定的公开形象都可能经过选择。', '看到别人工作顺利、外形精致又从不显得紧张，怀疑自己太用力、太狼狈时。', '参考：Audrezet等，2020，网红真实性管理；Zheng等，2020，社交媒体中的自我提升与自我验证。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (118, 2, '极致自律与晨间仪式人设', '## 这种人设是什么\\n\\n这类人设以规律、克制和持续执行为核心，常用早起、运动、阅读、饮食管理和时间规划证明个人掌控力。它可能提供动力，但也会把复杂生活压缩为一条整齐的习惯链。\\n\\n## 它通常展示什么\\n\\n镜头常记录已经完成的打卡、整洁的工具、明确的时间表和状态良好的身体。内容强调重复性和连续性，使观众感到这些行为每天都能稳定发生。\\n\\n## 它容易省略什么\\n\\n睡眠不足、工作安排、失败天数、恢复时间、家庭支持和用于维护习惯的成本较少被展示。偶尔中断也可能不被发布，因此公开记录通常比真实执行更连贯。\\n\\n## 为什么看起来很有说服力\\n\\n数字打卡与连续更新会把行为转化成清晰证据；固定机位和相似流程进一步强化“稳定人格”的印象。观看者容易把内容生产本身误认为普通生活的自然记录。\\n\\n**观看时需要区分：**\\n\\n- 习惯记录可以激励人，但不能证明发布者从不疲惫或拖延\\n- 能够长期自律往往与环境、资源和工作性质有关\\n- 适合他人的完整流程不等于适合所有人的健康标准\\n\\n## 需要注意\\n\\n本条只分析人设结构；具体的时间管理方法和使用边界应放入行动建议或训练分类。', '刷到完整早起、运动、学习流程后，把自己偶尔拖延解释成缺乏意志力时。', '参考：Duffy与Hund，2015，社交媒体自我品牌与“拥有一切”叙事；Hjetland等，2022，自我呈现关注。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (119, 2, '学霸与高效学习人设', '## 这种人设是什么\\n\\n学霸人设通过成绩、学习时长、笔记、书桌和备考流程，建立“聪明、勤奋且始终高效”的形象。Studygram和“Study With Me”内容既可能提供陪伴与学习灵感，也可能使学习过程更适合被观看。\\n\\n## 它通常展示什么\\n\\n常见展示包括整洁笔记、连续计时、录取结果、阶段性成果和高度结构化的学习环境。知识理解、学习策略和可视化进度被组合成容易模仿的模板。\\n\\n## 它容易省略什么\\n\\n走神、低效尝试、对知识的误解、成绩波动以及不适合拍摄的混乱过程不容易进入内容。学习直播也不等于主播在每个镜头外时段都保持同样专注。\\n\\n## 为什么看起来很有说服力\\n\\n可见的计时器、任务清单和书桌布置让抽象的努力变得具体。观众容易把能被拍摄的“学习样子”与真实掌握程度、长期成绩完全等同。\\n\\n**观看时需要区分：**\\n\\n- 学习内容可以提供陪伴和可控的同伴压力\\n- 漂亮笔记和长时间直播不能单独证明学习质量\\n- 发布者的专业、考试制度和现实条件可能与观看者不同\\n\\n## 需要注意\\n\\n这类内容既可能有正面价值，也可能引发比较；不能统一判断为虚假或有害。', '看到别人长时间学习、笔记精美和一次上岸后，觉得自己的学习过程不够像“真正努力”时。', '参考：Izquierdo-Iranzo与Gallardo-Echenique，2020；Lee等，2021；Lussier等，2023。', 1, 1, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (120, 2, '职场精英与持续上升人设', '## 这种人设是什么\\n\\n职场精英人设把个人职业身份组织成清晰的成长故事：能力不断提升、项目不断扩大、机会持续出现。它在职业平台和普通社交媒体上都很常见，核心是证明专业性、可靠性和发展潜力。\\n\\n## 它通常展示什么\\n\\n内容通常聚焦职位变化、项目成果、公开演讲、行业活动、证书和工作方法。失败的申请、普通重复劳动和无法公开的团队贡献较少出现。\\n\\n## 它容易省略什么\\n\\n职业成果往往由团队、行业周期、组织资源和机会共同形成，但个人主页倾向于把复杂过程压缩为个人能力叙事。求职空窗、迷茫和工作中的低控制感也不适合公开展示。\\n\\n## 为什么看起来很有说服力\\n\\n平台界面鼓励填写技能、经历和背书，使职业身份变成可持续更新的履历。专业术语和第三方认可还能增强可信度，让观看者把公开档案当成完整能力评估。\\n\\n**观看时需要区分：**\\n\\n- 职业主页的功能本来就是突出可验证成果\\n- 持续发布成果不代表现实工作没有挫折和重复\\n- 职位、收入与个人价值不是同一指标\\n\\n## 需要注意\\n\\n对职业平台内容应保持信息工具视角，而不是把每一份公开履历当作同龄人的统一进度线。', '求职或工作受挫时，看到别人持续晋升、获奖和输出专业观点，觉得自己已被行业淘汰时。', '参考：van Dijck，2013，Facebook与LinkedIn的身份呈现；Bar-Ilan等，2015，学术职业自我呈现。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (121, 2, '创业成功与自由职业人设', '## 这种人设是什么\\n\\n创业与自由职业人设强调自主、创造力和摆脱传统组织约束，常把工作呈现为个人选择、热爱与生活方式的统一。它既可能记录真实职业路径，也容易将不稳定劳动包装成连贯的成长故事。\\n\\n## 它通常展示什么\\n\\n常见内容包括项目启动、客户反馈、收入节点、灵活办公、个人理念和“从零开始”的回顾。叙事通常突出个人意志、勇气和快速迭代。\\n\\n## 它容易省略什么\\n\\n现金流波动、失败项目、无报酬劳动、平台依赖、家庭支持和长期积累较少进入公开故事。成功发生后，早期经历也可能被重新组织成看似必然的路线。\\n\\n## 为什么看起来很有说服力\\n\\n个人品牌叙事需要把复杂职业经历讲成容易理解的角色：有愿景、敢行动、能转化。连续发布会让尚在变化的职业状态看起来已经稳定。\\n\\n**观看时需要区分：**\\n\\n- 自由度和不确定性可以同时存在\\n- 个人成功可能包含团队、资本、运气与既有资源\\n- 公开复盘常是事后整理，不是可复制的完整路线\\n\\n## 需要注意\\n\\n不要把创业人设简单视为吹嘘，也不要把它直接当作职业选择的风险说明书。', '看到别人辞职创业、远程工作并快速变现后，觉得稳定工作等于失败或缺乏勇气时。', '参考：Duffy与Hund，2015，创业式自我品牌；Khamis等，2017，微名人与社交媒体网红的自我品牌。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (122, 2, '财富自由与高消费品位人设', '## 这种人设是什么\\n\\n这类人设通过消费选择、居住环境、旅行和品牌偏好，传递财富、品位和生活掌控感。重点不一定是直接展示价格，也可能通过稀缺体验、低调品牌和“懂行”细节表达社会位置。\\n\\n## 它通常展示什么\\n\\n内容常选择高辨识度商品、精致空间、稀缺服务或消费后的从容体验。产品被放进日常叙事后，看起来不只是购买物，而是身份、审美和生活能力的证据。\\n\\n## 它容易省略什么\\n\\n收入来源、负债、合作置换、租借、赠品、家庭资源和为消费付出的机会成本可能不会被说明。即便消费完全真实，也无法据此推断长期财务状况。\\n\\n## 为什么看起来很有说服力\\n\\n社交媒体使消费具有公开比较功能。研究发现，自我呈现、社会比较和炫耀性消费倾向之间可能相互强化；豪华体验也容易通过羡慕影响购买意向。\\n\\n**观看时需要区分：**\\n\\n- 拥有某件商品不等于拥有稳定财富\\n- 品牌和场景能传递身份信号，但不代表完整财务结构\\n- 商业合作与个人消费应尽量分开理解\\n\\n## 需要注意\\n\\n本条不判断具体消费是否合理，只帮助识别“消费被用来表达身份”的人设结构。', '连续看到高消费、稀缺体验和“随手买”的内容后，开始用购买力判断自己是否体面时。', '参考：Lu等，2024，微信自我呈现与炫耀性消费；Liu等，2024，社交分享、羡慕与消费意向。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (123, 2, '旅行达人与数字游牧人设', '## 这种人设是什么\\n\\n旅行达人或数字游牧人设把移动、自由和世界经验作为核心身份。它强调地点切换、文化体验和自主安排，让工作与旅行看起来能够自然融合。\\n\\n## 它通常展示什么\\n\\n常见展示包括景观、特色住宿、当地饮食、远程办公画面以及“像当地人一样生活”的叙事。地点连续变化会强化生活丰富、时间自由和见识广阔的形象。\\n\\n## 它容易省略什么\\n\\n交通疲劳、签证限制、预算、工作时差、安全问题、拍摄等待和重复性行政事务较少成为主要内容。旅行者的停留时间、合作关系和工作稳定性也未必能从照片判断。\\n\\n## 为什么看起来很有说服力\\n\\n陌生地点本身具有视觉新鲜感，连续更新还能把短暂旅程组织成长期身份。旅游网红研究指出，旅行身份需要持续建构与维护，而不是地点照片的简单集合。\\n\\n**观看时需要区分：**\\n\\n- 旅行体验可以真实丰富，也可能同时包含大量不可见劳动\\n- 短期度假、内容创作和长期游牧是不同生活方式\\n- 景点密度不能直接衡量日常自由度和幸福感\\n\\n## 需要注意\\n\\n不要因为看到自由移动的结果，就假定对方没有经济、行政和职业约束。', '刷到持续旅行和远程办公内容后，觉得固定城市、固定作息的生活缺乏价值时。', '参考：Li等，2024，旅行网红的社会身份建构；Audrezet等，2020，网红真实性管理。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (124, 2, '健身塑形与健康自律人设', '## 这种人设是什么\\n\\n健身人设以身体变化、运动纪律和健康知识建立可信度，常把可见体型与自我管理能力联系起来。部分内容确实能提供运动信息和鼓励，但“健康”与“符合某种外形”经常被混在一起。\\n\\n## 它通常展示什么\\n\\n内容通常展示训练片段、饮食、体重或围度变化、紧致体型和前后对比。镜头偏好容易识别的身体成果，而不是心肺、睡眠、力量恢复等难以视觉化的健康指标。\\n\\n## 它容易省略什么\\n\\n基因、拍摄状态、伤病、恢复期、专业指导、饮食压力和状态波动较少出现。单次照片也无法说明长期健康、饮食关系或训练是否适合他人。\\n\\n## 为什么看起来很有说服力\\n\\nFitspiration把身体目标、励志语言与日常记录结合，使外貌理想看起来像纯粹的健康成果。系统综述显示，这类内容可能同时具有激励作用与身体比较风险。\\n\\n**观看时需要区分：**\\n\\n- 有运动习惯不等于所有建议都具备专业依据\\n- 视觉上的精瘦或强壮不等于完整健康\\n- 前后对比省略了时间、条件和个体差异\\n\\n## 需要注意\\n\\n看到健身内容时，可以区分“记录个人经验”“提供一般知识”和“给出医疗营养建议”三种角色。', '看到健身博主的体型和训练流程后，把自己的身体状态直接理解为不自律时。', '参考：Jerónimo与Carraça，2022，Fitspiration系统综述；Tiggemann与Zaccardo，2015；Carrotte等，2017。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (125, 2, '高颜值与精致外貌人设', '## 这种人设是什么\\n\\n高颜值人设以面部、妆容、穿搭和镜头表现力为核心，持续建立“随时都很好看”的印象。外貌可以是真实优势，但公开内容通常是特定角度、时段和筛选标准下的表现。\\n\\n## 它通常展示什么\\n\\n常见展示包括自拍、妆前妆后、穿搭、护肤和被他人拍摄的生活照。稳定的妆容、表情和构图会让个人外貌形成明确而可识别的品牌。\\n\\n## 它容易省略什么\\n\\n皮肤状态波动、不适合上镜的角度、拍摄次数、妆造时间、数字编辑和普通生活中的样子可能不会被同步展示。即使没有修图，选择哪张照片发布本身也是呈现行为。\\n\\n## 为什么看起来很有说服力\\n\\n照片内容容易被快速比较，点赞和评论还会为某种外貌提供社会认可线索。视觉平台上的选择性自拍与身体比较研究表明，观看者容易把筛选后的图像当成稳定现实。\\n\\n**观看时需要区分：**\\n\\n- 精修与真实并不是非黑即白，照片可同时包含真实特征与选择加工\\n- 好看是特定审美和场景中的评价，不是完整个人价值\\n- 账号风格稳定不代表本人每时每刻都保持同样外貌\\n\\n## 需要注意\\n\\n本条不讨论具体修图方法；图像处理与平台审美机制应放在“套路拆解”。', '长时间浏览精致自拍和穿搭账号后，觉得普通光线下的自己“不像一个正常人”时。', '参考：Fox与Vendemia，2016；Vandenbosch等，2022，社交媒体与身体意象综述。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (126, 2, '完美伴侣与甜蜜关系人设', '## 这种人设是什么\\n\\n完美关系人设把亲密关系呈现为稳定支持、浪漫投入和高度默契。纪念日、礼物、共同旅行和公开互动被组织成持续的关系证明，使旁观者容易把可见浪漫当作整体质量。\\n\\n## 它通常展示什么\\n\\n内容通常展示值得纪念的节点、伴侣的体贴行为、共同爱好和冲突解决后的结果。关系中的公开确认也可能帮助双方表达承诺和归属。\\n\\n## 它容易省略什么\\n\\n日常协商、价值冲突、沉默时段、家务分配和不便公开的关系边界通常不会出现。很少发布伴侣并不等于关系疏远，频繁发布也不能证明不存在问题。\\n\\n## 为什么看起来很有说服力\\n\\n人们倾向于通过有限线索推断他人生活。社交媒体上的积极自我呈现会让观看者更容易认为他人拥有更好的生活；关系内容还会借助双方互动增强真实性。\\n\\n**观看时需要区分：**\\n\\n- 公开浪漫是关系的一部分，不是完整质量检测\\n- 表达方式因人而异，低调不等于缺爱\\n- 一段关系是否健康，需要看线下尊重、沟通和安全，而不是动态密度\\n\\n## 需要注意\\n\\n不要将所有情侣内容都解释为表演，也不要用它作为要求自己或伴侣复制同款表达的依据。', '看到他人频繁晒礼物、纪念日和旅行后，开始怀疑自己的关系不够浪漫或不够被爱时。', '参考：Chou与Edge，2012，社交媒体与他人生活感知；Zheng等，2020，自我提升式呈现。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (127, 2, '完美父母与精致育儿人设', '## 这种人设是什么\\n\\n精致育儿人设通过儿童成长、家庭秩序、教育安排和亲子互动，建立“有耐心、懂方法、家庭运行良好”的父母形象。分享可能出于记录、支持交流或职业内容，并不必然是炫耀。\\n\\n## 它通常展示什么\\n\\n常见内容包括营养餐、亲子阅读、整洁家居、成长里程碑和温和沟通片段。孩子的成果也会成为父母身份与养育能力的公开证据。\\n\\n## 它容易省略什么\\n\\n育儿冲突、照护者疲惫、家庭帮助、经济投入、孩子不愿公开的时刻以及拍摄之外的重复劳动较少出现。儿童的公开形象还涉及其隐私与未来数字身份。\\n\\n## 为什么看起来很有说服力\\n\\n父母分享可以获得社会支持和认同，同时也会形成比较环境。研究讨论了父母分享的动机、亲子偏好差异，以及社会比较与育儿自我效能之间的关系。\\n\\n**观看时需要区分：**\\n\\n- 漂亮的亲子片段不能代表每天的家庭氛围\\n- 孩子的发展受多种因素影响，不是父母能力排行榜\\n- 父母分享权与儿童隐私、同意之间可能存在张力\\n\\n## 需要注意\\n\\n本条不评价具体家庭的养育水平，只分析公开育儿内容为何容易形成“完美父母”印象。', '看到别人每天做辅食、阅读和高质量陪伴后，觉得自己不是合格父母或未来一定做不好时。', '参考：Moser等，2017，父母与儿童对亲子内容分享的偏好；Bayraktar等，2024，父母社交比较与育儿效能。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (128, 2, '知识专家与“什么都懂”人设', '## 这种人设是什么\\n\\n知识专家人设通过稳定输出观点、概念和解决方案，建立专业、理性和判断可靠的形象。真正的专业传播很有价值，但平台内容常把复杂知识压缩成简洁结论，使“表达确定”容易被当成“证据充分”。\\n\\n## 它通常展示什么\\n\\n常见展示包括术语解释、热点点评、方法总结、书单和明确立场。账号会持续聚焦特定主题，通过统一语言风格和高频回应建立专业身份。\\n\\n## 它容易省略什么\\n\\n知识边界、争议、失败预测、团队协作、资料检索过程和无法回答的问题较少被展示。账号在一个领域有经验，也不自动具备相邻领域的专业资格。\\n\\n## 为什么看起来很有说服力\\n\\n社交媒体的可见性奖励清晰、快速和可传播的结论；个人品牌又要求持续维持一致角色。粉丝数量、镜头自信和内容质量可能相关，但不能替代资质与证据核验。\\n\\n**观看时需要区分：**\\n\\n- 善于表达与专业能力有关，但二者并不完全相同\\n- 经验分享、科普和个体诊疗建议具有不同责任边界\\n- 一个观点受欢迎，不等于它已获得学术共识\\n\\n## 需要注意\\n\\n涉及医疗、法律、金融等高风险内容时，需单独核对身份、证据和利益关系。', '因为某位博主表达非常确定、粉丝很多，就准备把其跨领域观点全部当成专业结论时。', '参考：Khamis等，2017，自我品牌与微名人；van Dijck，2013，平台化身份与专业自我推广。', 1, 1, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (129, 2, '情绪稳定与“人间清醒”人设', '## 这种人设是什么\\n\\n这类人设以理性、边界清楚和不受情绪左右为核心，常通过简洁判断、关系观点和冲突复盘，呈现“我看透了并且能控制自己”的状态。它可能来自真实经验，也可能是特定表达风格。\\n\\n## 它通常展示什么\\n\\n内容通常展示已经整理好的结论、明确的原则和冷静的回应，很少保留犹豫、反复、情绪爆发和需要他人安慰的过程。\\n\\n## 它容易省略什么\\n\\n形成清晰判断前的混乱、关系依赖、现实妥协和观点改变不容易被看见。短内容为了传播也会省略情境，使复杂关系看起来只需要一句原则就能解决。\\n\\n## 为什么看起来很有说服力\\n\\n确定的语言能降低不确定感，容易被理解为成熟与权威。持续发布相似判断后，账号会形成稳定角色，观看者可能把表达克制等同于内心从不波动。\\n\\n**观看时需要区分：**\\n\\n- 情绪稳定不是没有情绪，而是能够识别和调节情绪\\n- 明确边界需要结合关系、责任和现实条件\\n- 一句话原则适合传播，但未必适合所有具体处境\\n\\n## 需要注意\\n\\n不要把自己需要安慰、犹豫或改变主意理解为“不够清醒”。', '看到大量果断关系观点后，因自己仍然难过、依赖或犹豫而感到羞耻时。', '参考：Bailey等，2020，真实自我表达与幸福感；Hjetland等，2022，社交媒体自我呈现差异。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (130, 2, '极简主义与高级品位人设', '## 这种人设是什么\\n\\n极简主义人设通过物品少、空间整洁和选择克制，传递自我掌控、审美成熟和不被消费支配的形象。它可能源于真实价值观，但极简本身也能成为需要购买和维护的消费风格。\\n\\n## 它通常展示什么\\n\\n常见内容包括留白空间、统一色调、少量高品质物品、整理前后对比和“只留下真正需要的东西”的叙事。\\n\\n## 它容易省略什么\\n\\n储物空间、清洁劳动、替换成本、被移出镜头的物品和家庭成员差异不容易出现。高价格的“少而精”也可能依赖较强购买力。\\n\\n## 为什么看起来很有说服力\\n\\n整洁画面提供强烈秩序感，少量物品又容易被解释为自律和品位。与直接展示奢侈品相比，克制消费能够用更隐蔽的方式传递资源和审美资本。\\n\\n**观看时需要区分：**\\n\\n- 物品少可能来自价值选择，也可能来自内容构图需求\\n- 极简空间不等于生活负担一定更少\\n- 整洁、昂贵和心理健康之间没有简单对应关系\\n\\n## 需要注意\\n\\n不要把个人物品数量变成道德等级，也不要把极简账号理解为普遍适用的生活标准。', '看到极简空间后，觉得自己的正常生活用品和杂乱痕迹说明人格不够高级时。', '参考：Lu等，2024，自我呈现、社会比较与消费倾向；Duffy与Hund，2015，生活方式自我品牌。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (131, 2, '高社交能量与“朋友很多”人设', '## 这种人设是什么\\n\\n高社交能量人设通过聚会、合照、群体互动和频繁邀约，呈现受欢迎、连接广泛且生活充实的形象。它可能真实反映外向生活，也可能只是公开内容天然偏好多人场景。\\n\\n## 它通常展示什么\\n\\n常见展示包括生日、旅行、演出、团建和朋友间的公开互动。多人画面和评论区熟人交流会为社会地位提供直观线索。\\n\\n## 它容易省略什么\\n\\n独处、关系摩擦、浅层连接、活动后的疲惫和未被记录的小范围关系很少出现。合照人数也不能说明关系深度、稳定性或一个人是否感到孤独。\\n\\n## 为什么看起来很有说服力\\n\\n社交活动具有强可见性，一张照片可以同时展示地点、人数与他人认可。观看者容易用公开互动数量推断人格魅力和归属程度。\\n\\n**观看时需要区分：**\\n\\n- 朋友数量、公开互动和关系质量是不同指标\\n- 外向与内向是倾向，不是高低等级\\n- 经常独处的人也可能拥有稳定而深厚的关系\\n\\n## 需要注意\\n\\n不应因为某个账号热闹就认定对方从不孤独，也不应把自己的安静生活视为社交失败。', '刷到密集聚会和合照后，开始用活动数量判断自己是否被喜欢、是否拥有正常生活时。', '参考：Chou与Edge，2012，他人生活感知；Nesi等，2018，社交媒体如何改变同伴经验。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (132, 2, '真实反精致与“翻车”亲近人设', '## 这种人设是什么\\n\\n反精致人设主动展示失误、狼狈、杂乱或未经修饰的片段，以区别于传统完美账号。它可能扩大真实表达空间，也可能逐渐形成另一种稳定风格：必须显得自然、敢自嘲、没有距离感。\\n\\n## 它通常展示什么\\n\\n常见内容包括失败花絮、素颜、房间杂乱、自我吐槽和对商业合作的透明说明。适度脆弱能降低受众距离，增强“这个人和我一样”的感受。\\n\\n## 它容易省略什么\\n\\n被公开的失败仍然是经过选择的失败。真正涉及隐私、声誉或商业风险的部分可能不会出现；有些“翻车”内容也可能经过事后整理和安全评估。\\n\\n## 为什么看起来很有说服力\\n\\n研究指出，真实性是网红重要的社会资本，创作者会通过热情一致、透明披露和选择性自我揭示来维护可信度。展示缺点并不必然虚假，但也不是未经筛选的完整自我。\\n\\n**观看时需要区分：**\\n\\n- 展示不完美可以是真诚表达，也可以同时具有品牌功能\\n- 看起来随意的内容仍可能经过受众和风险判断\\n- 真实不是“什么都公开”，保留隐私同样合理\\n\\n## 需要注意\\n\\n不要陷入“精致一定假、狼狈一定真”的二分法。', '因为某位博主经常自嘲和展示失败，就认为其所有内容都不可能经过策划时。', '参考：Audrezet等，2020，网红真实性策略；Zimmermann等，2025，网红自我呈现与真实性。', 1, 1, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (133, 2, '谦虚炫耀与低调成功人设', '## 这种人设是什么\\n\\n谦虚炫耀是把成就信息放进抱怨、惊讶或自我贬低中，例如“又被迫升职了”“只是随便准备却拿了第一”。它试图同时获得能力认可和谦逊印象，是一种具体的自我呈现方式。\\n\\n## 它通常展示什么\\n\\n内容通常包含可识别的成就，但语气淡化主动展示意图。成功被描述成偶然、麻烦或意料之外，使发布者看起来既优秀又不自负。\\n\\n## 它容易省略什么\\n\\n实际投入、对认可的期待以及选择发布这条信息的动机不会直接说明。并非所有轻描淡写都是操控，有时也来自文化中的谦逊规范或不知道如何表达成就。\\n\\n## 为什么看起来很有说服力\\n\\n研究将谦虚炫耀定义为由抱怨或谦逊包装的炫耀，并发现它常因被感知为不真诚而适得其反。不过现实语境、关系和表达习惯都会影响判断。\\n\\n**观看时需要区分：**\\n\\n- 先看事实信息，再判断语气，不必自动推断恶意\\n- 公开成就是正常需求，直接表达未必比包装表达更自恋\\n- 文化中的客套和实验研究中的谦虚炫耀不能完全等同\\n\\n## 需要注意\\n\\n本条用于识别表达结构，而不是给某个发布者贴上虚伪标签。', '看到“随便做做就成功”“优秀也是一种烦恼”之类内容，既羡慕又觉得不舒服时。', '参考：Sezer、Gino与Norton，2018，谦虚炫耀作为低效自我呈现策略。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (134, 2, '美妆时尚与风格权威人设', '## 这种人设是什么\\n\\n美妆时尚人设通过稳定审美、产品选择和身体呈现，建立“知道什么适合、什么值得买”的风格权威。它既是创意表达，也常与商业推荐和个人品牌紧密结合。\\n\\n## 它通常展示什么\\n\\n常见内容包括妆容、穿搭、趋势判断、单品测评和前后变化。连续风格和对细节的熟练描述，会让个人偏好看起来像普遍审美规则。\\n\\n## 它容易省略什么\\n\\n试错成本、退货、品牌合作、团队妆造、身体差异和不适用人群通常无法在每条内容中完整呈现。一个效果在镜头中好看，也不等于在所有光线和生活场景中相同。\\n\\n## 为什么看起来很有说服力\\n\\n网红依靠专业感、亲近感和真实性积累影响力。商业合作进入后，创作者需要同时维护个人品位和受众信任，这两种目标有时会产生张力。\\n\\n**观看时需要区分：**\\n\\n- 风格建议具有主观性，不能等同于医学或身体价值判断\\n- 广告披露、产品来源和专业资格应分别核对\\n- 适合创作者的妆容与服装可能依赖其面部、体型和工作场景\\n\\n## 需要注意\\n\\n不必把流行风格当作修正自身缺陷的强制标准。', '因某位博主风格统一、表达专业，就认为其推荐一定客观且每件单品都适合自己时。', '参考：Zimmermann等，2025，美妆时尚健身网红的自我呈现；Audrezet等，2020，真实性与商业合作。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (135, 2, '健康饮食与全方位养生人设', '## 这种人设是什么\\n\\n健康养生人设通过饮食、运动、睡眠和自我照护建立“身体管理有方法”的形象。内容可能促进健康意识，但个人经验、一般健康信息与专业医疗建议之间的边界容易模糊。\\n\\n## 它通常展示什么\\n\\n常见展示包括干净食材、固定补充剂、晨间流程、体检指标、情绪管理和看似完整的健康系统。结果通常以精神状态、外形和日常效率表现。\\n\\n## 它容易省略什么\\n\\n慢性疾病、医学治疗、基因差异、失败尝试、检测误差和商业利益可能不会在短内容中充分说明。健康结果也很难只归因于某一种食物或习惯。\\n\\n## 为什么看起来很有说服力\\n\\n生活化镜头和持续实践能让建议显得比抽象医学信息更亲近。拟社会信任、个人故事和可见外形会增强说服力，但它们不能替代证据和专业资格。\\n\\n**观看时需要区分：**\\n\\n- 个人有效不等于对所有人有效\\n- 健康生活方式与疾病治疗建议具有不同证据要求\\n- 外貌、精力和账号活跃度不能证明完整健康状况\\n\\n## 需要注意\\n\\n遇到限制饮食、停药、替代治疗或补充剂建议时，应单独核验专业来源。', '看到博主状态很好、生活规律，就准备把其个人饮食和补充剂方案当成普遍医疗建议时。', '参考：Kaňková等，2025，健康类网红传播范围综述；Pilgrim与Bohnet-Joschko，2019，Instagram健康传播。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (136, 3, '高光切片：为什么信息流像一场人生精选展', '## 这个套路是什么\\n\\n社交媒体中的生活展示通常不是按时间连续记录，而是从大量普通、重复和不适合公开的片段中，挑出更漂亮、更顺利、更值得被看见的一小部分。单条内容可能完全真实，但连续观看许多人的高光切片，容易形成“别人一直过得很好”的整体印象。\\n\\n## 它如何制造印象\\n\\n平台鼓励用户发布具有信息价值、审美价值或社交价值的内容。完成目标、旅行、聚会、礼物和好状态更容易被记录，等待、返工、失败、争吵和无聊时段则较少进入信息流。观看者却常用自己的完整日常，与别人经过筛选的公开片段比较。\\n\\n## 容易忽略什么\\n\\n选择性展示不自动等于造假。人们面对不同受众，本来就会决定公开什么、保留什么。问题在于信息流把大量账号的精选内容汇聚到一起，使这种选择不再显眼。\\n\\n**识别重点：**\\n\\n- 一张真实照片不等于对方生活的平均状态\\n- 多个账号的高光不能拼成“普通人的标准生活”\\n- 没有出现的部分，不能被推断为不存在\\n\\n## 需要注意\\n\\n本条解释的是信息结构，不用于判断某位发布者是否诚实。观察一个账号时，应区分“内容是否真实”与“内容是否完整”这两个问题。', '连续刷到他人的旅行、成就和聚会后，开始觉得身边所有人都比自己顺利时。', '参考：Schwämmlein与Wodzicki，2012，网络社群中的自我呈现；Fox与Vendemia，2016，照片选择性呈现研究。', 1, 1, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (137, 3, '角度、光线与构图：真实画面也能改变生活质感', '## 这个套路是什么\\n\\n照片和视频不必经过明显修图，也能通过拍摄角度、焦距、光线、背景和取景范围改变观看者对人物与环境的判断。画面记录的是真实场景，但它只保留了镜头选择的那一部分现实。\\n\\n## 它如何制造印象\\n\\n低机位可能拉长身体比例，近距离广角可能夸张面部或空间，柔和侧光能够弱化皮肤纹理，狭窄取景可以避开杂乱区域。整洁桌面、酒店一角或餐厅局部经过构图后，会显得比完整空间更统一、更高级。连续使用相似视觉语言，还会形成稳定的个人审美印象。\\n\\n## 容易忽略什么\\n\\n摄影本身就是选择。取景并不说明画面外一定很糟，也不能说明发布者在欺骗；但观看者若把构图效果当作未经选择的肉眼现实，就容易高估这种生活状态的普遍程度。\\n\\n**识别重点：**\\n\\n- 看见画面时，也要意识到镜头外仍有大量信息\\n- “原相机”不等于没有角度、光线和取景影响\\n- 视觉质感往往包含拍摄经验、设备与后期劳动\\n\\n## 需要注意\\n\\n本条不要求否定摄影审美，而是区分“画面好看”与“现实始终如此”。同样的场景，在不同镜头选择下可能呈现完全不同的气氛。', '看到看似随手拍的房间、身材或餐食后，觉得自己的现实环境明显更差时。', '参考：Fox与Vendemia，2016，社交照片中的选择性自我呈现；Schwämmlein与Wodzicki，2012。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (138, 3, '美颜滤镜与局部编辑如何重写外貌参照', '## 这个套路是什么\\n\\n美颜滤镜和照片编辑可以调整肤色、轮廓、比例、光影与局部细节。许多处理非常轻微，单看一张图并不容易察觉，但长期接触统一的精致面孔和身体比例，会改变观看者对“普通外貌”的参照。\\n\\n## 它如何制造印象\\n\\n编辑工具把原本需要化妆、灯光、姿势和后期共同完成的效果，变成即时、稳定且可重复的界面功能。平台中的热门模板又让不同人的面部逐渐接近相似审美。观看者看见的是经过筛选和加工后的结果，却可能把它当成自然、常见甚至无需成本的状态。\\n\\n## 容易忽略什么\\n\\n不是每张好看的照片都经过重度修改，也不能仅凭外观断定具体编辑程度。更重要的是，照片编辑、拍摄角度、妆容和内容选择常常共同作用，单靠肉眼很难准确拆分。\\n\\n**识别重点：**\\n\\n- 滤镜效果可能很轻，不一定出现明显变形\\n- 高频接触会让加工后的外貌看起来更普通、更普遍\\n- 图片适合表达与创作，不适合充当真实人口外貌统计\\n\\n## 需要注意\\n\\n研究发现，照片编辑投入与身体不满意、自我客体化和外貌比较存在关联，但不能据此判断每个使用滤镜的人都会受到同样影响。', '刷到大量肤质、脸型和身材都高度一致的照片后，开始把这种效果当成自然外貌标准时。', '参考：McLean等，2015，自拍编辑与身体不满意；Ozimek等，2023，照片编辑、自我客体化与外貌比较。', 1, 1, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (139, 3, '“前后对比”如何把复杂变化压缩成单一答案', '## 这个套路是什么\\n\\n“使用前—使用后”“改变前—改变后”是一种高效的视觉叙事。它把复杂、漫长且受多种因素影响的变化，压缩成两个画面之间的明显差异，并暗示中间的产品、方法或决定是主要原因。\\n\\n## 它如何制造印象\\n\\n前后图常使用不同光线、姿势、表情、服装、镜头距离和拍摄时间。即使变化真实，结果也可能同时受到作息、饮食、医疗、经济条件、团队协助和自然波动影响。两张图并排出现时，观看者会本能地寻找一个简单因果，并忽略未展示的过程。\\n\\n## 容易忽略什么\\n\\n前后对比不是天然虚假，它可以帮助展示真实进展；问题在于它往往省略失败案例、维持成本、反复过程和其他变量。单个成功案例也不能证明所有人使用同样方法都会得到相同结果。\\n\\n**识别重点：**\\n\\n- 比较两张图的光线、姿势、时间和拍摄条件是否一致\\n- 区分“发生在使用之后”与“由它造成”\\n- 关注过程、样本数量和未成功者是否被呈现\\n\\n## 需要注意\\n\\n本条适用于健身、护肤、学习、理财和生活改造等多种内容。具体效果仍应结合更完整证据判断。', '看到明显的改变前后图，立即觉得某个产品或方法已经被“证明有效”时。', '参考：FTC《Endorsement Guides》及社交媒体代言披露指南；Fardouly与Holland，2018，理想化图像标签研究。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (140, 3, '“我的一天”视频如何压缩时间与删去空白', '## 这个套路是什么\\n\\n“我的一天”“沉浸式跟拍”看似连续记录生活，实际通常由多个短片段剪接而成。数小时的等待、移动、准备、走神和重复劳动，会被压缩为几分钟内不断发生的有效行动。\\n\\n## 它如何制造印象\\n\\n视频只保留起床、运动、工作、学习、做饭和社交等容易辨认的节点，并用时间字幕和转场建立连续感。空白时间被删去后，一天显得格外充实；失败镜头和无结果的尝试不进入成片，也使行动看起来更加顺畅。\\n\\n## 它容易忽略什么\\n\\n视频中的活动可以都真实发生过，但不能据此推断发布者全天保持同样效率。拍摄、布景、补录和剪辑本身也可能是工作的一部分，不等于普通人在现有条件下可以无成本复制。\\n\\n**识别重点：**\\n\\n- 成片时长与真实时间跨度不是一回事\\n- 连续剪辑会隐藏等待、恢复和无效时段\\n- “记录一天”仍然是经过主题选择的叙事作品\\n\\n## 需要注意\\n\\n本条不否定生活记录的参考价值。观看时把它当作经过编辑的样本，而不是完整时间审计，更不容易把自己的普通节奏判断为失败。', '看完几分钟的高效日常视频后，觉得自己一天没有完成同样多事情就是浪费时间时。', '参考：Georgakopoulou与Nunes，2022，社交媒体小故事与真实性指令；Schwämmlein与Wodzicki，2012。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (141, 3, '跳切、配乐与字幕如何预先安排你的情绪', '## 这个套路是什么\\n\\n短视频中的跳切、音乐、音效、字幕和节奏，不只负责让内容好看，也会提前告诉观看者“这一段应该紧张、感动、愤怒还是爽快”。同一段素材采用不同剪辑方式，可能产生完全不同的意义。\\n\\n## 它如何制造印象\\n\\n快速跳切减少思考空隙，强烈音乐提高情绪唤醒，放大的关键词把注意力锁定在创作者希望强调的解释上。反应镜头、停顿和重复播放又能突出冲突或尴尬，使偶发事件看起来更戏剧化、更具有代表性。\\n\\n## 它容易忽略什么\\n\\n情绪反应并不等于事实判断。视频让人感到震撼，不能自动证明其观点正确；让人感到温暖，也不能证明商业主张可靠。被删去的前因后果、完整对话和时间顺序可能改变事件含义。\\n\\n**识别重点：**\\n\\n- 尝试区分素材本身与音乐、字幕带来的解释\\n- 关注是否存在断章取义、顺序重排或关键上下文缺失\\n- 情绪越强烈，越需要暂停判断内容证据\\n\\n## 需要注意\\n\\n剪辑是正常创作工具，并非只有恶意内容才会使用。套路拆解的重点是识别形式如何影响理解，而不是要求所有视频保持无剪辑状态。', '一段短视频让自己立刻愤怒、感动或恐慌，却还没弄清完整事件经过时。', '参考：Chiossi等，2023，短视频切换与意图记忆；Molina等，2021，点击诱导内容研究。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (142, 3, '结果先行的成功故事与幸存者偏差', '## 这个套路是什么\\n\\n成功故事常从一个已经获得结果的人开始，再回头整理出一条连贯的成长路线。由于失败者、退出者和普通结果较少公开，观看者容易把少数成功路径误认为常见结局。\\n\\n## 它如何制造印象\\n\\n内容通常突出关键决定、个人品质和几个转折点，使成功看起来可以被清晰解释和复制。运气、行业周期、家庭支持、人脉、试错成本与未成功项目较少被纳入。平台也更愿意传播结果显著、叙事完整的故事，因为它们更容易吸引注意。\\n\\n## 它容易忽略什么\\n\\n从成功者倒推原因，无法判断采用同样方法但没有成功的人有多少。一个人真诚分享经验，也不意味着经验对不同资源、时间和风险承受能力的人具有同样效果。\\n\\n**识别重点：**\\n\\n- 问一问未成功者和中途退出者是否可见\\n- 区分“成功者常做什么”与“做了就更可能成功”\\n- 关注背景条件、基准概率和失败成本\\n\\n## 需要注意\\n\\n成功案例可以提供思路和可能性，但不能替代整体数据。尤其在创业、投资、升学和减重内容中，应避免仅凭个案推断普遍结果。', '刷到逆袭、创业或快速上岸故事后，觉得只要照做就应当得到同样结果时。', '参考：Salganik等，2006，社会影响与文化市场结果的不平等和不可预测性；FTC代言指南。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (143, 3, '个人经验如何被包装成“人人适用”的规律', '## 这个套路是什么\\n\\n社交媒体常把“我这样做后感觉有效”转化成“这种方法就是有效”。第一人称经历具有具体细节和情感力量，比抽象统计更容易被记住，因此个人体验经常被当作普遍规律传播。\\n\\n## 它如何制造印象\\n\\n创作者会用清晰步骤、确定语气和自身结果建立可信度。观看者又容易把相似身份、相似困扰理解为相同条件，从而忽略年龄、健康、资源、环境和同期变化。评论区中的“我也有效”会进一步形成一致性印象。\\n\\n## 它容易忽略什么\\n\\n个人体验可以真实，但无法排除自然变化、其他措施、期待效应和选择性记忆。没有对照组、样本规模和失败反馈时，很难知道结果是否稳定或适用于其他人。\\n\\n**识别重点：**\\n\\n- 留意“对我有效”是否悄悄变成“对所有人有效”\\n- 查看内容是否说明适用条件、限制和不确定性\\n- 健康、财务等高风险建议需要更高等级证据\\n\\n## 需要注意\\n\\n本条不是要求普通分享都写成论文，而是提醒观看者把个人经验放回它应有的位置：它能提供线索和体验，不能单独完成普遍性证明。', '看到创作者用自己的经历断言某种学习、护肤、减肥或赚钱方法适合所有人时。', '参考：FTC《Endorsement Guides》；Mathur等，2018，社交媒体联盟营销披露研究。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (144, 3, '精选见证与好评截图如何代替整体效果', '## 这个套路是什么\\n\\n品牌、课程和博主常展示用户感谢信、聊天截图、成功反馈和高分评论。这些材料可能来自真实用户，但通常是从大量反馈中挑选出来的，不等于所有用户的总体体验。\\n\\n## 它如何制造印象\\n\\n具体人物、前后变化和情绪化语言，会让效果显得可触摸、可信。多张好评连续出现时，观看者容易把数量感理解为成功率；而未改善、退款、沉默和负面反馈可能没有同等展示机会。\\n\\n## 它容易忽略什么\\n\\n精选见证无法说明样本基数，也不一定能代表典型结果。截图还可能缺少时间、完整对话和利益关系信息。即使每条见证都真实，也需要知道它们占全部用户的比例。\\n\\n**识别重点：**\\n\\n- 询问“这些成功案例来自多少总用户”\\n- 区分用户满意度、短期感受与可验证效果\\n- 留意见证者是否获得赠品、佣金或其他激励\\n\\n## 需要注意\\n\\n见证可以帮助理解使用体验，但不应替代系统数据和风险说明。涉及医疗、投资和重大消费时，更不能只依据精选好评作决定。', '看到连续的感谢信和成功案例后，感觉产品几乎人人有效，却不知道总样本和失败情况时。', '参考：FTC《Endorsement Guides》与《Disclosures 101 for Social Media Influencers》。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (145, 3, '标题党与“信息缺口”如何驱动点击', '## 这个套路是什么\\n\\n标题党通过省略关键信息、制造意外、冲突或强烈承诺，让观看者产生“必须点开才知道答案”的信息缺口。常见表达包括“最后一点没人告诉你”“事情彻底反转”“千万别再这样做”。\\n\\n## 它如何制造印象\\n\\n标题先提供足够的情绪和悬念，却延迟给出核心事实。观看者为了消除不确定性进入内容，平台便记录一次点击或停留。部分标题还会把有限差异写成重大突破，使内容在进入前显得比实际更重要。\\n\\n## 它容易忽略什么\\n\\n点击量说明标题成功吸引注意，不说明内容准确、有用或获得认可。研究发现，不同类型的点击诱导表达效果并不一致，一些明显套路甚至可能降低信任。\\n\\n**识别重点：**\\n\\n- 标题是否给出可核验主张，还是只制造情绪\\n- 内容是否真正回答了标题提出的问题\\n- 留意“绝对、唯一、彻底、所有人”等过度概括词\\n\\n## 需要注意\\n\\n有吸引力的标题不必然是欺骗。判断重点在于标题是否严重夸大正文、隐去关键限制，或故意让观看者形成错误预期。', '被“真相惊人”“最后一次提醒”等标题吸引，点开后发现信息非常普通时。', '参考：Molina等，2021，三项点击诱导实验；Mukherjee等，2022，点击诱导与传播表现研究。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (146, 3, '夸张封面与“首秒钩子”如何放大冲突', '## 这个套路是什么\\n\\n短视频和图文通常在封面、标题或开头几秒争夺注意力。“首秒钩子”会先展示最强冲突、最极端结果或最具视觉刺激的画面，再在后续补充背景。\\n\\n## 它如何制造印象\\n\\n推荐系统会依据观看、跳过和互动等信号调整分发，创作者因此有动力把关键刺激提前。惊讶表情、巨大文字、危险画面和对立句式能够减少立即划走，但也可能让事件严重程度在进入内容前就被放大。\\n\\n## 它容易忽略什么\\n\\n开头承担的是吸引任务，不一定代表内容的平均情绪。极端画面可能只占完整事件的一小段，封面也可能使用补拍、拼接或与结论关系较弱的素材。\\n\\n**识别重点：**\\n\\n- 不要只凭封面和开场判断完整事件\\n- 查看后文是否补充证据、限制与反例\\n- 注意冲突是否被人为提前或循环播放\\n\\n## 需要注意\\n\\n首秒钩子是平台环境下常见的表达策略，不必然意味着虚假。但当钩子与正文差异过大，就可能构成误导或制造不必要的情绪压力。\\n\\n封面只是进入内容的入口，不应被当作完整结论。', '刷到强烈冲突画面或极端字幕后，尚未看完整内容就已经形成确定判断时。', '参考：TikTok官方《5 tips for TikTok creators》；Molina等，2021，点击诱导实验。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (147, 3, '高唤醒内容为何更容易占据推荐流', '## 这个套路是什么\\n\\n愤怒、恐惧、惊讶和道德冲突等高唤醒情绪，往往更容易引发评论、转发和停留。平台未必主动判断某种立场更正确，但以互动为目标的排序可能让更能激起反应的内容获得额外可见性。\\n\\n## 它如何制造印象\\n\\n当情绪强烈的内容得到更多互动，排序系统会把这些反应当作相关性或兴趣信号。结果是温和、复杂和不确定的观点较难与简单、冲突性的内容竞争。用户连续看见极端样本后，可能误以为现实中的多数人也同样激烈。\\n\\n## 它容易忽略什么\\n\\n互动不等于赞同。人们可能因为愤怒、反驳或担忧而点击和评论。平台目标、具体算法和用户行为也会变化，不能把所有极化都归因于单一推荐机制。\\n\\n**识别重点：**\\n\\n- 区分“引发反应”与“获得认可”\\n- 高评论量可能代表争议，而不是共识\\n- 看到极端观点时，关注样本来源和线下代表性\\n\\n## 需要注意\\n\\n近期研究显示，以参与度排序可能放大更具分裂性的内容，但效果取决于具体平台和排序目标。应避免把算法描述成有意制造所有冲突的单一主体。', '推荐流连续出现愤怒、冲突和群体对立内容，让自己觉得社会整体充满敌意时。', '参考：Milli等，2025，参与度、满意度与分裂性内容放大研究。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (148, 3, '点赞、播放量与粉丝数如何形成社会证明', '## 这个套路是什么\\n\\n点赞、播放量、转发和粉丝数把他人的注意与反应转换成公开数字。观看者常把高数字理解为“很多人已经验证过”，从而更愿意停留、点击或相信内容。\\n\\n## 它如何制造印象\\n\\n数字提供了快速判断线索，尤其在信息过多、缺乏时间核实时更有影响。先获得的互动还可能带来更多曝光，形成可见性与互动互相强化的循环。创作者也会用“全网都在看”“已有十万人收藏”突出这种社会证明。\\n\\n## 它容易忽略什么\\n\\n高互动可能来自争议、娱乐性、付费推广、既有粉丝规模或发布时间，不等于内容质量和事实准确性。实验研究还表明，更多点赞并不在所有场景都必然带来更多点击，社会证明的效果会受到来源和情境影响。\\n\\n**识别重点：**\\n\\n- 先判断主张和证据，再把互动量当辅助信息\\n- 区分粉丝规模、传播能力与专业资质\\n- 高播放量可以证明被看见，不能证明被证实\\n\\n## 需要注意\\n\\n互动指标并非毫无价值，它能反映传播和受众反应；问题在于把传播表现直接替换成真实性、专业性或普遍效果。', '看到高赞、高收藏和大量粉丝后，在未检查内容来源前就默认其更专业、更真实时。', '参考：Huang与Lin，2025，点赞数量与广告点击现场实验；Salganik等，2006，社会影响实验。', 1, 1, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (149, 3, '热门榜单与排序位置如何制造“大家都在关注”', '## 这个套路是什么\\n\\n热搜、热门榜单和推荐列表把内容排成先后顺序。排名不仅反映已有关注，也会决定后续谁更容易被看见，因此榜单可能同时是结果和新的原因。\\n\\n## 它如何制造印象\\n\\n靠前位置获得更大屏幕面积、更少操作成本和更高进入概率。更多人点击后，系统又可能得到新的热度信号，形成反馈循环。用户看到榜单时，容易把“排得靠前”理解为社会中最重要、最普遍或最值得担忧的问题。\\n\\n## 它容易忽略什么\\n\\n榜单通常依据平台内部数据和规则，不等于公共议题的客观重要性。不同平台的用户结构、统计窗口、商业推广和内容审核都会影响排名。近期排序实验也提示，即使内容完全相同，位置变化本身也会显著影响互动。\\n\\n**识别重点：**\\n\\n- 问清榜单依据的是搜索、点击、讨论还是编辑选择\\n- 排名反映平台内可见性，不自动代表现实发生概率\\n- 同一事件在不同平台的热度可能完全不同\\n\\n## 需要注意\\n\\n榜单适合帮助用户发现内容，但不应成为判断社会共识、风险程度或事实真实性的唯一依据。', '看到某话题长期位于热榜前列，便认为现实生活中所有人都在讨论或同样担忧时。', '参考：Chan等，2025，算法排名与注意力预印本；Ciampaglia等，2018，流行度偏差与质量。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (150, 3, '置顶、精选与删除如何塑造评论区气候', '## 这个套路是什么\\n\\n评论区并不是所有反馈的自然平均展示。发布者和平台可以置顶、精选、折叠、删除或排序评论，从而改变新观看者首先看到的意见结构。\\n\\n## 它如何制造印象\\n\\n最靠前的几条评论会为内容建立解释框架：一致赞美会制造高度共识，集中反对会制造争议感，幽默评论则可能改变原内容语气。多数用户不会完整浏览全部回复，因此前排评论具有远高于普通评论的影响。\\n\\n## 它容易忽略什么\\n\\n前排意见可能由互动排序、时间优势、发布者选择或平台治理共同决定。看不到某类评论，不代表从未有人提出；出现大量同类评论，也可能来自特定社群集中进入，而不是全部观看者的比例。\\n\\n**识别重点：**\\n\\n- 留意评论排序方式和是否标注“精选”\\n- 区分发布者自己的置顶与自然高赞\\n- 争议议题可查看不同来源，而不是只读单一评论区\\n\\n## 需要注意\\n\\n删除辱骂、骚扰和违法内容是合理治理，并非所有删评都意味着操纵。关键是不要把一个经过管理的评论区直接当作完整民意调查。', '看到评论区几乎一边倒，便认定所有用户都持同样态度时。', '参考：Meta关于虚假互动与不真实行为的政策资料；Salganik等，2006，社会影响与反馈循环。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (151, 3, '刷量、互赞群与虚假互动如何伪造热度', '## 这个套路是什么\\n\\n账号可以通过购买点赞、播放、粉丝和评论，或加入互赞互评群，人为提高互动指标。这些行为让内容看起来已经获得大量真实关注，从而影响普通用户和推荐系统的后续判断。\\n\\n## 它如何制造印象\\n\\n高数字提供社会证明，整齐的好评评论又补充了“真实用户体验”。如果虚假互动发生在发布初期，它还可能帮助内容跨过某些可见性门槛。协调账号可以同时放大特定叙事，使少数组织化行为看起来像自发群众趋势。\\n\\n## 它容易忽略什么\\n\\n不是所有增长迅速的账号都刷量，也不能仅凭评论相似就断定造假。虚假互动形式不断变化，普通用户通常无法准确估算真实比例。平台公布的打击行动只能说明此类行为存在，不能证明某个具体账号参与。\\n\\n**识别重点：**\\n\\n- 观察互动是否与账号历史、内容质量和评论细节相符\\n- 大量空泛、重复或时间高度集中的评论值得进一步核验\\n- 不要仅凭粉丝和点赞判断专业能力\\n\\n## 需要注意\\n\\n本条用于理解指标可能被操纵，不建议对具体个人作无证据指控。必要时应依赖平台标记、公开调查或可验证数据。', '看到突然爆红的账号或一边倒的重复评论，想判断热度是否代表真实受众反应时。', '参考：Jahn等，2023，社交媒体点赞中的协调不真实行为；Murero等，2023，协调不真实行为研究；Meta相关政策。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (152, 3, '推荐流不是社会全貌，而是个性化排序结果', '## 这个套路是什么\\n\\n推荐流不是随机抽取社会内容，也不是按现实发生比例排列。系统会根据用户互动、内容信息、账号关系和平台规则，为不同用户生成不同顺序的内容集合。\\n\\n## 它如何制造印象\\n\\n个性化推荐提高相关性，也让每个人看到的“世界”不同。用户若频繁接触某类议题，容易把个人信息流误认为大众信息流，进而认为某种生活方式、冲突或观点无处不在。流行内容和既有账号还可能因历史数据获得更多机会。\\n\\n## 它容易忽略什么\\n\\n平台通常公开的是推荐因素和大致原则，而不是完整实时模型。推荐结果也不只由用户兴趣决定，还可能受地域、语言、新鲜度、安全规则和内容供给影响。因此不能用一句“算法懂你”解释所有内容出现。\\n\\n**识别重点：**\\n\\n- 你的首页只是一个经过排序的样本\\n- 连续出现不等于现实中占比同样高\\n- 不同账号、设备和时间可能看到完全不同的结果\\n\\n## 需要注意\\n\\n个性化推荐本身可以帮助发现有用内容。风险主要来自把高度定制的内容环境误当作完整社会统计或普遍共识。', '首页反复出现某类生活、冲突或观点，开始认为现实世界几乎全是这样时。', '参考：TikTok官方《How TikTok recommends videos #ForYou》；YouTube官方推荐说明；Meta Instagram推荐系统说明。', 1, 1, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (153, 3, '一次停留、重播和互动如何改变后续推荐', '## 这个套路是什么\\n\\n推荐系统会从观看时长、是否看完、重播、点赞、评论、分享、关注和跳过等行为中推断内容相关性。用户即使没有明确表示喜欢，停留和反复查看也可能成为后续推荐的信号。\\n\\n## 它如何制造印象\\n\\n争议、恐惧和猎奇内容会让人停下来确认细节，系统却未必能完整区分“喜欢”“担忧”“反驳”或“只是没反应过来”。当相似内容继续出现，用户又产生更多停留，便可能形成自我强化的信息路径。\\n\\n## 它容易忽略什么\\n\\n不同平台使用的信号权重不同，而且系统会综合许多因素。一次停留不一定立刻决定整个首页，也不能把所有后续内容归因于某一个动作。平台官方说明通常描述一般信号，而非公开具体权重。\\n\\n**识别重点：**\\n\\n- 观看行为也在向系统提供反馈\\n- 愤怒观看可能仍然增加该类内容的可见机会\\n- 推荐变化通常来自一组行为，而不是单次点击\\n\\n## 需要注意\\n\\n本条解释推荐反馈，不提供具体清理或训练步骤。平台的“不感兴趣”等控制工具属于行动建议库内容。', '因为震惊或生气而反复观看一类内容，随后发现首页越来越多相似内容时。', '参考：TikTok官方推荐与创作者说明；Zannettou等，2023，TikTok推荐与用户参与研究。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (154, 3, '相似内容连续出现如何制造“到处都是”的错觉', '## 这个套路是什么\\n\\n当推荐系统聚合相似主题、审美或立场时，用户会在很短时间内接触大量同类样本。重复暴露会提高内容的熟悉度和可提取性，使它在主观上显得更普遍、更重要。\\n\\n## 它如何制造印象\\n\\n只要用户对某主题表现出兴趣，系统就可能继续寻找相似内容。热门账号和高互动作品又容易被重复推荐，导致样本并不独立。十个相似视频可能来自同一种趋势、同一批素材或互相模仿的账号，却被大脑理解成十个独立现实证据。\\n\\n## 它容易忽略什么\\n\\n信息流中的出现频率不是现实发生率。内容供给、平台用户结构和推荐策略都会改变可见比例。熟悉感也不等于真实性，一种说法被重复很多次仍可能缺少可靠依据。\\n\\n**识别重点：**\\n\\n- 检查多个内容是否引用同一事件或同一原始来源\\n- 区分平台内热度与现实总体比例\\n- 重复出现可能说明系统找到了相似内容，不说明观点已被广泛证实\\n\\n## 需要注意\\n\\n这一现象可与流行度偏差、选择性接触和可得性判断共同作用，但不能简单概括为所有用户都被困在封闭“信息茧房”。', '几小时内刷到大量相同观点或生活方式，便觉得它已经成为普遍现实或唯一选择时。', '参考：Klimashevskaia等，2024，推荐系统流行度偏差综述；Ciampaglia等，2018。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (155, 3, '无限滚动与自动播放如何消除自然停止点', '## 这个套路是什么\\n\\n无限滚动和自动播放让下一条内容无需用户再次选择就自动出现。传统阅读中的页尾、节目结束和“是否继续”按钮被减少，使用过程因此缺少清晰的自然停止点。\\n\\n## 它如何制造印象\\n\\n每次滑动都可能出现不同奖励：有时有趣、有时无聊、有时非常吸引。不可预测的内容让用户愿意再看一条，而自动衔接又降低继续使用的操作成本。短视频之间快速切换，还可能打断用户对原本任务的保持。\\n\\n## 它容易忽略什么\\n\\n长时间使用并不完全由界面设计决定，用户目的、情绪、习惯和内容质量同样重要。监管机构对“成瘾式设计”的评估也可能处于调查或初步认定阶段，不能把所有过度使用都直接归因于单一功能。\\n\\n**识别重点：**\\n\\n- 观察产品是否持续提供内容而不要求再次确认\\n- 区分“我主动选择继续”与“下一条已经自动开始”\\n- 没有页尾会削弱对时间段落的感知\\n\\n## 需要注意\\n\\n本条解释界面结构。如何设置使用时段、关闭自动播放或建立停止提示，应放入行动建议库。', '原本只想看几分钟，却在没有明显结束提示的情况下不断滑到很久以后时。', '参考：FTC，2022《Bringing Dark Patterns to Light》；欧盟委员会，2026，对TikTok成瘾式设计的初步认定；Chiossi等，2023。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (156, 3, '红点、推送与“你错过了什么”如何召回注意', '## 这个套路是什么\\n\\n红点、角标、声音、震动和“你错过了什么”式推送，会在用户离开平台后重新争夺注意。这些提示把未读内容表现为需要处理的任务，或暗示社交关系和重要信息正在发生变化。\\n\\n## 它如何制造印象\\n\\n醒目的颜色和数字让未读状态持续可见，模糊文案则保留信息缺口，使用户需要点开才能确认。通知打断当前活动后，即使查看时间很短，也可能带来重新集中注意的额外成本。\\n\\n## 它容易忽略什么\\n\\n通知并非都为了操纵用户，安全提醒、工作消息和真实社交联系也依赖它们。影响取决于通知频率、内容重要性、个人任务和是否能够自主设置。研究通常发现干扰和压力风险，而不是说明每条推送都有相同效果。\\n\\n**识别重点：**\\n\\n- 区分有具体信息的通知与只制造悬念的召回文案\\n- 角标数量不等于事件紧急程度\\n- 推送设计可能利用FOMO和未完成感\\n\\n## 需要注意\\n\\n本条只解释提示设计。通知管理、免打扰设置等具体做法属于行动建议库。\\n\\n同一提示对不同任务和用户造成的干扰程度并不相同。', '看到未读数字或模糊推送后立刻中断学习工作，担心错过重要社交信息时。', '参考：Ohly等，2023，通信通知中断、压力与绩效；Dekker等，2025，关闭通知干预研究；FTC暗黑模式报告。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (157, 3, '软广如何伪装成自然生活分享', '## 这个套路是什么\\n\\n软广把品牌推广嵌入日常记录、经验分享、开箱、教程或情绪故事中，使商业信息看起来像普通内容。产品不一定被直接夸奖，也可能只是自然出现在“真实生活”里。\\n\\n## 它如何制造印象\\n\\n观看者与创作者形成熟悉感后，更容易把推荐理解为朋友式建议。广告如果沿用账号原有语气、场景和审美，商业边界会进一步模糊。品牌还可能要求创作者围绕个人困扰和改善过程构建故事，让产品成为叙事转折点。\\n\\n## 它容易忽略什么\\n\\n商业合作不等于推荐一定虚假，创作者也可能真实使用并认可产品。关键是观看者是否能够清楚识别利益关系，从而用适当标准评估内容。即使没有现金付款，赠品、免费旅行和佣金也可能构成需要披露的关系。\\n\\n**识别重点：**\\n\\n- 留意品牌是否在关键镜头、字幕和链接中反复出现\\n- 查看是否标注广告、赞助、赠品或合作\\n- 区分产品体验与无法验证的普遍效果承诺\\n\\n## 需要注意\\n\\n不同地区的披露规则不完全相同。本条不进行法律判断，只提醒商业关系可能影响内容选择和表达方式。', '一段看似普通的生活记录突然自然带出产品，却不确定创作者是否存在商业关系时。', '参考：Evans等，2017，Instagram网红广告披露；Mathur等，2018，YouTube与Pinterest联盟营销披露；FTC指南。', 1, 1, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (158, 3, '模糊广告标识为何让人意识不到自己在看广告', '## 这个套路是什么\\n\\n广告披露如果使用不显眼位置、含糊缩写或容易被忽略的词语，观看者可能在接收推荐后才意识到内容具有商业性质。常见问题不是完全没有文字，而是文字不够清楚、及时和容易理解。\\n\\n## 它如何制造印象\\n\\n“合作”“感谢品牌”“ambassador”等表达可能被理解为普通关系说明，而不是付费推广。披露放在长文末尾、折叠区域或大量标签中，也会降低识别率。用户没有意识到广告身份时，通常更容易按普通经验分享来评估可信度。\\n\\n## 它容易忽略什么\\n\\n不同用户对同一标识的理解不同，平台功能和法规也会更新。不能因为使用了某个缩写就直接判定违规，但清晰的“广告/赞助”通常比模糊表达更容易被识别。\\n\\n**识别重点：**\\n\\n- 披露是否在进入内容时就能看到\\n- 用词是否能让普通用户直接理解存在利益关系\\n- 是否被大量标签、折叠文字或快速画面掩盖\\n\\n## 需要注意\\n\\n研究主要关注广告识别、态度和行为意向，不能简单推断所有披露都会降低购买，或所有未识别广告都会造成同样影响。', '看到“合作伙伴”“品牌挚友”等模糊文字，不确定这究竟是普通分享还是付费推广时。', '参考：Evans等，2017，披露语言与广告识别；FTC《Disclosures 101》。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (159, 3, '优惠码与联盟链接如何改变推荐动机', '## 这个套路是什么\\n\\n联盟营销允许创作者通过专属链接、优惠码或成交追踪获得佣金。内容既可能帮助用户发现产品，也意味着推荐者的收益与点击或购买数量直接相关。\\n\\n## 它如何制造印象\\n\\n优惠码会把商业转化包装成“帮粉丝省钱”，专属链接则使购买过程非常顺畅。创作者可能优先介绍佣金更高、活动期更紧迫或更容易成交的商品，而观看者若不知道收益关系，容易把推荐顺序理解为纯粹的个人偏好排序。\\n\\n## 它容易忽略什么\\n\\n有佣金不代表产品不好或评价不真实，但它构成评估推荐时的重要背景。免费试用、赠品和长期品牌合作也会影响接触范围，即使创作者没有被要求说正面评价。\\n\\n**识别重点：**\\n\\n- 查看链接、优惠码是否带来佣金或其他奖励\\n- 区分“价格更低”与“是否真的需要”\\n- 关注创作者是否比较过无佣金的替代方案\\n\\n## 需要注意\\n\\n本条解释利益结构，不判断具体合作是否违规。购买决策和预算管理属于行动建议库，不在此展开。\\n\\n透明披露能帮助观看者把利益关系纳入判断。', '博主频繁提供专属优惠码和购买链接，想判断推荐是否受到成交收益影响时。', '参考：Mathur等，2018，联盟营销披露实证研究；FTC代言与披露指南。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (160, 3, '限时、限量与倒计时如何制造决策紧迫感', '## 这个套路是什么\\n\\n“最后十分钟”“仅剩三件”“今晚恢复原价”等提示通过时间或数量稀缺，缩短用户比较、核实和等待的空间。紧迫感越强，用户越容易把注意力放在“会不会错过”，而不是“是否真的需要”。\\n\\n## 它如何制造印象\\n\\n倒计时、库存数字和滚动购买提示会把普通购物变成需要立即反应的事件。部分设计还会在刷新页面后重新开始倒计时，或使用难以验证的库存信息。即使稀缺真实，界面也可能通过颜色、动画和提示频率进一步放大压力。\\n\\n## 它容易忽略什么\\n\\n限时和限量并不必然虚假，直播场次、库存和促销周期可能确实有限。需要区分真实商业限制与无法核验、反复重置或故意模糊的紧迫提示。\\n\\n**识别重点：**\\n\\n- 倒计时结束后优惠是否真的消失\\n- 库存和购买提示是否可验证\\n- 紧迫信息是否遮盖价格、退货和订阅条件\\n\\n## 需要注意\\n\\n监管研究把虚假紧迫、隐藏信息和阻碍选择列为常见暗黑模式。具体消费延迟方法应放入行动建议库。\\n\\n紧迫感本身不是产品价值或适配程度的证明。', '直播间或购买页面不断倒数，自己还没比较产品就担心错过而准备立即付款时。', '参考：FTC，2022《Bringing Dark Patterns to Light》；欧盟委员会，2022，暗黑模式与操纵性个性化研究；EDPB，2022。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (161, 4, '触发—想法—情绪—行为四步记录法', '## 方法是什么\\n\\n这是一种基础的CBT自我监测方法，用来把“刷完突然很难受”拆成可观察的环节：发生了什么、脑中闪过什么解释、情绪和身体反应有多强、随后做了什么。它的目标不是立即把情绪消掉，而是找到焦虑循环中可以调整的位置。\\n\\n## 怎么使用\\n\\n1. **触发**：只写可观察事实，例如“看到同学发布录取通知”。\\n2. **自动想法**：记录第一时间出现的话，例如“所有人都比我快”。\\n3. **情绪与强度**：写出焦虑、羞耻、嫉妒或失落，并用0—100评分。\\n4. **行为**：记录继续刷、退出、反复看主页、删动态或回避学习等反应。\\n\\n完成后再问：这个行为短期帮了我什么，长期又带来了什么？\\n\\n## 社交媒体场景示例\\n\\n触发是“发帖20分钟只有两个赞”；自动想法是“大家觉得我很可笑”；焦虑75分；行为是每分钟刷新一次并准备删帖。把它写下来后，问题就从“我整个人不行”变成了一个可以检查的具体推断。\\n\\n## 使用边界\\n\\n记录不是审讯自己，也不要求每次情绪都分析。若记录让你反复纠缠细节，可以缩短为四句话。若焦虑持续严重影响睡眠、学习、工作或安全，应寻求专业评估。', '刷到比较内容、发帖等待反馈或被忽视后，情绪一下升高却说不清原因时。', '参考：Curtiss等，2021，焦虑相关CBT综述；NICE CG159，CBT中的监测与个体化认知模型。', 1, 1, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (162, 4, '把事实和解释分开', '## 方法是什么\\n\\n焦虑状态下，大脑容易把解释写成事实。例如“对方没有回复”是事实，“对方讨厌我”是解释；“视频播放量下降”是事实，“我已经失去价值”是解释。这个方法训练你先辨认两者，减少在证据不足时把最坏推断当成定论。\\n\\n## 怎么使用\\n\\n在纸上分两栏：\\n\\n- **摄像机能记录到的事实**：时间、文字、数字和实际行为。\\n- **我对事实的解释**：原因推测、他人想法和未来预测。\\n\\n接着给解释加一句：“这是一个可能性，不是已经证实的结论。”再列出至少两个同样符合事实的其他解释。\\n\\n## 社交媒体场景示例\\n\\n事实：“朋友看了群消息，没有回复，但十分钟后转发了另一条通知。”解释：“他故意无视我。”其他可能包括：不知道如何回复、认为不需要单独回应、当时只处理了工作通知。\\n\\n## 使用边界\\n\\n分开事实与解释，不代表要求你否认真实的人际问题。若同一种行为长期、稳定且伴随明确证据，可以进一步沟通或设定边界。这个方法只用于避免在证据不足时过早定案。', '看到已读不回、点赞减少或冷淡互动后，马上认定别人对自己有负面看法时。', '参考：Curtiss等，2021，认知重构与思维陷阱；Trent等，2024，焦虑CBT核心组成。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (163, 4, '自动想法捕捉：找到情绪前的一句话', '## 方法是什么\\n\\n自动想法是情绪被触发时迅速出现、常常未经审查的短句或画面。很多人只注意到“我很焦虑”，却没有发现焦虑前可能闪过“我落后了”“他们在笑我”“这次数据差说明以后都完了”。捕捉它，是后续认知检查的起点。\\n\\n## 怎么使用\\n\\n当情绪明显上升时，暂停并问：\\n\\n1. 刚才那一秒，我认为发生了什么？\\n2. 我最担心别人怎么看我？\\n3. 我预测接下来会发生什么？\\n4. 如果这个场景意味着一件关于“我”的事，那是什么？\\n\\n尽量把答案写成一句具体、可验证的话，而不是“我不好”“很焦虑”这种宽泛总结。\\n\\n## 社交媒体场景示例\\n\\n刷到前同学升职后，表面情绪是烦躁。继续追问，可能捕捉到：“我们起点差不多，他成功说明我浪费了这些年。”真正需要检查的是这条推断，而不是“升职动态”本身。\\n\\n## 使用边界\\n\\n自动想法不等于你真实相信的全部价值观，也不需要因为它刻薄、嫉妒或夸张而羞耻。它只是大脑在压力下给出的快速解释。若追问引发强烈创伤记忆，先停止并寻求专业支持。', '只知道自己刷完后很难受，却找不到究竟是哪种想法在推动情绪时。', '参考：Curtiss等，2021；Hofmann等，2012，CBT认知干预与总体证据综述。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (164, 4, '支持证据与反对证据检查', '## 方法是什么\\n\\n证据检查不是强迫自己积极，而是像调查员一样审查一个焦虑想法。它同时寻找支持和不支持该想法的材料，避免只收集符合最坏结论的信息。核心问题是：如果这是一项需要向别人证明的判断，我现在拥有多少可靠证据？\\n\\n## 怎么使用\\n\\n先把想法写得具体，例如“同学都认为我混得最差”。然后分别列出：\\n\\n- **支持证据**：真实发生、可以观察的材料。\\n- **反对证据**：不符合该结论的事实、例外和未知信息。\\n- **证据质量**：它是事实、猜测、单个案例，还是由情绪推出来的？\\n- **暂时结论**：当前最准确的说法是什么？\\n\\n## 社交媒体场景示例\\n\\n支持证据：有三位同学发布了工作成果。反对证据：没有人评价我的工作；朋友圈只展示愿意公开的人；我也完成了未发布的任务。更平衡的结论可以是：“我看到几个人的成果后产生落差，但没有证据证明所有人都领先或都否定我。”\\n\\n## 使用边界\\n\\n证据检查不用于替他人的伤害行为找借口，也不是要求你证明一切都很好。若证据明确指向现实问题，下一步应是问题解决或边界设置，而不是继续改写想法。', '对“所有人都比我好”“大家都讨厌我”等绝对结论深信不疑时。', '参考：Curtiss等，2021，认知重构；Carpenter等，2018，焦虑相关CBT随机试验元分析。', 1, 1, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (165, 4, '写出可相信的平衡替代想法', '## 方法是什么\\n\\n平衡替代想法不是把“我很失败”硬改成“我最优秀”，而是写出同时容纳困难、未知和自身资源的更准确解释。只有本人能够部分相信的句子，才可能在焦虑时发挥作用。\\n\\n## 怎么使用\\n\\n替代想法可以包含四部分：\\n\\n1. 承认事实：“这次互动确实比我期待的少。”\\n2. 指出未知：“我不知道每个人没有回应的原因。”\\n3. 修正扩大化：“一次反馈不能代表所有关系和长期价值。”\\n4. 提醒可行动部分：“我可以等到情绪下降后再决定是否沟通。”\\n\\n写完后给新想法的可信度评分。如果只有10%，说明句子太空泛，需要改得更贴近现实。\\n\\n## 社交媒体场景示例\\n\\n原想法：“这条内容数据差，说明我已经没有创作能力。”平衡版本：“这次数据低让我失望，但一次分发受多个因素影响；我可以分析内容表现，而不是把它当成对全部能力的判决。”\\n\\n## 使用边界\\n\\n替代想法不能代替现实行动，也不需要把负面感受消除。它的目标是减少过度、绝对和无法验证的解释。若你长期处在明确的攻击、骚扰或剥削环境中，应优先处理安全与边界。', '知道原想法可能过度，却只会用“想开点”压住自己，无法形成可信的新解释时。', '参考：Curtiss等，2021；Trent等，2024，焦虑CBT中的认知重构。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (166, 4, '识别社交媒体中的常见认知偏差', '## 方法是什么\\n\\n认知偏差标签帮助你识别思考方式，而不是给自己贴人格标签。社交媒体场景中常见的包括：读心术、灾难化、以偏概全、非黑即白、选择性注意、情绪推理和个人化。给模式命名，可以在想法与事实之间增加一点距离。\\n\\n## 怎么使用\\n\\n看到自动想法后，先问它更像哪种模式：\\n\\n- “没人点赞就是大家讨厌我”——读心术、以偏概全。\\n- “今天流量低，以后账号一定完了”——灾难化。\\n- “别人自律，我拖延，所以我毫无意志力”——非黑即白。\\n- “看到十个成功者，感觉所有人都成功”——选择性注意。\\n- “我感到羞耻，所以我一定做了丢脸的事”——情绪推理。\\n\\n命名后继续做证据检查，而不是停在“我又认知扭曲了”。\\n\\n## 社交媒体场景示例\\n\\n“朋友聚会没有叫我，说明我在所有关系里都不重要。”可以标记为以偏概全与个人化，再检查是否存在其他关系、其他原因和未掌握的信息。\\n\\n## 使用边界\\n\\n标签只是辅助语言，不是判定想法错误的证据。现实中的排斥、比较和不公平确实可能存在；认知工作应与事实核查并用。', '想法反复出现但说不清它为什么总把事情推向最坏结论时。', '参考：Curtiss等，2021，thinking traps与认知重构；Hofmann等，2012。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (167, 4, '连续谱法：打破非黑即白评价', '## 方法是什么\\n\\n非黑即白思维会把复杂表现压缩成两个极端：成功或失败、自律或堕落、受欢迎或被所有人厌恶。连续谱法把评价放回0—100的范围，并寻找中间位置与具体维度。\\n\\n## 怎么使用\\n\\n先写出两个极端，例如：\\n\\n- 0分：完全没有能力的创作者。\\n- 100分：每条内容都成功、永远稳定输出的完美创作者。\\n\\n再问：\\n\\n1. 现实中真的有人长期处在100分吗？\\n2. 我目前在哪个区间？依据是什么？\\n3. 能力由哪些维度组成，例如选题、表达、剪辑、稳定性和学习速度？\\n4. 提高5分的具体表现是什么？\\n\\n## 社交媒体场景示例\\n\\n刷到别人连续打卡后，你把自己定义为“完全不自律”。拆开后可能发现：学习执行60分、睡眠管理35分、运动50分。结论从人格判决变成了可调整的具体领域。\\n\\n## 使用边界\\n\\n连续谱法不是要求你用数字精确衡量人格。数字只用于打破两个极端。若你开始反复比较分数或建立新的完美标准，应停止量化，改用具体行为描述。', '因为一次拖延、一次低数据或一次冷场，就把自己归为彻底失败的人时。', '参考：Curtiss等，2021，认知重构与偏差识别；Hofmann等，2012。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (168, 4, '去灾难化：同时估计概率与应对能力', '## 方法是什么\\n\\n灾难化不仅高估坏结果发生的概率，还会低估自己应对结果的能力。去灾难化分两条线检查：“它有多可能发生？”以及“即使发生，我可以怎样处理？”\\n\\n## 怎么使用\\n\\n针对一个具体预测依次回答：\\n\\n1. 我担心的最坏结果是什么？\\n2. 发生概率大约是多少？依据是什么？\\n3. 更可能出现的普通结果是什么？\\n4. 如果最坏结果发生，我有哪些资源、步骤和求助对象？\\n5. 一周、一个月后，这件事可能处于什么位置？\\n\\n## 社交媒体场景示例\\n\\n预测：“我发错一句话会被全网围攻，学校和工作都会毁掉。”先检查账号可见范围、内容性质和过往经验，再写出应对方案：删除或澄清、保存证据、限制评论、向平台申诉、向可信任的人求助。焦虑可能仍在，但事件不再被理解为完全无法承受。\\n\\n## 使用边界\\n\\n若确实遭遇网暴、隐私泄露、勒索或现实威胁，不要只做认知练习，应优先保存证据并寻求平台、学校、单位、法律或警方支持。', '把一次发言、低流量或人际误会预测成不可挽回的人生灾难时。', '参考：Curtiss等，2021；Trent等，2024，焦虑CBT的认知与应对策略。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (169, 4, '替代解释法：减少读心和敌意归因', '## 方法是什么\\n\\n当线上信息缺少语气、表情和背景时，人容易用最威胁性的解释填补空白。替代解释法要求列出多个能够解释同一事实的假设，再比较每个假设的证据，而不是直接采用最伤人的版本。\\n\\n## 怎么使用\\n\\n把原解释写在第一行，例如“他没有回复，因为觉得我烦”。然后至少列出三种替代：\\n\\n- 当时忙，准备之后回复。\\n- 不知道怎样回应情绪内容。\\n- 认为消息不需要立即回答。\\n- 关系确实在疏远。\\n\\n分别给每种解释写支持证据、反对证据和当前可信度。最后确定“目前能知道什么、还不知道什么”。\\n\\n## 社交媒体场景示例\\n\\n你发现好友给别人点赞却没回你的消息。替代解释并不是否认被忽视的可能，而是防止从一个行为直接推导出“对方从未在乎我”这种全面结论。\\n\\n## 使用边界\\n\\n如果对方长期反复回避、贬低或利用你，替代解释不应成为无限容忍的工具。认知开放与人际边界需要同时存在。\\n\\n补充提醒：列替代解释时不必追求数量，重点是承认信息不完整，并让后续判断保持可修正。', '线上回应含糊或缺失时，脑中只剩“对方故意伤害我”这一种解释时。', '参考：Curtiss等，2021；NICE CG159，社会焦虑中的负面解释与行为实验。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (170, 4, '责任饼图：纠正过度个人化', '## 方法是什么\\n\\n过度个人化会把复杂结果主要归因于自己，例如“群聊冷场都是因为我无聊”“作品数据低全是因为我没能力”。责任饼图把可能因素列出并分配比例，提醒你结果通常由多个条件共同形成。\\n\\n## 怎么使用\\n\\n先写结果，例如“这条内容互动少”。列出所有可能因素：\\n\\n- 发布时间与在线人数\\n- 平台分发和受众匹配\\n- 内容主题与表达\\n- 账号规模\\n- 观众当时的精力\\n- 自己可以改进的部分\\n\\n再给各因素粗略分配比例，总和为100%。最后单独圈出“我能够影响但不等于由我负责全部”的部分。\\n\\n## 社交媒体场景示例\\n\\n班级群邀约无人回应。责任饼图中可能包含时间不合适、责任扩散、大家不熟、消息被覆盖和表达不够清晰。你的表达只占其中一部分，不需要把整个结果变成人格结论。\\n\\n## 使用边界\\n\\n比例不需要准确，也不能用来逃避自己明确的责任。它的作用是纠正“全是我的错”，不是改成“完全与我无关”。\\n\\n补充提醒：若多个因素无法估算，可以只写“主要、次要、未知”，不需要制造看似精确的百分比。', '把群聊冷场、关系变化或内容表现不佳全部归咎于自己时。', '参考：Curtiss等，2021，认知重构原则；Hofmann等，2012，CBT证据综述。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (171, 4, '向下箭头：找到反复比较背后的核心担忧', '## 方法是什么\\n\\n有些社交媒体触发会反复出现，是因为表面想法连接着更深的条件性规则或核心评价。向下箭头通过连续追问“如果这是真的，对我意味着什么”，找到真正让情绪升级的担忧。\\n\\n## 怎么使用\\n\\n从具体想法开始，每次只追问一次：\\n\\n- “别人升职了，我还没有。”\\n- 如果这是真的，对我意味着什么？——“我落后了。”\\n- 落后意味着什么？——“我没有能力。”\\n- 没有能力最让我怕什么？——“别人会失望，我也不值得被尊重。”\\n\\n找到较深层评价后，再检查它是否绝对、从何形成、是否把单一表现等同于整体价值。\\n\\n## 社交媒体场景示例\\n\\n你以为自己只是嫉妒别人的旅行，追问后却发现核心担忧是：“只有过得精彩，才证明我的人生值得被看见。”真正需要处理的是价值条件，而不是某一张旅行照。\\n\\n## 使用边界\\n\\n这项方法可能触及羞耻、童年经历或长期负面信念，不适合在情绪极度激动时持续深挖。若出现强烈痛苦、解离或创伤反应，应停止自助并在专业支持下进行。', '不同平台和内容总能触发相似的自卑，却不知道这些反应共同指向什么时。', '参考：Curtiss等，2021，焦虑CBT认知干预；NICE CG159，个体化认知模型。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (172, 4, '行为实验：用小测试检验焦虑预测', '## 方法是什么\\n\\n行为实验不是逼自己“勇敢一次”，而是把焦虑预测变成可以观察的小型测试。它通常比单纯争论想法更有说服力，因为结果来自亲身经验。实验重点是学习，而不是证明自己一定没事。\\n\\n## 怎么使用\\n\\n1. 写出预测：“如果我发一条不完美的动态，至少一半的人会觉得我很丢脸。”\\n2. 设计低风险测试：选择普通内容、限定可见范围或从较轻场景开始。\\n3. 预先确定观察指标：实际负面回应数、自己的焦虑变化、是否出现预想后果。\\n4. 完成后比较预测与结果，并记录学到什么。\\n5. 若结果不理想，也分析它是否真的等于原来的灾难结论。\\n\\n## 社交媒体场景示例\\n\\n预测“发言稍有停顿就会被群友嘲笑”，实验可以是在熟悉的小群中发一段不反复润色的普通观点，并观察真实回应，而不是直接在高风险公共议题下测试。\\n\\n## 使用边界\\n\\n不要用行为实验测试泄露隐私、挑衅网暴、医疗风险或现实安全。社交焦虑严重、存在创伤或强烈惊恐时，实验应与专业人员共同设计。', '理智上知道预测可能过度，但仅靠劝自己仍无法相信时。', '参考：Clément等，2019，行为实验研究；McManus等，2009，社会焦虑认知治疗成分实验。', 1, 1, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (173, 4, '分级暴露：逐步面对发布与互动焦虑', '## 方法是什么\\n\\n分级暴露是按照难度阶梯，逐步接触被焦虑回避的情境，并停留到能够获得新经验。对社交媒体而言，目标不是增加使用时长，而是减少“因为害怕评价而完全不敢正常表达”的回避。\\n\\n## 怎么使用\\n\\n先列出场景并评0—100难度，例如：\\n\\n- 给熟悉朋友点赞：20\\n- 在小群发普通消息：35\\n- 发布仅好友可见的日常：50\\n- 在公开区表达温和观点：75\\n\\n从中等偏低难度开始，重复练习，观察真实结果和焦虑变化，再逐步上移。暴露时尽量不使用过多安全行为，例如反复删改、请所有人提前保证会支持。\\n\\n## 社交媒体场景示例\\n\\n害怕发动态的人，不需要直接公开长文。可以先发一条低敏感、有限可见的普通内容，允许它保留一段时间，再记录预期与实际反馈。\\n\\n## 使用边界\\n\\n暴露不是硬扛，也不适用于现实中确有骚扰、隐私或职业风险的情境。若涉及创伤、惊恐、自伤风险或严重功能受损，应由专业人员评估和设计。\\n\\n补充提醒：每一级都应允许重复和退回；焦虑暂时升高不代表练习失败，但持续失控时应停止并求助。', '因为害怕被评价，已经无法进行必要的群聊、表达或正常发布时。', '参考：Ougrin，2011，暴露与认知治疗元分析；NICE CG159，社会焦虑个体CBT。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (174, 4, '减少安全行为：不再靠反复润色获得安全感', '## 方法是什么\\n\\n安全行为是为了防止被否定而采取的保护动作，例如一条消息修改二十遍、发布后立即删除、只说绝对不会出错的话、不断请朋友确认。它们短期降低焦虑，却可能让人无法知道：“即使不做这些，我也许仍能应对。”\\n\\n## 怎么使用\\n\\n先列出自己常用的安全行为，并区分必要保护与过度保护。一次只减少一个，例如：\\n\\n- 将修改次数从十次降到三次。\\n- 不再要求朋友发布前逐句审阅。\\n- 发出普通消息后允许自己暂时离开对话框。\\n- 不用自嘲提前否定自己来阻止别人评价。\\n\\n完成后记录预测、真实反馈和焦虑变化。\\n\\n## 社交媒体场景示例\\n\\n你担心群友觉得自己无聊，于是每句话后都加“哈哈我乱说的”。实验可以是在低风险群聊中发一次直接、普通的观点，不用自我贬低收尾。\\n\\n## 使用边界\\n\\n隐私设置、屏蔽骚扰和事实核查不是需要消除的安全行为。只减少那些主要用于缓解焦虑、却长期限制正常表达的动作。严重社交焦虑应在专业支持下练习。', '发消息或动态前必须不断修改、求确认或自我贬低，否则无法发送时。', '参考：McManus等，2008；Taylor与Alden，2010；Schreiber等，2015。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (175, 4, '延迟检查：打断反复刷新反馈的循环', '## 方法是什么\\n\\n反复刷新点赞、评论、在线状态和数据后台，常由“不检查就无法确定是否安全”的冲动推动。延迟检查不是永久禁止查看，而是在冲动与动作之间加入可控间隔，观察焦虑是否能够在不立即确认的情况下自然变化。\\n\\n## 怎么使用\\n\\n1. 记录平时发布后多久检查一次。\\n2. 设定略长但可完成的间隔，例如从每2分钟改为10分钟。\\n3. 冲动出现时记录强度，不立刻争辩，也不马上打开。\\n4. 到约定时间再查看一次，而不是连续刷新。\\n5. 稳定后逐步延长间隔，或减少每日固定检查次数。\\n\\n## 社交媒体场景示例\\n\\n发布内容后，你预测“十分钟不看就会错过重要评论”。练习时把手机放在视线外，记录焦虑从80变化到多少，再在约定时间统一查看。\\n\\n## 使用边界\\n\\n工作值班、紧急联络和需要及时处理的客服任务不适合机械延迟。若检查行为已经占用大量时间、影响睡眠或具有明显强迫性质，应寻求专业评估。\\n\\n补充提醒：练习应从可承受的短间隔开始；目标是增加选择空间，而不是用另一套严格规则惩罚自己。', '发布后不断刷新点赞、评论、在线状态或后台数据，明知疲惫却停不下来时。', '参考：Curtiss等，2021，焦虑CBT中的行为实验与暴露原则；NICE CG159。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (176, 4, '外部注意训练：把注意从自我监控移回交流', '## 方法是什么\\n\\n评价焦虑时，人可能把大量注意放在“我看起来怎样、这句话会不会很蠢、别人是否发现我紧张”，导致交流信息反而进入不了大脑。外部注意训练把注意重新放回对方内容、任务和环境线索。\\n\\n## 怎么使用\\n\\n在线交流前设定一个外部任务：\\n\\n- 找出对方表达的两个核心观点。\\n- 注意聊天中实际出现的语气与信息，而不是想象中的评价。\\n- 回应内容本身，而不是不断检查自己的措辞形象。\\n- 交流后列出三个真实观察，不写推测。\\n\\n还可以在低风险对话中比较“高度自我监控”和“关注交流内容”两种状态的体验差异。\\n\\n## 社交媒体场景示例\\n\\n参加线上会议时，你一直盯着自己的摄像头画面。练习可以隐藏自我预览，把注意放到发言者的论点，并在会后记录自己实际记住了什么。\\n\\n## 使用边界\\n\\n注意训练不是忽略真实危险或他人的明确攻击。它主要适用于因过度自我聚焦而加重的评价焦虑。注意偏向矫正的独立疗效证据有限，不应宣传为通用治疗。', '线上开会、群聊或发言时，全部注意都放在自己表现是否难看上时。', '参考：McManus等，2009；Furukawa等，2009；Heeren等，2015注意偏向矫正元分析。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (177, 4, '视频或录音反馈：校准过度负面的自我印象', '## 方法是什么\\n\\n评价焦虑会让人凭内部感受判断外在表现：心跳很快，就觉得所有人都看出自己失控；说话卡顿一下，就记成“整段表现都很糟”。视频或录音反馈用于比较预测、主观感受和真实记录。\\n\\n## 怎么使用\\n\\n在低风险场景中完成一段短发言或语音，事前写下具体预测，例如“我会停顿超过十次、声音明显发抖”。观看或收听前，先尝试以中性观察者角度记录可见事实，再与预测比较。\\n\\n观察时只描述：\\n\\n- 实际停顿次数\\n- 声音是否能听清\\n- 内容是否表达完整\\n- 他人是否出现明确负面反应\\n\\n避免反复放大外貌细节或无限回看。\\n\\n## 社交媒体场景示例\\n\\n你认为自己的线上发言“紧张得无法看”。回看后可能发现有两次停顿，但内容完整、语速基本正常。新的结论不是“我完美”，而是“内部紧张感比外部表现更强”。\\n\\n## 使用边界\\n\\n身体意象困扰、外貌强迫检查或创伤相关问题可能因录像加重，不宜自行反复观看。最好限定次数，严重焦虑时由专业人员引导。', '总觉得自己在视频、语音或直播中表现得极其糟糕，却主要依据内部感觉判断时。', '参考：McManus等，2009；Furukawa等，2009，视频反馈与社会焦虑实验。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (178, 4, '行为激活：从刷屏后的回避中重新行动', '## 方法是什么\\n\\n被比较内容打击后，有些人会停止学习、运动、社交和基本照顾，转而继续刷屏或躺着回避。行为激活不是等待心情好了再做事，而是安排小而具体、与生活价值相关的活动，让行动重新带来环境反馈。\\n\\n## 怎么使用\\n\\n先记录一天中的活动与情绪，找出“刷屏—低落—回避—更低落”的循环。随后分别安排：\\n\\n- **必要活动**：洗澡、吃饭、完成一个最小任务。\\n- **愉悦活动**：散步、音乐、线下兴趣。\\n- **掌控活动**：整理桌面、回复一封邮件、学习15分钟。\\n\\n任务要小到当下能开始，完成后记录情绪和掌控感，而不是只看是否“效率很高”。\\n\\n## 社交媒体场景示例\\n\\n看到同龄人成就后，你放弃原定学习并继续刷两小时。行为激活可以是先离开床铺、完成十分钟复习，再决定下一步，而不是制定极端逆袭计划。\\n\\n## 使用边界\\n\\n行为激活对抑郁的证据更充分，对焦虑也可能有帮助，但不能替代对严重抑郁、自伤风险或功能明显受损的专业治疗。', '刷完比较内容后陷入低落和瘫痪，越不行动越觉得自己失败时。', '参考：Stein等，2021，行为激活对抑郁、焦虑及活动水平的元分析。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (179, 4, '结构化问题解决：区分能处理的问题与情绪噪声', '## 方法是什么\\n\\n结构化问题解决适用于现实中确实存在、可以采取行动的问题，例如账号被骚扰、合作边界不清、社交媒体占用学习时间。它避免把所有困扰都当成“想法问题”，也避免在焦虑中同时解决十件事。\\n\\n## 怎么使用\\n\\n1. 用一句话定义问题，避免写成“我的人生很失败”。\\n2. 区分可控制、可影响和暂时不可控制的部分。\\n3. 不评判地列出多个方案。\\n4. 比较成本、风险和可行性。\\n5. 选择一个最小步骤，规定时间。\\n6. 执行后复盘结果，再调整方案。\\n\\n## 社交媒体场景示例\\n\\n问题不是“我自控力太差”，而是“睡前一小时反复打开短视频，导致入睡推迟”。可选方案包括调整充电位置、使用系统限制、替换睡前活动或请同住者协助。具体设置属于行动建议，问题解决法负责选择和评估。\\n\\n## 使用边界\\n\\n无法控制的事情不适合无限制定方案，例如要求所有人喜欢自己。涉及网暴、诈骗、隐私泄漏或现实威胁时，应优先使用平台、法律和安全资源。', '困扰中既有真实可处理问题，也有大量反复担忧，导致不知道先做什么时。', '参考：Zhang等，2018，问题解决治疗系统综述与元分析；Curtiss等，2021。', 1, 0, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (180, 4, '复发预防：为再次被触发提前写计划', '## 方法是什么\\n\\n情绪改善不等于以后再也不会被触发。复发预防把波动视为可以预期的过程：识别早期信号、总结有效方法、规定何时升级求助。它能减少“我又焦虑了，所以之前所有努力都白费”的二次打击。\\n\\n## 怎么使用\\n\\n建立一页维持计划：\\n\\n- **高风险情境**：考试季、失眠、关系冲突、发布重要内容后。\\n- **早期信号**：刷新次数增加、睡前刷屏、开始搜索比较对象。\\n- **已验证有效的方法**：四步记录、证据检查、延迟检查、线下活动。\\n- **需要避免的旧循环**：通宵搜索、冲动删号、与陌生人持续争辩。\\n- **升级标准**：连续多久影响睡眠或功能时联系谁、寻求何种帮助。\\n\\n## 社交媒体场景示例\\n\\n你已经减少数据检查，但重要作品发布时又开始频繁刷新。计划提醒你：先按固定时间查看，若两天内严重失眠或无法工作，就联系可信任的人或专业支持，而不是解释成彻底失败。\\n\\n## 使用边界\\n\\n维持计划不是保证不会复发，也不能替代危机处理。若出现自伤想法、明显危险或无法维持基本生活，应立即寻求当地紧急和专业帮助。', '状态好转后担心以后再次被社交媒体触发，或一次反复就觉得全部失败时。', '参考：Levy等，2021，焦虑CBT复发率元分析；Lorimer等，2021，复发预测因素综述。', 1, 1, NULL, '2026-06-17 15:19:38', '2026-06-17 14:43:43', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (181, 2, '精致生活与高光日常人设', '## 这种人设是什么\\n\\n这类人设把日常生活呈现为稳定、整洁、审美统一且值得记录的连续画面。常见内容包括布置讲究的房间、精心搭配的餐食、氛围感通勤和被认真安排的周末。它可能是真实生活的一部分，但并不等于发布者每天都处在同样的状态。\\n\\n## 它通常展示什么\\n\\n画面往往集中在适合公开、容易获得认可的时刻，例如完成布置后的房间、光线最好的早餐、已经解决问题后的复盘。不同日期和场景经过持续筛选后，会形成一种“生活一直很顺”的整体印象。\\n\\n## 它容易省略什么\\n\\n准备、返工、家务、经济成本、情绪低谷和普通到不值得拍摄的时段通常较少出现。被省略并不一定是欺骗，而是社交媒体自我呈现天然会优先选择可展示内容。\\n\\n## 为什么看起来很有说服力\\n\\n稳定的视觉风格和连续更新会让零散高光看起来像完整生活。观看者还容易把多个账号的优点叠加成一个不存在的“标准生活”，再与自己的全部日常比较。\\n\\n**观看时需要区分：**\\n\\n- 精致画面可以真实，但通常不是生活的平均切片\\n- 审美一致性反映内容选择，也可能反映时间、金钱与劳动投入\\n- 不应仅凭公开动态判断一个人的幸福程度\\n\\n## 需要注意\\n\\n研究表明，社交媒体自我呈现既可能包含真实表达，也可能带有选择性增强；具体程度因人、平台和受众而异。', '连续刷到整洁、从容、充满仪式感的日常后，开始觉得自己的普通生活粗糙而失败时。', '参考：Fox与Vendemia，2016，照片中的选择性自我呈现；Chou与Edge，2012，社交媒体与他人生活感知。', 1, 1, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (182, 2, '松弛感与“不费力”人设', '## 这种人设是什么\\n\\n松弛感人设强调自然、从容、不急于证明自己，好像工作、外貌、社交和生活品位都能毫不费力地维持。它与传统的炫耀不同，吸引力恰恰来自“看起来没有在经营”。\\n\\n## 它通常展示什么\\n\\n内容常呈现随手拍却构图良好的照片、轻描淡写的成功、不过度解释的消费选择，以及在繁忙生活中仍然保留休闲与审美的状态。\\n\\n## 它容易省略什么\\n\\n形成这种效果所需的筛选、拍摄、经济条件、时间安排和情绪管理通常不会进入画面。发布者也可能确实较为从容，但观看者无法从结果反推出过程毫无压力。\\n\\n## 为什么看起来很有说服力\\n\\n人们往往把明显努力与表演联系起来，而把自然感与真实性联系起来。持续稳定的“随意”风格会削弱观看者对策划程度的感知，使生活优势看起来像性格本身。\\n\\n**观看时需要区分：**\\n\\n- 从容可能是真实特质，也可能只是被选择出来的公开侧面\\n- 看起来不费力，不代表没有准备、资源或他人协助\\n- 松弛感不是衡量心理健康和生活能力的统一标准\\n\\n## 需要注意\\n\\n人设图鉴的目标不是揭穿谁在表演，而是提醒观看者：任何稳定的公开形象都可能经过选择。', '看到别人工作顺利、外形精致又从不显得紧张，怀疑自己太用力、太狼狈时。', '参考：Audrezet等，2020，网红真实性管理；Zheng等，2020，社交媒体中的自我提升与自我验证。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (183, 2, '极致自律与晨间仪式人设', '## 这种人设是什么\\n\\n这类人设以规律、克制和持续执行为核心，常用早起、运动、阅读、饮食管理和时间规划证明个人掌控力。它可能提供动力，但也会把复杂生活压缩为一条整齐的习惯链。\\n\\n## 它通常展示什么\\n\\n镜头常记录已经完成的打卡、整洁的工具、明确的时间表和状态良好的身体。内容强调重复性和连续性，使观众感到这些行为每天都能稳定发生。\\n\\n## 它容易省略什么\\n\\n睡眠不足、工作安排、失败天数、恢复时间、家庭支持和用于维护习惯的成本较少被展示。偶尔中断也可能不被发布，因此公开记录通常比真实执行更连贯。\\n\\n## 为什么看起来很有说服力\\n\\n数字打卡与连续更新会把行为转化成清晰证据；固定机位和相似流程进一步强化“稳定人格”的印象。观看者容易把内容生产本身误认为普通生活的自然记录。\\n\\n**观看时需要区分：**\\n\\n- 习惯记录可以激励人，但不能证明发布者从不疲惫或拖延\\n- 能够长期自律往往与环境、资源和工作性质有关\\n- 适合他人的完整流程不等于适合所有人的健康标准\\n\\n## 需要注意\\n\\n本条只分析人设结构；具体的时间管理方法和使用边界应放入行动建议或训练分类。', '刷到完整早起、运动、学习流程后，把自己偶尔拖延解释成缺乏意志力时。', '参考：Duffy与Hund，2015，社交媒体自我品牌与“拥有一切”叙事；Hjetland等，2022，自我呈现关注。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (184, 2, '学霸与高效学习人设', '## 这种人设是什么\\n\\n学霸人设通过成绩、学习时长、笔记、书桌和备考流程，建立“聪明、勤奋且始终高效”的形象。Studygram和“Study With Me”内容既可能提供陪伴与学习灵感，也可能使学习过程更适合被观看。\\n\\n## 它通常展示什么\\n\\n常见展示包括整洁笔记、连续计时、录取结果、阶段性成果和高度结构化的学习环境。知识理解、学习策略和可视化进度被组合成容易模仿的模板。\\n\\n## 它容易省略什么\\n\\n走神、低效尝试、对知识的误解、成绩波动以及不适合拍摄的混乱过程不容易进入内容。学习直播也不等于主播在每个镜头外时段都保持同样专注。\\n\\n## 为什么看起来很有说服力\\n\\n可见的计时器、任务清单和书桌布置让抽象的努力变得具体。观众容易把能被拍摄的“学习样子”与真实掌握程度、长期成绩完全等同。\\n\\n**观看时需要区分：**\\n\\n- 学习内容可以提供陪伴和可控的同伴压力\\n- 漂亮笔记和长时间直播不能单独证明学习质量\\n- 发布者的专业、考试制度和现实条件可能与观看者不同\\n\\n## 需要注意\\n\\n这类内容既可能有正面价值，也可能引发比较；不能统一判断为虚假或有害。', '看到别人长时间学习、笔记精美和一次上岸后，觉得自己的学习过程不够像“真正努力”时。', '参考：Izquierdo-Iranzo与Gallardo-Echenique，2020；Lee等，2021；Lussier等，2023。', 1, 1, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (185, 2, '职场精英与持续上升人设', '## 这种人设是什么\\n\\n职场精英人设把个人职业身份组织成清晰的成长故事：能力不断提升、项目不断扩大、机会持续出现。它在职业平台和普通社交媒体上都很常见，核心是证明专业性、可靠性和发展潜力。\\n\\n## 它通常展示什么\\n\\n内容通常聚焦职位变化、项目成果、公开演讲、行业活动、证书和工作方法。失败的申请、普通重复劳动和无法公开的团队贡献较少出现。\\n\\n## 它容易省略什么\\n\\n职业成果往往由团队、行业周期、组织资源和机会共同形成，但个人主页倾向于把复杂过程压缩为个人能力叙事。求职空窗、迷茫和工作中的低控制感也不适合公开展示。\\n\\n## 为什么看起来很有说服力\\n\\n平台界面鼓励填写技能、经历和背书，使职业身份变成可持续更新的履历。专业术语和第三方认可还能增强可信度，让观看者把公开档案当成完整能力评估。\\n\\n**观看时需要区分：**\\n\\n- 职业主页的功能本来就是突出可验证成果\\n- 持续发布成果不代表现实工作没有挫折和重复\\n- 职位、收入与个人价值不是同一指标\\n\\n## 需要注意\\n\\n对职业平台内容应保持信息工具视角，而不是把每一份公开履历当作同龄人的统一进度线。', '求职或工作受挫时，看到别人持续晋升、获奖和输出专业观点，觉得自己已被行业淘汰时。', '参考：van Dijck，2013，Facebook与LinkedIn的身份呈现；Bar-Ilan等，2015，学术职业自我呈现。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (186, 2, '创业成功与自由职业人设', '## 这种人设是什么\\n\\n创业与自由职业人设强调自主、创造力和摆脱传统组织约束，常把工作呈现为个人选择、热爱与生活方式的统一。它既可能记录真实职业路径，也容易将不稳定劳动包装成连贯的成长故事。\\n\\n## 它通常展示什么\\n\\n常见内容包括项目启动、客户反馈、收入节点、灵活办公、个人理念和“从零开始”的回顾。叙事通常突出个人意志、勇气和快速迭代。\\n\\n## 它容易省略什么\\n\\n现金流波动、失败项目、无报酬劳动、平台依赖、家庭支持和长期积累较少进入公开故事。成功发生后，早期经历也可能被重新组织成看似必然的路线。\\n\\n## 为什么看起来很有说服力\\n\\n个人品牌叙事需要把复杂职业经历讲成容易理解的角色：有愿景、敢行动、能转化。连续发布会让尚在变化的职业状态看起来已经稳定。\\n\\n**观看时需要区分：**\\n\\n- 自由度和不确定性可以同时存在\\n- 个人成功可能包含团队、资本、运气与既有资源\\n- 公开复盘常是事后整理，不是可复制的完整路线\\n\\n## 需要注意\\n\\n不要把创业人设简单视为吹嘘，也不要把它直接当作职业选择的风险说明书。', '看到别人辞职创业、远程工作并快速变现后，觉得稳定工作等于失败或缺乏勇气时。', '参考：Duffy与Hund，2015，创业式自我品牌；Khamis等，2017，微名人与社交媒体网红的自我品牌。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (187, 2, '财富自由与高消费品位人设', '## 这种人设是什么\\n\\n这类人设通过消费选择、居住环境、旅行和品牌偏好，传递财富、品位和生活掌控感。重点不一定是直接展示价格，也可能通过稀缺体验、低调品牌和“懂行”细节表达社会位置。\\n\\n## 它通常展示什么\\n\\n内容常选择高辨识度商品、精致空间、稀缺服务或消费后的从容体验。产品被放进日常叙事后，看起来不只是购买物，而是身份、审美和生活能力的证据。\\n\\n## 它容易省略什么\\n\\n收入来源、负债、合作置换、租借、赠品、家庭资源和为消费付出的机会成本可能不会被说明。即便消费完全真实，也无法据此推断长期财务状况。\\n\\n## 为什么看起来很有说服力\\n\\n社交媒体使消费具有公开比较功能。研究发现，自我呈现、社会比较和炫耀性消费倾向之间可能相互强化；豪华体验也容易通过羡慕影响购买意向。\\n\\n**观看时需要区分：**\\n\\n- 拥有某件商品不等于拥有稳定财富\\n- 品牌和场景能传递身份信号，但不代表完整财务结构\\n- 商业合作与个人消费应尽量分开理解\\n\\n## 需要注意\\n\\n本条不判断具体消费是否合理，只帮助识别“消费被用来表达身份”的人设结构。', '连续看到高消费、稀缺体验和“随手买”的内容后，开始用购买力判断自己是否体面时。', '参考：Lu等，2024，微信自我呈现与炫耀性消费；Liu等，2024，社交分享、羡慕与消费意向。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (188, 2, '旅行达人与数字游牧人设', '## 这种人设是什么\\n\\n旅行达人或数字游牧人设把移动、自由和世界经验作为核心身份。它强调地点切换、文化体验和自主安排，让工作与旅行看起来能够自然融合。\\n\\n## 它通常展示什么\\n\\n常见展示包括景观、特色住宿、当地饮食、远程办公画面以及“像当地人一样生活”的叙事。地点连续变化会强化生活丰富、时间自由和见识广阔的形象。\\n\\n## 它容易省略什么\\n\\n交通疲劳、签证限制、预算、工作时差、安全问题、拍摄等待和重复性行政事务较少成为主要内容。旅行者的停留时间、合作关系和工作稳定性也未必能从照片判断。\\n\\n## 为什么看起来很有说服力\\n\\n陌生地点本身具有视觉新鲜感，连续更新还能把短暂旅程组织成长期身份。旅游网红研究指出，旅行身份需要持续建构与维护，而不是地点照片的简单集合。\\n\\n**观看时需要区分：**\\n\\n- 旅行体验可以真实丰富，也可能同时包含大量不可见劳动\\n- 短期度假、内容创作和长期游牧是不同生活方式\\n- 景点密度不能直接衡量日常自由度和幸福感\\n\\n## 需要注意\\n\\n不要因为看到自由移动的结果，就假定对方没有经济、行政和职业约束。', '刷到持续旅行和远程办公内容后，觉得固定城市、固定作息的生活缺乏价值时。', '参考：Li等，2024，旅行网红的社会身份建构；Audrezet等，2020，网红真实性管理。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (189, 2, '健身塑形与健康自律人设', '## 这种人设是什么\\n\\n健身人设以身体变化、运动纪律和健康知识建立可信度，常把可见体型与自我管理能力联系起来。部分内容确实能提供运动信息和鼓励，但“健康”与“符合某种外形”经常被混在一起。\\n\\n## 它通常展示什么\\n\\n内容通常展示训练片段、饮食、体重或围度变化、紧致体型和前后对比。镜头偏好容易识别的身体成果，而不是心肺、睡眠、力量恢复等难以视觉化的健康指标。\\n\\n## 它容易省略什么\\n\\n基因、拍摄状态、伤病、恢复期、专业指导、饮食压力和状态波动较少出现。单次照片也无法说明长期健康、饮食关系或训练是否适合他人。\\n\\n## 为什么看起来很有说服力\\n\\nFitspiration把身体目标、励志语言与日常记录结合，使外貌理想看起来像纯粹的健康成果。系统综述显示，这类内容可能同时具有激励作用与身体比较风险。\\n\\n**观看时需要区分：**\\n\\n- 有运动习惯不等于所有建议都具备专业依据\\n- 视觉上的精瘦或强壮不等于完整健康\\n- 前后对比省略了时间、条件和个体差异\\n\\n## 需要注意\\n\\n看到健身内容时，可以区分“记录个人经验”“提供一般知识”和“给出医疗营养建议”三种角色。', '看到健身博主的体型和训练流程后，把自己的身体状态直接理解为不自律时。', '参考：Jerónimo与Carraça，2022，Fitspiration系统综述；Tiggemann与Zaccardo，2015；Carrotte等，2017。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (190, 2, '高颜值与精致外貌人设', '## 这种人设是什么\\n\\n高颜值人设以面部、妆容、穿搭和镜头表现力为核心，持续建立“随时都很好看”的印象。外貌可以是真实优势，但公开内容通常是特定角度、时段和筛选标准下的表现。\\n\\n## 它通常展示什么\\n\\n常见展示包括自拍、妆前妆后、穿搭、护肤和被他人拍摄的生活照。稳定的妆容、表情和构图会让个人外貌形成明确而可识别的品牌。\\n\\n## 它容易省略什么\\n\\n皮肤状态波动、不适合上镜的角度、拍摄次数、妆造时间、数字编辑和普通生活中的样子可能不会被同步展示。即使没有修图，选择哪张照片发布本身也是呈现行为。\\n\\n## 为什么看起来很有说服力\\n\\n照片内容容易被快速比较，点赞和评论还会为某种外貌提供社会认可线索。视觉平台上的选择性自拍与身体比较研究表明，观看者容易把筛选后的图像当成稳定现实。\\n\\n**观看时需要区分：**\\n\\n- 精修与真实并不是非黑即白，照片可同时包含真实特征与选择加工\\n- 好看是特定审美和场景中的评价，不是完整个人价值\\n- 账号风格稳定不代表本人每时每刻都保持同样外貌\\n\\n## 需要注意\\n\\n本条不讨论具体修图方法；图像处理与平台审美机制应放在“套路拆解”。', '长时间浏览精致自拍和穿搭账号后，觉得普通光线下的自己“不像一个正常人”时。', '参考：Fox与Vendemia，2016；Vandenbosch等，2022，社交媒体与身体意象综述。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (191, 2, '完美伴侣与甜蜜关系人设', '## 这种人设是什么\\n\\n完美关系人设把亲密关系呈现为稳定支持、浪漫投入和高度默契。纪念日、礼物、共同旅行和公开互动被组织成持续的关系证明，使旁观者容易把可见浪漫当作整体质量。\\n\\n## 它通常展示什么\\n\\n内容通常展示值得纪念的节点、伴侣的体贴行为、共同爱好和冲突解决后的结果。关系中的公开确认也可能帮助双方表达承诺和归属。\\n\\n## 它容易省略什么\\n\\n日常协商、价值冲突、沉默时段、家务分配和不便公开的关系边界通常不会出现。很少发布伴侣并不等于关系疏远，频繁发布也不能证明不存在问题。\\n\\n## 为什么看起来很有说服力\\n\\n人们倾向于通过有限线索推断他人生活。社交媒体上的积极自我呈现会让观看者更容易认为他人拥有更好的生活；关系内容还会借助双方互动增强真实性。\\n\\n**观看时需要区分：**\\n\\n- 公开浪漫是关系的一部分，不是完整质量检测\\n- 表达方式因人而异，低调不等于缺爱\\n- 一段关系是否健康，需要看线下尊重、沟通和安全，而不是动态密度\\n\\n## 需要注意\\n\\n不要将所有情侣内容都解释为表演，也不要用它作为要求自己或伴侣复制同款表达的依据。', '看到他人频繁晒礼物、纪念日和旅行后，开始怀疑自己的关系不够浪漫或不够被爱时。', '参考：Chou与Edge，2012，社交媒体与他人生活感知；Zheng等，2020，自我提升式呈现。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (192, 2, '完美父母与精致育儿人设', '## 这种人设是什么\\n\\n精致育儿人设通过儿童成长、家庭秩序、教育安排和亲子互动，建立“有耐心、懂方法、家庭运行良好”的父母形象。分享可能出于记录、支持交流或职业内容，并不必然是炫耀。\\n\\n## 它通常展示什么\\n\\n常见内容包括营养餐、亲子阅读、整洁家居、成长里程碑和温和沟通片段。孩子的成果也会成为父母身份与养育能力的公开证据。\\n\\n## 它容易省略什么\\n\\n育儿冲突、照护者疲惫、家庭帮助、经济投入、孩子不愿公开的时刻以及拍摄之外的重复劳动较少出现。儿童的公开形象还涉及其隐私与未来数字身份。\\n\\n## 为什么看起来很有说服力\\n\\n父母分享可以获得社会支持和认同，同时也会形成比较环境。研究讨论了父母分享的动机、亲子偏好差异，以及社会比较与育儿自我效能之间的关系。\\n\\n**观看时需要区分：**\\n\\n- 漂亮的亲子片段不能代表每天的家庭氛围\\n- 孩子的发展受多种因素影响，不是父母能力排行榜\\n- 父母分享权与儿童隐私、同意之间可能存在张力\\n\\n## 需要注意\\n\\n本条不评价具体家庭的养育水平，只分析公开育儿内容为何容易形成“完美父母”印象。', '看到别人每天做辅食、阅读和高质量陪伴后，觉得自己不是合格父母或未来一定做不好时。', '参考：Moser等，2017，父母与儿童对亲子内容分享的偏好；Bayraktar等，2024，父母社交比较与育儿效能。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (193, 2, '知识专家与“什么都懂”人设', '## 这种人设是什么\\n\\n知识专家人设通过稳定输出观点、概念和解决方案，建立专业、理性和判断可靠的形象。真正的专业传播很有价值，但平台内容常把复杂知识压缩成简洁结论，使“表达确定”容易被当成“证据充分”。\\n\\n## 它通常展示什么\\n\\n常见展示包括术语解释、热点点评、方法总结、书单和明确立场。账号会持续聚焦特定主题，通过统一语言风格和高频回应建立专业身份。\\n\\n## 它容易省略什么\\n\\n知识边界、争议、失败预测、团队协作、资料检索过程和无法回答的问题较少被展示。账号在一个领域有经验，也不自动具备相邻领域的专业资格。\\n\\n## 为什么看起来很有说服力\\n\\n社交媒体的可见性奖励清晰、快速和可传播的结论；个人品牌又要求持续维持一致角色。粉丝数量、镜头自信和内容质量可能相关，但不能替代资质与证据核验。\\n\\n**观看时需要区分：**\\n\\n- 善于表达与专业能力有关，但二者并不完全相同\\n- 经验分享、科普和个体诊疗建议具有不同责任边界\\n- 一个观点受欢迎，不等于它已获得学术共识\\n\\n## 需要注意\\n\\n涉及医疗、法律、金融等高风险内容时，需单独核对身份、证据和利益关系。', '因为某位博主表达非常确定、粉丝很多，就准备把其跨领域观点全部当成专业结论时。', '参考：Khamis等，2017，自我品牌与微名人；van Dijck，2013，平台化身份与专业自我推广。', 1, 1, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (194, 2, '情绪稳定与“人间清醒”人设', '## 这种人设是什么\\n\\n这类人设以理性、边界清楚和不受情绪左右为核心，常通过简洁判断、关系观点和冲突复盘，呈现“我看透了并且能控制自己”的状态。它可能来自真实经验，也可能是特定表达风格。\\n\\n## 它通常展示什么\\n\\n内容通常展示已经整理好的结论、明确的原则和冷静的回应，很少保留犹豫、反复、情绪爆发和需要他人安慰的过程。\\n\\n## 它容易省略什么\\n\\n形成清晰判断前的混乱、关系依赖、现实妥协和观点改变不容易被看见。短内容为了传播也会省略情境，使复杂关系看起来只需要一句原则就能解决。\\n\\n## 为什么看起来很有说服力\\n\\n确定的语言能降低不确定感，容易被理解为成熟与权威。持续发布相似判断后，账号会形成稳定角色，观看者可能把表达克制等同于内心从不波动。\\n\\n**观看时需要区分：**\\n\\n- 情绪稳定不是没有情绪，而是能够识别和调节情绪\\n- 明确边界需要结合关系、责任和现实条件\\n- 一句话原则适合传播，但未必适合所有具体处境\\n\\n## 需要注意\\n\\n不要把自己需要安慰、犹豫或改变主意理解为“不够清醒”。', '看到大量果断关系观点后，因自己仍然难过、依赖或犹豫而感到羞耻时。', '参考：Bailey等，2020，真实自我表达与幸福感；Hjetland等，2022，社交媒体自我呈现差异。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (195, 2, '极简主义与高级品位人设', '## 这种人设是什么\\n\\n极简主义人设通过物品少、空间整洁和选择克制，传递自我掌控、审美成熟和不被消费支配的形象。它可能源于真实价值观，但极简本身也能成为需要购买和维护的消费风格。\\n\\n## 它通常展示什么\\n\\n常见内容包括留白空间、统一色调、少量高品质物品、整理前后对比和“只留下真正需要的东西”的叙事。\\n\\n## 它容易省略什么\\n\\n储物空间、清洁劳动、替换成本、被移出镜头的物品和家庭成员差异不容易出现。高价格的“少而精”也可能依赖较强购买力。\\n\\n## 为什么看起来很有说服力\\n\\n整洁画面提供强烈秩序感，少量物品又容易被解释为自律和品位。与直接展示奢侈品相比，克制消费能够用更隐蔽的方式传递资源和审美资本。\\n\\n**观看时需要区分：**\\n\\n- 物品少可能来自价值选择，也可能来自内容构图需求\\n- 极简空间不等于生活负担一定更少\\n- 整洁、昂贵和心理健康之间没有简单对应关系\\n\\n## 需要注意\\n\\n不要把个人物品数量变成道德等级，也不要把极简账号理解为普遍适用的生活标准。', '看到极简空间后，觉得自己的正常生活用品和杂乱痕迹说明人格不够高级时。', '参考：Lu等，2024，自我呈现、社会比较与消费倾向；Duffy与Hund，2015，生活方式自我品牌。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (196, 2, '高社交能量与“朋友很多”人设', '## 这种人设是什么\\n\\n高社交能量人设通过聚会、合照、群体互动和频繁邀约，呈现受欢迎、连接广泛且生活充实的形象。它可能真实反映外向生活，也可能只是公开内容天然偏好多人场景。\\n\\n## 它通常展示什么\\n\\n常见展示包括生日、旅行、演出、团建和朋友间的公开互动。多人画面和评论区熟人交流会为社会地位提供直观线索。\\n\\n## 它容易省略什么\\n\\n独处、关系摩擦、浅层连接、活动后的疲惫和未被记录的小范围关系很少出现。合照人数也不能说明关系深度、稳定性或一个人是否感到孤独。\\n\\n## 为什么看起来很有说服力\\n\\n社交活动具有强可见性，一张照片可以同时展示地点、人数与他人认可。观看者容易用公开互动数量推断人格魅力和归属程度。\\n\\n**观看时需要区分：**\\n\\n- 朋友数量、公开互动和关系质量是不同指标\\n- 外向与内向是倾向，不是高低等级\\n- 经常独处的人也可能拥有稳定而深厚的关系\\n\\n## 需要注意\\n\\n不应因为某个账号热闹就认定对方从不孤独，也不应把自己的安静生活视为社交失败。', '刷到密集聚会和合照后，开始用活动数量判断自己是否被喜欢、是否拥有正常生活时。', '参考：Chou与Edge，2012，他人生活感知；Nesi等，2018，社交媒体如何改变同伴经验。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (197, 2, '真实反精致与“翻车”亲近人设', '## 这种人设是什么\\n\\n反精致人设主动展示失误、狼狈、杂乱或未经修饰的片段，以区别于传统完美账号。它可能扩大真实表达空间，也可能逐渐形成另一种稳定风格：必须显得自然、敢自嘲、没有距离感。\\n\\n## 它通常展示什么\\n\\n常见内容包括失败花絮、素颜、房间杂乱、自我吐槽和对商业合作的透明说明。适度脆弱能降低受众距离，增强“这个人和我一样”的感受。\\n\\n## 它容易省略什么\\n\\n被公开的失败仍然是经过选择的失败。真正涉及隐私、声誉或商业风险的部分可能不会出现；有些“翻车”内容也可能经过事后整理和安全评估。\\n\\n## 为什么看起来很有说服力\\n\\n研究指出，真实性是网红重要的社会资本，创作者会通过热情一致、透明披露和选择性自我揭示来维护可信度。展示缺点并不必然虚假，但也不是未经筛选的完整自我。\\n\\n**观看时需要区分：**\\n\\n- 展示不完美可以是真诚表达，也可以同时具有品牌功能\\n- 看起来随意的内容仍可能经过受众和风险判断\\n- 真实不是“什么都公开”，保留隐私同样合理\\n\\n## 需要注意\\n\\n不要陷入“精致一定假、狼狈一定真”的二分法。', '因为某位博主经常自嘲和展示失败，就认为其所有内容都不可能经过策划时。', '参考：Audrezet等，2020，网红真实性策略；Zimmermann等，2025，网红自我呈现与真实性。', 1, 1, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (198, 2, '谦虚炫耀与低调成功人设', '## 这种人设是什么\\n\\n谦虚炫耀是把成就信息放进抱怨、惊讶或自我贬低中，例如“又被迫升职了”“只是随便准备却拿了第一”。它试图同时获得能力认可和谦逊印象，是一种具体的自我呈现方式。\\n\\n## 它通常展示什么\\n\\n内容通常包含可识别的成就，但语气淡化主动展示意图。成功被描述成偶然、麻烦或意料之外，使发布者看起来既优秀又不自负。\\n\\n## 它容易省略什么\\n\\n实际投入、对认可的期待以及选择发布这条信息的动机不会直接说明。并非所有轻描淡写都是操控，有时也来自文化中的谦逊规范或不知道如何表达成就。\\n\\n## 为什么看起来很有说服力\\n\\n研究将谦虚炫耀定义为由抱怨或谦逊包装的炫耀，并发现它常因被感知为不真诚而适得其反。不过现实语境、关系和表达习惯都会影响判断。\\n\\n**观看时需要区分：**\\n\\n- 先看事实信息，再判断语气，不必自动推断恶意\\n- 公开成就是正常需求，直接表达未必比包装表达更自恋\\n- 文化中的客套和实验研究中的谦虚炫耀不能完全等同\\n\\n## 需要注意\\n\\n本条用于识别表达结构，而不是给某个发布者贴上虚伪标签。', '看到“随便做做就成功”“优秀也是一种烦恼”之类内容，既羡慕又觉得不舒服时。', '参考：Sezer、Gino与Norton，2018，谦虚炫耀作为低效自我呈现策略。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (199, 2, '美妆时尚与风格权威人设', '## 这种人设是什么\\n\\n美妆时尚人设通过稳定审美、产品选择和身体呈现，建立“知道什么适合、什么值得买”的风格权威。它既是创意表达，也常与商业推荐和个人品牌紧密结合。\\n\\n## 它通常展示什么\\n\\n常见内容包括妆容、穿搭、趋势判断、单品测评和前后变化。连续风格和对细节的熟练描述，会让个人偏好看起来像普遍审美规则。\\n\\n## 它容易省略什么\\n\\n试错成本、退货、品牌合作、团队妆造、身体差异和不适用人群通常无法在每条内容中完整呈现。一个效果在镜头中好看，也不等于在所有光线和生活场景中相同。\\n\\n## 为什么看起来很有说服力\\n\\n网红依靠专业感、亲近感和真实性积累影响力。商业合作进入后，创作者需要同时维护个人品位和受众信任，这两种目标有时会产生张力。\\n\\n**观看时需要区分：**\\n\\n- 风格建议具有主观性，不能等同于医学或身体价值判断\\n- 广告披露、产品来源和专业资格应分别核对\\n- 适合创作者的妆容与服装可能依赖其面部、体型和工作场景\\n\\n## 需要注意\\n\\n不必把流行风格当作修正自身缺陷的强制标准。', '因某位博主风格统一、表达专业，就认为其推荐一定客观且每件单品都适合自己时。', '参考：Zimmermann等，2025，美妆时尚健身网红的自我呈现；Audrezet等，2020，真实性与商业合作。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (200, 2, '健康饮食与全方位养生人设', '## 这种人设是什么\\n\\n健康养生人设通过饮食、运动、睡眠和自我照护建立“身体管理有方法”的形象。内容可能促进健康意识，但个人经验、一般健康信息与专业医疗建议之间的边界容易模糊。\\n\\n## 它通常展示什么\\n\\n常见展示包括干净食材、固定补充剂、晨间流程、体检指标、情绪管理和看似完整的健康系统。结果通常以精神状态、外形和日常效率表现。\\n\\n## 它容易省略什么\\n\\n慢性疾病、医学治疗、基因差异、失败尝试、检测误差和商业利益可能不会在短内容中充分说明。健康结果也很难只归因于某一种食物或习惯。\\n\\n## 为什么看起来很有说服力\\n\\n生活化镜头和持续实践能让建议显得比抽象医学信息更亲近。拟社会信任、个人故事和可见外形会增强说服力，但它们不能替代证据和专业资格。\\n\\n**观看时需要区分：**\\n\\n- 个人有效不等于对所有人有效\\n- 健康生活方式与疾病治疗建议具有不同证据要求\\n- 外貌、精力和账号活跃度不能证明完整健康状况\\n\\n## 需要注意\\n\\n遇到限制饮食、停药、替代治疗或补充剂建议时，应单独核验专业来源。', '看到博主状态很好、生活规律，就准备把其个人饮食和补充剂方案当成普遍医疗建议时。', '参考：Kaňková等，2025，健康类网红传播范围综述；Pilgrim与Bohnet-Joschko，2019，Instagram健康传播。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (201, 3, '高光切片：为什么信息流像一场人生精选展', '## 这个套路是什么\\n\\n社交媒体中的生活展示通常不是按时间连续记录，而是从大量普通、重复和不适合公开的片段中，挑出更漂亮、更顺利、更值得被看见的一小部分。单条内容可能完全真实，但连续观看许多人的高光切片，容易形成“别人一直过得很好”的整体印象。\\n\\n## 它如何制造印象\\n\\n平台鼓励用户发布具有信息价值、审美价值或社交价值的内容。完成目标、旅行、聚会、礼物和好状态更容易被记录，等待、返工、失败、争吵和无聊时段则较少进入信息流。观看者却常用自己的完整日常，与别人经过筛选的公开片段比较。\\n\\n## 容易忽略什么\\n\\n选择性展示不自动等于造假。人们面对不同受众，本来就会决定公开什么、保留什么。问题在于信息流把大量账号的精选内容汇聚到一起，使这种选择不再显眼。\\n\\n**识别重点：**\\n\\n- 一张真实照片不等于对方生活的平均状态\\n- 多个账号的高光不能拼成“普通人的标准生活”\\n- 没有出现的部分，不能被推断为不存在\\n\\n## 需要注意\\n\\n本条解释的是信息结构，不用于判断某位发布者是否诚实。观察一个账号时，应区分“内容是否真实”与“内容是否完整”这两个问题。', '连续刷到他人的旅行、成就和聚会后，开始觉得身边所有人都比自己顺利时。', '参考：Schwämmlein与Wodzicki，2012，网络社群中的自我呈现；Fox与Vendemia，2016，照片选择性呈现研究。', 1, 1, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (202, 3, '角度、光线与构图：真实画面也能改变生活质感', '## 这个套路是什么\\n\\n照片和视频不必经过明显修图，也能通过拍摄角度、焦距、光线、背景和取景范围改变观看者对人物与环境的判断。画面记录的是真实场景，但它只保留了镜头选择的那一部分现实。\\n\\n## 它如何制造印象\\n\\n低机位可能拉长身体比例，近距离广角可能夸张面部或空间，柔和侧光能够弱化皮肤纹理，狭窄取景可以避开杂乱区域。整洁桌面、酒店一角或餐厅局部经过构图后，会显得比完整空间更统一、更高级。连续使用相似视觉语言，还会形成稳定的个人审美印象。\\n\\n## 容易忽略什么\\n\\n摄影本身就是选择。取景并不说明画面外一定很糟，也不能说明发布者在欺骗；但观看者若把构图效果当作未经选择的肉眼现实，就容易高估这种生活状态的普遍程度。\\n\\n**识别重点：**\\n\\n- 看见画面时，也要意识到镜头外仍有大量信息\\n- “原相机”不等于没有角度、光线和取景影响\\n- 视觉质感往往包含拍摄经验、设备与后期劳动\\n\\n## 需要注意\\n\\n本条不要求否定摄影审美，而是区分“画面好看”与“现实始终如此”。同样的场景，在不同镜头选择下可能呈现完全不同的气氛。', '看到看似随手拍的房间、身材或餐食后，觉得自己的现实环境明显更差时。', '参考：Fox与Vendemia，2016，社交照片中的选择性自我呈现；Schwämmlein与Wodzicki，2012。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (203, 3, '美颜滤镜与局部编辑如何重写外貌参照', '## 这个套路是什么\\n\\n美颜滤镜和照片编辑可以调整肤色、轮廓、比例、光影与局部细节。许多处理非常轻微，单看一张图并不容易察觉，但长期接触统一的精致面孔和身体比例，会改变观看者对“普通外貌”的参照。\\n\\n## 它如何制造印象\\n\\n编辑工具把原本需要化妆、灯光、姿势和后期共同完成的效果，变成即时、稳定且可重复的界面功能。平台中的热门模板又让不同人的面部逐渐接近相似审美。观看者看见的是经过筛选和加工后的结果，却可能把它当成自然、常见甚至无需成本的状态。\\n\\n## 容易忽略什么\\n\\n不是每张好看的照片都经过重度修改，也不能仅凭外观断定具体编辑程度。更重要的是，照片编辑、拍摄角度、妆容和内容选择常常共同作用，单靠肉眼很难准确拆分。\\n\\n**识别重点：**\\n\\n- 滤镜效果可能很轻，不一定出现明显变形\\n- 高频接触会让加工后的外貌看起来更普通、更普遍\\n- 图片适合表达与创作，不适合充当真实人口外貌统计\\n\\n## 需要注意\\n\\n研究发现，照片编辑投入与身体不满意、自我客体化和外貌比较存在关联，但不能据此判断每个使用滤镜的人都会受到同样影响。', '刷到大量肤质、脸型和身材都高度一致的照片后，开始把这种效果当成自然外貌标准时。', '参考：McLean等，2015，自拍编辑与身体不满意；Ozimek等，2023，照片编辑、自我客体化与外貌比较。', 1, 1, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (204, 3, '“前后对比”如何把复杂变化压缩成单一答案', '## 这个套路是什么\\n\\n“使用前—使用后”“改变前—改变后”是一种高效的视觉叙事。它把复杂、漫长且受多种因素影响的变化，压缩成两个画面之间的明显差异，并暗示中间的产品、方法或决定是主要原因。\\n\\n## 它如何制造印象\\n\\n前后图常使用不同光线、姿势、表情、服装、镜头距离和拍摄时间。即使变化真实，结果也可能同时受到作息、饮食、医疗、经济条件、团队协助和自然波动影响。两张图并排出现时，观看者会本能地寻找一个简单因果，并忽略未展示的过程。\\n\\n## 容易忽略什么\\n\\n前后对比不是天然虚假，它可以帮助展示真实进展；问题在于它往往省略失败案例、维持成本、反复过程和其他变量。单个成功案例也不能证明所有人使用同样方法都会得到相同结果。\\n\\n**识别重点：**\\n\\n- 比较两张图的光线、姿势、时间和拍摄条件是否一致\\n- 区分“发生在使用之后”与“由它造成”\\n- 关注过程、样本数量和未成功者是否被呈现\\n\\n## 需要注意\\n\\n本条适用于健身、护肤、学习、理财和生活改造等多种内容。具体效果仍应结合更完整证据判断。', '看到明显的改变前后图，立即觉得某个产品或方法已经被“证明有效”时。', '参考：FTC《Endorsement Guides》及社交媒体代言披露指南；Fardouly与Holland，2018，理想化图像标签研究。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (205, 3, '“我的一天”视频如何压缩时间与删去空白', '## 这个套路是什么\\n\\n“我的一天”“沉浸式跟拍”看似连续记录生活，实际通常由多个短片段剪接而成。数小时的等待、移动、准备、走神和重复劳动，会被压缩为几分钟内不断发生的有效行动。\\n\\n## 它如何制造印象\\n\\n视频只保留起床、运动、工作、学习、做饭和社交等容易辨认的节点，并用时间字幕和转场建立连续感。空白时间被删去后，一天显得格外充实；失败镜头和无结果的尝试不进入成片，也使行动看起来更加顺畅。\\n\\n## 它容易忽略什么\\n\\n视频中的活动可以都真实发生过，但不能据此推断发布者全天保持同样效率。拍摄、布景、补录和剪辑本身也可能是工作的一部分，不等于普通人在现有条件下可以无成本复制。\\n\\n**识别重点：**\\n\\n- 成片时长与真实时间跨度不是一回事\\n- 连续剪辑会隐藏等待、恢复和无效时段\\n- “记录一天”仍然是经过主题选择的叙事作品\\n\\n## 需要注意\\n\\n本条不否定生活记录的参考价值。观看时把它当作经过编辑的样本，而不是完整时间审计，更不容易把自己的普通节奏判断为失败。', '看完几分钟的高效日常视频后，觉得自己一天没有完成同样多事情就是浪费时间时。', '参考：Georgakopoulou与Nunes，2022，社交媒体小故事与真实性指令；Schwämmlein与Wodzicki，2012。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (206, 3, '跳切、配乐与字幕如何预先安排你的情绪', '## 这个套路是什么\\n\\n短视频中的跳切、音乐、音效、字幕和节奏，不只负责让内容好看，也会提前告诉观看者“这一段应该紧张、感动、愤怒还是爽快”。同一段素材采用不同剪辑方式，可能产生完全不同的意义。\\n\\n## 它如何制造印象\\n\\n快速跳切减少思考空隙，强烈音乐提高情绪唤醒，放大的关键词把注意力锁定在创作者希望强调的解释上。反应镜头、停顿和重复播放又能突出冲突或尴尬，使偶发事件看起来更戏剧化、更具有代表性。\\n\\n## 它容易忽略什么\\n\\n情绪反应并不等于事实判断。视频让人感到震撼，不能自动证明其观点正确；让人感到温暖，也不能证明商业主张可靠。被删去的前因后果、完整对话和时间顺序可能改变事件含义。\\n\\n**识别重点：**\\n\\n- 尝试区分素材本身与音乐、字幕带来的解释\\n- 关注是否存在断章取义、顺序重排或关键上下文缺失\\n- 情绪越强烈，越需要暂停判断内容证据\\n\\n## 需要注意\\n\\n剪辑是正常创作工具，并非只有恶意内容才会使用。套路拆解的重点是识别形式如何影响理解，而不是要求所有视频保持无剪辑状态。', '一段短视频让自己立刻愤怒、感动或恐慌，却还没弄清完整事件经过时。', '参考：Chiossi等，2023，短视频切换与意图记忆；Molina等，2021，点击诱导内容研究。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (207, 3, '结果先行的成功故事与幸存者偏差', '## 这个套路是什么\\n\\n成功故事常从一个已经获得结果的人开始，再回头整理出一条连贯的成长路线。由于失败者、退出者和普通结果较少公开，观看者容易把少数成功路径误认为常见结局。\\n\\n## 它如何制造印象\\n\\n内容通常突出关键决定、个人品质和几个转折点，使成功看起来可以被清晰解释和复制。运气、行业周期、家庭支持、人脉、试错成本与未成功项目较少被纳入。平台也更愿意传播结果显著、叙事完整的故事，因为它们更容易吸引注意。\\n\\n## 它容易忽略什么\\n\\n从成功者倒推原因，无法判断采用同样方法但没有成功的人有多少。一个人真诚分享经验，也不意味着经验对不同资源、时间和风险承受能力的人具有同样效果。\\n\\n**识别重点：**\\n\\n- 问一问未成功者和中途退出者是否可见\\n- 区分“成功者常做什么”与“做了就更可能成功”\\n- 关注背景条件、基准概率和失败成本\\n\\n## 需要注意\\n\\n成功案例可以提供思路和可能性，但不能替代整体数据。尤其在创业、投资、升学和减重内容中，应避免仅凭个案推断普遍结果。', '刷到逆袭、创业或快速上岸故事后，觉得只要照做就应当得到同样结果时。', '参考：Salganik等，2006，社会影响与文化市场结果的不平等和不可预测性；FTC代言指南。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (208, 3, '个人经验如何被包装成“人人适用”的规律', '## 这个套路是什么\\n\\n社交媒体常把“我这样做后感觉有效”转化成“这种方法就是有效”。第一人称经历具有具体细节和情感力量，比抽象统计更容易被记住，因此个人体验经常被当作普遍规律传播。\\n\\n## 它如何制造印象\\n\\n创作者会用清晰步骤、确定语气和自身结果建立可信度。观看者又容易把相似身份、相似困扰理解为相同条件，从而忽略年龄、健康、资源、环境和同期变化。评论区中的“我也有效”会进一步形成一致性印象。\\n\\n## 它容易忽略什么\\n\\n个人体验可以真实，但无法排除自然变化、其他措施、期待效应和选择性记忆。没有对照组、样本规模和失败反馈时，很难知道结果是否稳定或适用于其他人。\\n\\n**识别重点：**\\n\\n- 留意“对我有效”是否悄悄变成“对所有人有效”\\n- 查看内容是否说明适用条件、限制和不确定性\\n- 健康、财务等高风险建议需要更高等级证据\\n\\n## 需要注意\\n\\n本条不是要求普通分享都写成论文，而是提醒观看者把个人经验放回它应有的位置：它能提供线索和体验，不能单独完成普遍性证明。', '看到创作者用自己的经历断言某种学习、护肤、减肥或赚钱方法适合所有人时。', '参考：FTC《Endorsement Guides》；Mathur等，2018，社交媒体联盟营销披露研究。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (209, 3, '精选见证与好评截图如何代替整体效果', '## 这个套路是什么\\n\\n品牌、课程和博主常展示用户感谢信、聊天截图、成功反馈和高分评论。这些材料可能来自真实用户，但通常是从大量反馈中挑选出来的，不等于所有用户的总体体验。\\n\\n## 它如何制造印象\\n\\n具体人物、前后变化和情绪化语言，会让效果显得可触摸、可信。多张好评连续出现时，观看者容易把数量感理解为成功率；而未改善、退款、沉默和负面反馈可能没有同等展示机会。\\n\\n## 它容易忽略什么\\n\\n精选见证无法说明样本基数，也不一定能代表典型结果。截图还可能缺少时间、完整对话和利益关系信息。即使每条见证都真实，也需要知道它们占全部用户的比例。\\n\\n**识别重点：**\\n\\n- 询问“这些成功案例来自多少总用户”\\n- 区分用户满意度、短期感受与可验证效果\\n- 留意见证者是否获得赠品、佣金或其他激励\\n\\n## 需要注意\\n\\n见证可以帮助理解使用体验，但不应替代系统数据和风险说明。涉及医疗、投资和重大消费时，更不能只依据精选好评作决定。', '看到连续的感谢信和成功案例后，感觉产品几乎人人有效，却不知道总样本和失败情况时。', '参考：FTC《Endorsement Guides》与《Disclosures 101 for Social Media Influencers》。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (210, 3, '标题党与“信息缺口”如何驱动点击', '## 这个套路是什么\\n\\n标题党通过省略关键信息、制造意外、冲突或强烈承诺，让观看者产生“必须点开才知道答案”的信息缺口。常见表达包括“最后一点没人告诉你”“事情彻底反转”“千万别再这样做”。\\n\\n## 它如何制造印象\\n\\n标题先提供足够的情绪和悬念，却延迟给出核心事实。观看者为了消除不确定性进入内容，平台便记录一次点击或停留。部分标题还会把有限差异写成重大突破，使内容在进入前显得比实际更重要。\\n\\n## 它容易忽略什么\\n\\n点击量说明标题成功吸引注意，不说明内容准确、有用或获得认可。研究发现，不同类型的点击诱导表达效果并不一致，一些明显套路甚至可能降低信任。\\n\\n**识别重点：**\\n\\n- 标题是否给出可核验主张，还是只制造情绪\\n- 内容是否真正回答了标题提出的问题\\n- 留意“绝对、唯一、彻底、所有人”等过度概括词\\n\\n## 需要注意\\n\\n有吸引力的标题不必然是欺骗。判断重点在于标题是否严重夸大正文、隐去关键限制，或故意让观看者形成错误预期。', '被“真相惊人”“最后一次提醒”等标题吸引，点开后发现信息非常普通时。', '参考：Molina等，2021，三项点击诱导实验；Mukherjee等，2022，点击诱导与传播表现研究。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (211, 3, '夸张封面与“首秒钩子”如何放大冲突', '## 这个套路是什么\\n\\n短视频和图文通常在封面、标题或开头几秒争夺注意力。“首秒钩子”会先展示最强冲突、最极端结果或最具视觉刺激的画面，再在后续补充背景。\\n\\n## 它如何制造印象\\n\\n推荐系统会依据观看、跳过和互动等信号调整分发，创作者因此有动力把关键刺激提前。惊讶表情、巨大文字、危险画面和对立句式能够减少立即划走，但也可能让事件严重程度在进入内容前就被放大。\\n\\n## 它容易忽略什么\\n\\n开头承担的是吸引任务，不一定代表内容的平均情绪。极端画面可能只占完整事件的一小段，封面也可能使用补拍、拼接或与结论关系较弱的素材。\\n\\n**识别重点：**\\n\\n- 不要只凭封面和开场判断完整事件\\n- 查看后文是否补充证据、限制与反例\\n- 注意冲突是否被人为提前或循环播放\\n\\n## 需要注意\\n\\n首秒钩子是平台环境下常见的表达策略，不必然意味着虚假。但当钩子与正文差异过大，就可能构成误导或制造不必要的情绪压力。\\n\\n封面只是进入内容的入口，不应被当作完整结论。', '刷到强烈冲突画面或极端字幕后，尚未看完整内容就已经形成确定判断时。', '参考：TikTok官方《5 tips for TikTok creators》；Molina等，2021，点击诱导实验。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (212, 3, '高唤醒内容为何更容易占据推荐流', '## 这个套路是什么\\n\\n愤怒、恐惧、惊讶和道德冲突等高唤醒情绪，往往更容易引发评论、转发和停留。平台未必主动判断某种立场更正确，但以互动为目标的排序可能让更能激起反应的内容获得额外可见性。\\n\\n## 它如何制造印象\\n\\n当情绪强烈的内容得到更多互动，排序系统会把这些反应当作相关性或兴趣信号。结果是温和、复杂和不确定的观点较难与简单、冲突性的内容竞争。用户连续看见极端样本后，可能误以为现实中的多数人也同样激烈。\\n\\n## 它容易忽略什么\\n\\n互动不等于赞同。人们可能因为愤怒、反驳或担忧而点击和评论。平台目标、具体算法和用户行为也会变化，不能把所有极化都归因于单一推荐机制。\\n\\n**识别重点：**\\n\\n- 区分“引发反应”与“获得认可”\\n- 高评论量可能代表争议，而不是共识\\n- 看到极端观点时，关注样本来源和线下代表性\\n\\n## 需要注意\\n\\n近期研究显示，以参与度排序可能放大更具分裂性的内容，但效果取决于具体平台和排序目标。应避免把算法描述成有意制造所有冲突的单一主体。', '推荐流连续出现愤怒、冲突和群体对立内容，让自己觉得社会整体充满敌意时。', '参考：Milli等，2025，参与度、满意度与分裂性内容放大研究。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (213, 3, '点赞、播放量与粉丝数如何形成社会证明', '## 这个套路是什么\\n\\n点赞、播放量、转发和粉丝数把他人的注意与反应转换成公开数字。观看者常把高数字理解为“很多人已经验证过”，从而更愿意停留、点击或相信内容。\\n\\n## 它如何制造印象\\n\\n数字提供了快速判断线索，尤其在信息过多、缺乏时间核实时更有影响。先获得的互动还可能带来更多曝光，形成可见性与互动互相强化的循环。创作者也会用“全网都在看”“已有十万人收藏”突出这种社会证明。\\n\\n## 它容易忽略什么\\n\\n高互动可能来自争议、娱乐性、付费推广、既有粉丝规模或发布时间，不等于内容质量和事实准确性。实验研究还表明，更多点赞并不在所有场景都必然带来更多点击，社会证明的效果会受到来源和情境影响。\\n\\n**识别重点：**\\n\\n- 先判断主张和证据，再把互动量当辅助信息\\n- 区分粉丝规模、传播能力与专业资质\\n- 高播放量可以证明被看见，不能证明被证实\\n\\n## 需要注意\\n\\n互动指标并非毫无价值，它能反映传播和受众反应；问题在于把传播表现直接替换成真实性、专业性或普遍效果。', '看到高赞、高收藏和大量粉丝后，在未检查内容来源前就默认其更专业、更真实时。', '参考：Huang与Lin，2025，点赞数量与广告点击现场实验；Salganik等，2006，社会影响实验。', 1, 1, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (214, 3, '热门榜单与排序位置如何制造“大家都在关注”', '## 这个套路是什么\\n\\n热搜、热门榜单和推荐列表把内容排成先后顺序。排名不仅反映已有关注，也会决定后续谁更容易被看见，因此榜单可能同时是结果和新的原因。\\n\\n## 它如何制造印象\\n\\n靠前位置获得更大屏幕面积、更少操作成本和更高进入概率。更多人点击后，系统又可能得到新的热度信号，形成反馈循环。用户看到榜单时，容易把“排得靠前”理解为社会中最重要、最普遍或最值得担忧的问题。\\n\\n## 它容易忽略什么\\n\\n榜单通常依据平台内部数据和规则，不等于公共议题的客观重要性。不同平台的用户结构、统计窗口、商业推广和内容审核都会影响排名。近期排序实验也提示，即使内容完全相同，位置变化本身也会显著影响互动。\\n\\n**识别重点：**\\n\\n- 问清榜单依据的是搜索、点击、讨论还是编辑选择\\n- 排名反映平台内可见性，不自动代表现实发生概率\\n- 同一事件在不同平台的热度可能完全不同\\n\\n## 需要注意\\n\\n榜单适合帮助用户发现内容，但不应成为判断社会共识、风险程度或事实真实性的唯一依据。', '看到某话题长期位于热榜前列，便认为现实生活中所有人都在讨论或同样担忧时。', '参考：Chan等，2025，算法排名与注意力预印本；Ciampaglia等，2018，流行度偏差与质量。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (215, 3, '置顶、精选与删除如何塑造评论区气候', '## 这个套路是什么\\n\\n评论区并不是所有反馈的自然平均展示。发布者和平台可以置顶、精选、折叠、删除或排序评论，从而改变新观看者首先看到的意见结构。\\n\\n## 它如何制造印象\\n\\n最靠前的几条评论会为内容建立解释框架：一致赞美会制造高度共识，集中反对会制造争议感，幽默评论则可能改变原内容语气。多数用户不会完整浏览全部回复，因此前排评论具有远高于普通评论的影响。\\n\\n## 它容易忽略什么\\n\\n前排意见可能由互动排序、时间优势、发布者选择或平台治理共同决定。看不到某类评论，不代表从未有人提出；出现大量同类评论，也可能来自特定社群集中进入，而不是全部观看者的比例。\\n\\n**识别重点：**\\n\\n- 留意评论排序方式和是否标注“精选”\\n- 区分发布者自己的置顶与自然高赞\\n- 争议议题可查看不同来源，而不是只读单一评论区\\n\\n## 需要注意\\n\\n删除辱骂、骚扰和违法内容是合理治理，并非所有删评都意味着操纵。关键是不要把一个经过管理的评论区直接当作完整民意调查。', '看到评论区几乎一边倒，便认定所有用户都持同样态度时。', '参考：Meta关于虚假互动与不真实行为的政策资料；Salganik等，2006，社会影响与反馈循环。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (216, 3, '刷量、互赞群与虚假互动如何伪造热度', '## 这个套路是什么\\n\\n账号可以通过购买点赞、播放、粉丝和评论，或加入互赞互评群，人为提高互动指标。这些行为让内容看起来已经获得大量真实关注，从而影响普通用户和推荐系统的后续判断。\\n\\n## 它如何制造印象\\n\\n高数字提供社会证明，整齐的好评评论又补充了“真实用户体验”。如果虚假互动发生在发布初期，它还可能帮助内容跨过某些可见性门槛。协调账号可以同时放大特定叙事，使少数组织化行为看起来像自发群众趋势。\\n\\n## 它容易忽略什么\\n\\n不是所有增长迅速的账号都刷量，也不能仅凭评论相似就断定造假。虚假互动形式不断变化，普通用户通常无法准确估算真实比例。平台公布的打击行动只能说明此类行为存在，不能证明某个具体账号参与。\\n\\n**识别重点：**\\n\\n- 观察互动是否与账号历史、内容质量和评论细节相符\\n- 大量空泛、重复或时间高度集中的评论值得进一步核验\\n- 不要仅凭粉丝和点赞判断专业能力\\n\\n## 需要注意\\n\\n本条用于理解指标可能被操纵，不建议对具体个人作无证据指控。必要时应依赖平台标记、公开调查或可验证数据。', '看到突然爆红的账号或一边倒的重复评论，想判断热度是否代表真实受众反应时。', '参考：Jahn等，2023，社交媒体点赞中的协调不真实行为；Murero等，2023，协调不真实行为研究；Meta相关政策。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (217, 3, '推荐流不是社会全貌，而是个性化排序结果', '## 这个套路是什么\\n\\n推荐流不是随机抽取社会内容，也不是按现实发生比例排列。系统会根据用户互动、内容信息、账号关系和平台规则，为不同用户生成不同顺序的内容集合。\\n\\n## 它如何制造印象\\n\\n个性化推荐提高相关性，也让每个人看到的“世界”不同。用户若频繁接触某类议题，容易把个人信息流误认为大众信息流，进而认为某种生活方式、冲突或观点无处不在。流行内容和既有账号还可能因历史数据获得更多机会。\\n\\n## 它容易忽略什么\\n\\n平台通常公开的是推荐因素和大致原则，而不是完整实时模型。推荐结果也不只由用户兴趣决定，还可能受地域、语言、新鲜度、安全规则和内容供给影响。因此不能用一句“算法懂你”解释所有内容出现。\\n\\n**识别重点：**\\n\\n- 你的首页只是一个经过排序的样本\\n- 连续出现不等于现实中占比同样高\\n- 不同账号、设备和时间可能看到完全不同的结果\\n\\n## 需要注意\\n\\n个性化推荐本身可以帮助发现有用内容。风险主要来自把高度定制的内容环境误当作完整社会统计或普遍共识。', '首页反复出现某类生活、冲突或观点，开始认为现实世界几乎全是这样时。', '参考：TikTok官方《How TikTok recommends videos #ForYou》；YouTube官方推荐说明；Meta Instagram推荐系统说明。', 1, 1, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (218, 3, '一次停留、重播和互动如何改变后续推荐', '## 这个套路是什么\\n\\n推荐系统会从观看时长、是否看完、重播、点赞、评论、分享、关注和跳过等行为中推断内容相关性。用户即使没有明确表示喜欢，停留和反复查看也可能成为后续推荐的信号。\\n\\n## 它如何制造印象\\n\\n争议、恐惧和猎奇内容会让人停下来确认细节，系统却未必能完整区分“喜欢”“担忧”“反驳”或“只是没反应过来”。当相似内容继续出现，用户又产生更多停留，便可能形成自我强化的信息路径。\\n\\n## 它容易忽略什么\\n\\n不同平台使用的信号权重不同，而且系统会综合许多因素。一次停留不一定立刻决定整个首页，也不能把所有后续内容归因于某一个动作。平台官方说明通常描述一般信号，而非公开具体权重。\\n\\n**识别重点：**\\n\\n- 观看行为也在向系统提供反馈\\n- 愤怒观看可能仍然增加该类内容的可见机会\\n- 推荐变化通常来自一组行为，而不是单次点击\\n\\n## 需要注意\\n\\n本条解释推荐反馈，不提供具体清理或训练步骤。平台的“不感兴趣”等控制工具属于行动建议库内容。', '因为震惊或生气而反复观看一类内容，随后发现首页越来越多相似内容时。', '参考：TikTok官方推荐与创作者说明；Zannettou等，2023，TikTok推荐与用户参与研究。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (219, 3, '相似内容连续出现如何制造“到处都是”的错觉', '## 这个套路是什么\\n\\n当推荐系统聚合相似主题、审美或立场时，用户会在很短时间内接触大量同类样本。重复暴露会提高内容的熟悉度和可提取性，使它在主观上显得更普遍、更重要。\\n\\n## 它如何制造印象\\n\\n只要用户对某主题表现出兴趣，系统就可能继续寻找相似内容。热门账号和高互动作品又容易被重复推荐，导致样本并不独立。十个相似视频可能来自同一种趋势、同一批素材或互相模仿的账号，却被大脑理解成十个独立现实证据。\\n\\n## 它容易忽略什么\\n\\n信息流中的出现频率不是现实发生率。内容供给、平台用户结构和推荐策略都会改变可见比例。熟悉感也不等于真实性，一种说法被重复很多次仍可能缺少可靠依据。\\n\\n**识别重点：**\\n\\n- 检查多个内容是否引用同一事件或同一原始来源\\n- 区分平台内热度与现实总体比例\\n- 重复出现可能说明系统找到了相似内容，不说明观点已被广泛证实\\n\\n## 需要注意\\n\\n这一现象可与流行度偏差、选择性接触和可得性判断共同作用，但不能简单概括为所有用户都被困在封闭“信息茧房”。', '几小时内刷到大量相同观点或生活方式，便觉得它已经成为普遍现实或唯一选择时。', '参考：Klimashevskaia等，2024，推荐系统流行度偏差综述；Ciampaglia等，2018。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (220, 3, '无限滚动与自动播放如何消除自然停止点', '## 这个套路是什么\\n\\n无限滚动和自动播放让下一条内容无需用户再次选择就自动出现。传统阅读中的页尾、节目结束和“是否继续”按钮被减少，使用过程因此缺少清晰的自然停止点。\\n\\n## 它如何制造印象\\n\\n每次滑动都可能出现不同奖励：有时有趣、有时无聊、有时非常吸引。不可预测的内容让用户愿意再看一条，而自动衔接又降低继续使用的操作成本。短视频之间快速切换，还可能打断用户对原本任务的保持。\\n\\n## 它容易忽略什么\\n\\n长时间使用并不完全由界面设计决定，用户目的、情绪、习惯和内容质量同样重要。监管机构对“成瘾式设计”的评估也可能处于调查或初步认定阶段，不能把所有过度使用都直接归因于单一功能。\\n\\n**识别重点：**\\n\\n- 观察产品是否持续提供内容而不要求再次确认\\n- 区分“我主动选择继续”与“下一条已经自动开始”\\n- 没有页尾会削弱对时间段落的感知\\n\\n## 需要注意\\n\\n本条解释界面结构。如何设置使用时段、关闭自动播放或建立停止提示，应放入行动建议库。', '原本只想看几分钟，却在没有明显结束提示的情况下不断滑到很久以后时。', '参考：FTC，2022《Bringing Dark Patterns to Light》；欧盟委员会，2026，对TikTok成瘾式设计的初步认定；Chiossi等，2023。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (221, 3, '红点、推送与“你错过了什么”如何召回注意', '## 这个套路是什么\\n\\n红点、角标、声音、震动和“你错过了什么”式推送，会在用户离开平台后重新争夺注意。这些提示把未读内容表现为需要处理的任务，或暗示社交关系和重要信息正在发生变化。\\n\\n## 它如何制造印象\\n\\n醒目的颜色和数字让未读状态持续可见，模糊文案则保留信息缺口，使用户需要点开才能确认。通知打断当前活动后，即使查看时间很短，也可能带来重新集中注意的额外成本。\\n\\n## 它容易忽略什么\\n\\n通知并非都为了操纵用户，安全提醒、工作消息和真实社交联系也依赖它们。影响取决于通知频率、内容重要性、个人任务和是否能够自主设置。研究通常发现干扰和压力风险，而不是说明每条推送都有相同效果。\\n\\n**识别重点：**\\n\\n- 区分有具体信息的通知与只制造悬念的召回文案\\n- 角标数量不等于事件紧急程度\\n- 推送设计可能利用FOMO和未完成感\\n\\n## 需要注意\\n\\n本条只解释提示设计。通知管理、免打扰设置等具体做法属于行动建议库。\\n\\n同一提示对不同任务和用户造成的干扰程度并不相同。', '看到未读数字或模糊推送后立刻中断学习工作，担心错过重要社交信息时。', '参考：Ohly等，2023，通信通知中断、压力与绩效；Dekker等，2025，关闭通知干预研究；FTC暗黑模式报告。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (222, 3, '软广如何伪装成自然生活分享', '## 这个套路是什么\\n\\n软广把品牌推广嵌入日常记录、经验分享、开箱、教程或情绪故事中，使商业信息看起来像普通内容。产品不一定被直接夸奖，也可能只是自然出现在“真实生活”里。\\n\\n## 它如何制造印象\\n\\n观看者与创作者形成熟悉感后，更容易把推荐理解为朋友式建议。广告如果沿用账号原有语气、场景和审美，商业边界会进一步模糊。品牌还可能要求创作者围绕个人困扰和改善过程构建故事，让产品成为叙事转折点。\\n\\n## 它容易忽略什么\\n\\n商业合作不等于推荐一定虚假，创作者也可能真实使用并认可产品。关键是观看者是否能够清楚识别利益关系，从而用适当标准评估内容。即使没有现金付款，赠品、免费旅行和佣金也可能构成需要披露的关系。\\n\\n**识别重点：**\\n\\n- 留意品牌是否在关键镜头、字幕和链接中反复出现\\n- 查看是否标注广告、赞助、赠品或合作\\n- 区分产品体验与无法验证的普遍效果承诺\\n\\n## 需要注意\\n\\n不同地区的披露规则不完全相同。本条不进行法律判断，只提醒商业关系可能影响内容选择和表达方式。', '一段看似普通的生活记录突然自然带出产品，却不确定创作者是否存在商业关系时。', '参考：Evans等，2017，Instagram网红广告披露；Mathur等，2018，YouTube与Pinterest联盟营销披露；FTC指南。', 1, 1, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (223, 3, '模糊广告标识为何让人意识不到自己在看广告', '## 这个套路是什么\\n\\n广告披露如果使用不显眼位置、含糊缩写或容易被忽略的词语，观看者可能在接收推荐后才意识到内容具有商业性质。常见问题不是完全没有文字，而是文字不够清楚、及时和容易理解。\\n\\n## 它如何制造印象\\n\\n“合作”“感谢品牌”“ambassador”等表达可能被理解为普通关系说明，而不是付费推广。披露放在长文末尾、折叠区域或大量标签中，也会降低识别率。用户没有意识到广告身份时，通常更容易按普通经验分享来评估可信度。\\n\\n## 它容易忽略什么\\n\\n不同用户对同一标识的理解不同，平台功能和法规也会更新。不能因为使用了某个缩写就直接判定违规，但清晰的“广告/赞助”通常比模糊表达更容易被识别。\\n\\n**识别重点：**\\n\\n- 披露是否在进入内容时就能看到\\n- 用词是否能让普通用户直接理解存在利益关系\\n- 是否被大量标签、折叠文字或快速画面掩盖\\n\\n## 需要注意\\n\\n研究主要关注广告识别、态度和行为意向，不能简单推断所有披露都会降低购买，或所有未识别广告都会造成同样影响。', '看到“合作伙伴”“品牌挚友”等模糊文字，不确定这究竟是普通分享还是付费推广时。', '参考：Evans等，2017，披露语言与广告识别；FTC《Disclosures 101》。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (224, 3, '优惠码与联盟链接如何改变推荐动机', '## 这个套路是什么\\n\\n联盟营销允许创作者通过专属链接、优惠码或成交追踪获得佣金。内容既可能帮助用户发现产品，也意味着推荐者的收益与点击或购买数量直接相关。\\n\\n## 它如何制造印象\\n\\n优惠码会把商业转化包装成“帮粉丝省钱”，专属链接则使购买过程非常顺畅。创作者可能优先介绍佣金更高、活动期更紧迫或更容易成交的商品，而观看者若不知道收益关系，容易把推荐顺序理解为纯粹的个人偏好排序。\\n\\n## 它容易忽略什么\\n\\n有佣金不代表产品不好或评价不真实，但它构成评估推荐时的重要背景。免费试用、赠品和长期品牌合作也会影响接触范围，即使创作者没有被要求说正面评价。\\n\\n**识别重点：**\\n\\n- 查看链接、优惠码是否带来佣金或其他奖励\\n- 区分“价格更低”与“是否真的需要”\\n- 关注创作者是否比较过无佣金的替代方案\\n\\n## 需要注意\\n\\n本条解释利益结构，不判断具体合作是否违规。购买决策和预算管理属于行动建议库，不在此展开。\\n\\n透明披露能帮助观看者把利益关系纳入判断。', '博主频繁提供专属优惠码和购买链接，想判断推荐是否受到成交收益影响时。', '参考：Mathur等，2018，联盟营销披露实证研究；FTC代言与披露指南。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (225, 3, '限时、限量与倒计时如何制造决策紧迫感', '## 这个套路是什么\\n\\n“最后十分钟”“仅剩三件”“今晚恢复原价”等提示通过时间或数量稀缺，缩短用户比较、核实和等待的空间。紧迫感越强，用户越容易把注意力放在“会不会错过”，而不是“是否真的需要”。\\n\\n## 它如何制造印象\\n\\n倒计时、库存数字和滚动购买提示会把普通购物变成需要立即反应的事件。部分设计还会在刷新页面后重新开始倒计时，或使用难以验证的库存信息。即使稀缺真实，界面也可能通过颜色、动画和提示频率进一步放大压力。\\n\\n## 它容易忽略什么\\n\\n限时和限量并不必然虚假，直播场次、库存和促销周期可能确实有限。需要区分真实商业限制与无法核验、反复重置或故意模糊的紧迫提示。\\n\\n**识别重点：**\\n\\n- 倒计时结束后优惠是否真的消失\\n- 库存和购买提示是否可验证\\n- 紧迫信息是否遮盖价格、退货和订阅条件\\n\\n## 需要注意\\n\\n监管研究把虚假紧迫、隐藏信息和阻碍选择列为常见暗黑模式。具体消费延迟方法应放入行动建议库。\\n\\n紧迫感本身不是产品价值或适配程度的证明。', '直播间或购买页面不断倒数，自己还没比较产品就担心错过而准备立即付款时。', '参考：FTC，2022《Bringing Dark Patterns to Light》；欧盟委员会，2022，暗黑模式与操纵性个性化研究；EDPB，2022。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (226, 4, '触发—想法—情绪—行为四步记录法', '## 方法是什么\\n\\n这是一种基础的CBT自我监测方法，用来把“刷完突然很难受”拆成可观察的环节：发生了什么、脑中闪过什么解释、情绪和身体反应有多强、随后做了什么。它的目标不是立即把情绪消掉，而是找到焦虑循环中可以调整的位置。\\n\\n## 怎么使用\\n\\n1. **触发**：只写可观察事实，例如“看到同学发布录取通知”。\\n2. **自动想法**：记录第一时间出现的话，例如“所有人都比我快”。\\n3. **情绪与强度**：写出焦虑、羞耻、嫉妒或失落，并用0—100评分。\\n4. **行为**：记录继续刷、退出、反复看主页、删动态或回避学习等反应。\\n\\n完成后再问：这个行为短期帮了我什么，长期又带来了什么？\\n\\n## 社交媒体场景示例\\n\\n触发是“发帖20分钟只有两个赞”；自动想法是“大家觉得我很可笑”；焦虑75分；行为是每分钟刷新一次并准备删帖。把它写下来后，问题就从“我整个人不行”变成了一个可以检查的具体推断。\\n\\n## 使用边界\\n\\n记录不是审讯自己，也不要求每次情绪都分析。若记录让你反复纠缠细节，可以缩短为四句话。若焦虑持续严重影响睡眠、学习、工作或安全，应寻求专业评估。', '刷到比较内容、发帖等待反馈或被忽视后，情绪一下升高却说不清原因时。', '参考：Curtiss等，2021，焦虑相关CBT综述；NICE CG159，CBT中的监测与个体化认知模型。', 1, 1, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (227, 4, '把事实和解释分开', '## 方法是什么\\n\\n焦虑状态下，大脑容易把解释写成事实。例如“对方没有回复”是事实，“对方讨厌我”是解释；“视频播放量下降”是事实，“我已经失去价值”是解释。这个方法训练你先辨认两者，减少在证据不足时把最坏推断当成定论。\\n\\n## 怎么使用\\n\\n在纸上分两栏：\\n\\n- **摄像机能记录到的事实**：时间、文字、数字和实际行为。\\n- **我对事实的解释**：原因推测、他人想法和未来预测。\\n\\n接着给解释加一句：“这是一个可能性，不是已经证实的结论。”再列出至少两个同样符合事实的其他解释。\\n\\n## 社交媒体场景示例\\n\\n事实：“朋友看了群消息，没有回复，但十分钟后转发了另一条通知。”解释：“他故意无视我。”其他可能包括：不知道如何回复、认为不需要单独回应、当时只处理了工作通知。\\n\\n## 使用边界\\n\\n分开事实与解释，不代表要求你否认真实的人际问题。若同一种行为长期、稳定且伴随明确证据，可以进一步沟通或设定边界。这个方法只用于避免在证据不足时过早定案。', '看到已读不回、点赞减少或冷淡互动后，马上认定别人对自己有负面看法时。', '参考：Curtiss等，2021，认知重构与思维陷阱；Trent等，2024，焦虑CBT核心组成。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (228, 4, '自动想法捕捉：找到情绪前的一句话', '## 方法是什么\\n\\n自动想法是情绪被触发时迅速出现、常常未经审查的短句或画面。很多人只注意到“我很焦虑”，却没有发现焦虑前可能闪过“我落后了”“他们在笑我”“这次数据差说明以后都完了”。捕捉它，是后续认知检查的起点。\\n\\n## 怎么使用\\n\\n当情绪明显上升时，暂停并问：\\n\\n1. 刚才那一秒，我认为发生了什么？\\n2. 我最担心别人怎么看我？\\n3. 我预测接下来会发生什么？\\n4. 如果这个场景意味着一件关于“我”的事，那是什么？\\n\\n尽量把答案写成一句具体、可验证的话，而不是“我不好”“很焦虑”这种宽泛总结。\\n\\n## 社交媒体场景示例\\n\\n刷到前同学升职后，表面情绪是烦躁。继续追问，可能捕捉到：“我们起点差不多，他成功说明我浪费了这些年。”真正需要检查的是这条推断，而不是“升职动态”本身。\\n\\n## 使用边界\\n\\n自动想法不等于你真实相信的全部价值观，也不需要因为它刻薄、嫉妒或夸张而羞耻。它只是大脑在压力下给出的快速解释。若追问引发强烈创伤记忆，先停止并寻求专业支持。', '只知道自己刷完后很难受，却找不到究竟是哪种想法在推动情绪时。', '参考：Curtiss等，2021；Hofmann等，2012，CBT认知干预与总体证据综述。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (229, 4, '支持证据与反对证据检查', '## 方法是什么\\n\\n证据检查不是强迫自己积极，而是像调查员一样审查一个焦虑想法。它同时寻找支持和不支持该想法的材料，避免只收集符合最坏结论的信息。核心问题是：如果这是一项需要向别人证明的判断，我现在拥有多少可靠证据？\\n\\n## 怎么使用\\n\\n先把想法写得具体，例如“同学都认为我混得最差”。然后分别列出：\\n\\n- **支持证据**：真实发生、可以观察的材料。\\n- **反对证据**：不符合该结论的事实、例外和未知信息。\\n- **证据质量**：它是事实、猜测、单个案例，还是由情绪推出来的？\\n- **暂时结论**：当前最准确的说法是什么？\\n\\n## 社交媒体场景示例\\n\\n支持证据：有三位同学发布了工作成果。反对证据：没有人评价我的工作；朋友圈只展示愿意公开的人；我也完成了未发布的任务。更平衡的结论可以是：“我看到几个人的成果后产生落差，但没有证据证明所有人都领先或都否定我。”\\n\\n## 使用边界\\n\\n证据检查不用于替他人的伤害行为找借口，也不是要求你证明一切都很好。若证据明确指向现实问题，下一步应是问题解决或边界设置，而不是继续改写想法。', '对“所有人都比我好”“大家都讨厌我”等绝对结论深信不疑时。', '参考：Curtiss等，2021，认知重构；Carpenter等，2018，焦虑相关CBT随机试验元分析。', 1, 1, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (230, 4, '写出可相信的平衡替代想法', '## 方法是什么\\n\\n平衡替代想法不是把“我很失败”硬改成“我最优秀”，而是写出同时容纳困难、未知和自身资源的更准确解释。只有本人能够部分相信的句子，才可能在焦虑时发挥作用。\\n\\n## 怎么使用\\n\\n替代想法可以包含四部分：\\n\\n1. 承认事实：“这次互动确实比我期待的少。”\\n2. 指出未知：“我不知道每个人没有回应的原因。”\\n3. 修正扩大化：“一次反馈不能代表所有关系和长期价值。”\\n4. 提醒可行动部分：“我可以等到情绪下降后再决定是否沟通。”\\n\\n写完后给新想法的可信度评分。如果只有10%，说明句子太空泛，需要改得更贴近现实。\\n\\n## 社交媒体场景示例\\n\\n原想法：“这条内容数据差，说明我已经没有创作能力。”平衡版本：“这次数据低让我失望，但一次分发受多个因素影响；我可以分析内容表现，而不是把它当成对全部能力的判决。”\\n\\n## 使用边界\\n\\n替代想法不能代替现实行动，也不需要把负面感受消除。它的目标是减少过度、绝对和无法验证的解释。若你长期处在明确的攻击、骚扰或剥削环境中，应优先处理安全与边界。', '知道原想法可能过度，却只会用“想开点”压住自己，无法形成可信的新解释时。', '参考：Curtiss等，2021；Trent等，2024，焦虑CBT中的认知重构。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (231, 4, '识别社交媒体中的常见认知偏差', '## 方法是什么\\n\\n认知偏差标签帮助你识别思考方式，而不是给自己贴人格标签。社交媒体场景中常见的包括：读心术、灾难化、以偏概全、非黑即白、选择性注意、情绪推理和个人化。给模式命名，可以在想法与事实之间增加一点距离。\\n\\n## 怎么使用\\n\\n看到自动想法后，先问它更像哪种模式：\\n\\n- “没人点赞就是大家讨厌我”——读心术、以偏概全。\\n- “今天流量低，以后账号一定完了”——灾难化。\\n- “别人自律，我拖延，所以我毫无意志力”——非黑即白。\\n- “看到十个成功者，感觉所有人都成功”——选择性注意。\\n- “我感到羞耻，所以我一定做了丢脸的事”——情绪推理。\\n\\n命名后继续做证据检查，而不是停在“我又认知扭曲了”。\\n\\n## 社交媒体场景示例\\n\\n“朋友聚会没有叫我，说明我在所有关系里都不重要。”可以标记为以偏概全与个人化，再检查是否存在其他关系、其他原因和未掌握的信息。\\n\\n## 使用边界\\n\\n标签只是辅助语言，不是判定想法错误的证据。现实中的排斥、比较和不公平确实可能存在；认知工作应与事实核查并用。', '想法反复出现但说不清它为什么总把事情推向最坏结论时。', '参考：Curtiss等，2021，thinking traps与认知重构；Hofmann等，2012。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (232, 4, '连续谱法：打破非黑即白评价', '## 方法是什么\\n\\n非黑即白思维会把复杂表现压缩成两个极端：成功或失败、自律或堕落、受欢迎或被所有人厌恶。连续谱法把评价放回0—100的范围，并寻找中间位置与具体维度。\\n\\n## 怎么使用\\n\\n先写出两个极端，例如：\\n\\n- 0分：完全没有能力的创作者。\\n- 100分：每条内容都成功、永远稳定输出的完美创作者。\\n\\n再问：\\n\\n1. 现实中真的有人长期处在100分吗？\\n2. 我目前在哪个区间？依据是什么？\\n3. 能力由哪些维度组成，例如选题、表达、剪辑、稳定性和学习速度？\\n4. 提高5分的具体表现是什么？\\n\\n## 社交媒体场景示例\\n\\n刷到别人连续打卡后，你把自己定义为“完全不自律”。拆开后可能发现：学习执行60分、睡眠管理35分、运动50分。结论从人格判决变成了可调整的具体领域。\\n\\n## 使用边界\\n\\n连续谱法不是要求你用数字精确衡量人格。数字只用于打破两个极端。若你开始反复比较分数或建立新的完美标准，应停止量化，改用具体行为描述。', '因为一次拖延、一次低数据或一次冷场，就把自己归为彻底失败的人时。', '参考：Curtiss等，2021，认知重构与偏差识别；Hofmann等，2012。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (233, 4, '去灾难化：同时估计概率与应对能力', '## 方法是什么\\n\\n灾难化不仅高估坏结果发生的概率，还会低估自己应对结果的能力。去灾难化分两条线检查：“它有多可能发生？”以及“即使发生，我可以怎样处理？”\\n\\n## 怎么使用\\n\\n针对一个具体预测依次回答：\\n\\n1. 我担心的最坏结果是什么？\\n2. 发生概率大约是多少？依据是什么？\\n3. 更可能出现的普通结果是什么？\\n4. 如果最坏结果发生，我有哪些资源、步骤和求助对象？\\n5. 一周、一个月后，这件事可能处于什么位置？\\n\\n## 社交媒体场景示例\\n\\n预测：“我发错一句话会被全网围攻，学校和工作都会毁掉。”先检查账号可见范围、内容性质和过往经验，再写出应对方案：删除或澄清、保存证据、限制评论、向平台申诉、向可信任的人求助。焦虑可能仍在，但事件不再被理解为完全无法承受。\\n\\n## 使用边界\\n\\n若确实遭遇网暴、隐私泄露、勒索或现实威胁，不要只做认知练习，应优先保存证据并寻求平台、学校、单位、法律或警方支持。', '把一次发言、低流量或人际误会预测成不可挽回的人生灾难时。', '参考：Curtiss等，2021；Trent等，2024，焦虑CBT的认知与应对策略。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (234, 4, '替代解释法：减少读心和敌意归因', '## 方法是什么\\n\\n当线上信息缺少语气、表情和背景时，人容易用最威胁性的解释填补空白。替代解释法要求列出多个能够解释同一事实的假设，再比较每个假设的证据，而不是直接采用最伤人的版本。\\n\\n## 怎么使用\\n\\n把原解释写在第一行，例如“他没有回复，因为觉得我烦”。然后至少列出三种替代：\\n\\n- 当时忙，准备之后回复。\\n- 不知道怎样回应情绪内容。\\n- 认为消息不需要立即回答。\\n- 关系确实在疏远。\\n\\n分别给每种解释写支持证据、反对证据和当前可信度。最后确定“目前能知道什么、还不知道什么”。\\n\\n## 社交媒体场景示例\\n\\n你发现好友给别人点赞却没回你的消息。替代解释并不是否认被忽视的可能，而是防止从一个行为直接推导出“对方从未在乎我”这种全面结论。\\n\\n## 使用边界\\n\\n如果对方长期反复回避、贬低或利用你，替代解释不应成为无限容忍的工具。认知开放与人际边界需要同时存在。\\n\\n补充提醒：列替代解释时不必追求数量，重点是承认信息不完整，并让后续判断保持可修正。', '线上回应含糊或缺失时，脑中只剩“对方故意伤害我”这一种解释时。', '参考：Curtiss等，2021；NICE CG159，社会焦虑中的负面解释与行为实验。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (235, 4, '责任饼图：纠正过度个人化', '## 方法是什么\\n\\n过度个人化会把复杂结果主要归因于自己，例如“群聊冷场都是因为我无聊”“作品数据低全是因为我没能力”。责任饼图把可能因素列出并分配比例，提醒你结果通常由多个条件共同形成。\\n\\n## 怎么使用\\n\\n先写结果，例如“这条内容互动少”。列出所有可能因素：\\n\\n- 发布时间与在线人数\\n- 平台分发和受众匹配\\n- 内容主题与表达\\n- 账号规模\\n- 观众当时的精力\\n- 自己可以改进的部分\\n\\n再给各因素粗略分配比例，总和为100%。最后单独圈出“我能够影响但不等于由我负责全部”的部分。\\n\\n## 社交媒体场景示例\\n\\n班级群邀约无人回应。责任饼图中可能包含时间不合适、责任扩散、大家不熟、消息被覆盖和表达不够清晰。你的表达只占其中一部分，不需要把整个结果变成人格结论。\\n\\n## 使用边界\\n\\n比例不需要准确，也不能用来逃避自己明确的责任。它的作用是纠正“全是我的错”，不是改成“完全与我无关”。\\n\\n补充提醒：若多个因素无法估算，可以只写“主要、次要、未知”，不需要制造看似精确的百分比。', '把群聊冷场、关系变化或内容表现不佳全部归咎于自己时。', '参考：Curtiss等，2021，认知重构原则；Hofmann等，2012，CBT证据综述。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (236, 4, '向下箭头：找到反复比较背后的核心担忧', '## 方法是什么\\n\\n有些社交媒体触发会反复出现，是因为表面想法连接着更深的条件性规则或核心评价。向下箭头通过连续追问“如果这是真的，对我意味着什么”，找到真正让情绪升级的担忧。\\n\\n## 怎么使用\\n\\n从具体想法开始，每次只追问一次：\\n\\n- “别人升职了，我还没有。”\\n- 如果这是真的，对我意味着什么？——“我落后了。”\\n- 落后意味着什么？——“我没有能力。”\\n- 没有能力最让我怕什么？——“别人会失望，我也不值得被尊重。”\\n\\n找到较深层评价后，再检查它是否绝对、从何形成、是否把单一表现等同于整体价值。\\n\\n## 社交媒体场景示例\\n\\n你以为自己只是嫉妒别人的旅行，追问后却发现核心担忧是：“只有过得精彩，才证明我的人生值得被看见。”真正需要处理的是价值条件，而不是某一张旅行照。\\n\\n## 使用边界\\n\\n这项方法可能触及羞耻、童年经历或长期负面信念，不适合在情绪极度激动时持续深挖。若出现强烈痛苦、解离或创伤反应，应停止自助并在专业支持下进行。', '不同平台和内容总能触发相似的自卑，却不知道这些反应共同指向什么时。', '参考：Curtiss等，2021，焦虑CBT认知干预；NICE CG159，个体化认知模型。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (237, 4, '行为实验：用小测试检验焦虑预测', '## 方法是什么\\n\\n行为实验不是逼自己“勇敢一次”，而是把焦虑预测变成可以观察的小型测试。它通常比单纯争论想法更有说服力，因为结果来自亲身经验。实验重点是学习，而不是证明自己一定没事。\\n\\n## 怎么使用\\n\\n1. 写出预测：“如果我发一条不完美的动态，至少一半的人会觉得我很丢脸。”\\n2. 设计低风险测试：选择普通内容、限定可见范围或从较轻场景开始。\\n3. 预先确定观察指标：实际负面回应数、自己的焦虑变化、是否出现预想后果。\\n4. 完成后比较预测与结果，并记录学到什么。\\n5. 若结果不理想，也分析它是否真的等于原来的灾难结论。\\n\\n## 社交媒体场景示例\\n\\n预测“发言稍有停顿就会被群友嘲笑”，实验可以是在熟悉的小群中发一段不反复润色的普通观点，并观察真实回应，而不是直接在高风险公共议题下测试。\\n\\n## 使用边界\\n\\n不要用行为实验测试泄露隐私、挑衅网暴、医疗风险或现实安全。社交焦虑严重、存在创伤或强烈惊恐时，实验应与专业人员共同设计。', '理智上知道预测可能过度，但仅靠劝自己仍无法相信时。', '参考：Clément等，2019，行为实验研究；McManus等，2009，社会焦虑认知治疗成分实验。', 1, 1, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (238, 4, '分级暴露：逐步面对发布与互动焦虑', '## 方法是什么\\n\\n分级暴露是按照难度阶梯，逐步接触被焦虑回避的情境，并停留到能够获得新经验。对社交媒体而言，目标不是增加使用时长，而是减少“因为害怕评价而完全不敢正常表达”的回避。\\n\\n## 怎么使用\\n\\n先列出场景并评0—100难度，例如：\\n\\n- 给熟悉朋友点赞：20\\n- 在小群发普通消息：35\\n- 发布仅好友可见的日常：50\\n- 在公开区表达温和观点：75\\n\\n从中等偏低难度开始，重复练习，观察真实结果和焦虑变化，再逐步上移。暴露时尽量不使用过多安全行为，例如反复删改、请所有人提前保证会支持。\\n\\n## 社交媒体场景示例\\n\\n害怕发动态的人，不需要直接公开长文。可以先发一条低敏感、有限可见的普通内容，允许它保留一段时间，再记录预期与实际反馈。\\n\\n## 使用边界\\n\\n暴露不是硬扛，也不适用于现实中确有骚扰、隐私或职业风险的情境。若涉及创伤、惊恐、自伤风险或严重功能受损，应由专业人员评估和设计。\\n\\n补充提醒：每一级都应允许重复和退回；焦虑暂时升高不代表练习失败，但持续失控时应停止并求助。', '因为害怕被评价，已经无法进行必要的群聊、表达或正常发布时。', '参考：Ougrin，2011，暴露与认知治疗元分析；NICE CG159，社会焦虑个体CBT。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (239, 4, '减少安全行为：不再靠反复润色获得安全感', '## 方法是什么\\n\\n安全行为是为了防止被否定而采取的保护动作，例如一条消息修改二十遍、发布后立即删除、只说绝对不会出错的话、不断请朋友确认。它们短期降低焦虑，却可能让人无法知道：“即使不做这些，我也许仍能应对。”\\n\\n## 怎么使用\\n\\n先列出自己常用的安全行为，并区分必要保护与过度保护。一次只减少一个，例如：\\n\\n- 将修改次数从十次降到三次。\\n- 不再要求朋友发布前逐句审阅。\\n- 发出普通消息后允许自己暂时离开对话框。\\n- 不用自嘲提前否定自己来阻止别人评价。\\n\\n完成后记录预测、真实反馈和焦虑变化。\\n\\n## 社交媒体场景示例\\n\\n你担心群友觉得自己无聊，于是每句话后都加“哈哈我乱说的”。实验可以是在低风险群聊中发一次直接、普通的观点，不用自我贬低收尾。\\n\\n## 使用边界\\n\\n隐私设置、屏蔽骚扰和事实核查不是需要消除的安全行为。只减少那些主要用于缓解焦虑、却长期限制正常表达的动作。严重社交焦虑应在专业支持下练习。', '发消息或动态前必须不断修改、求确认或自我贬低，否则无法发送时。', '参考：McManus等，2008；Taylor与Alden，2010；Schreiber等，2015。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (240, 4, '延迟检查：打断反复刷新反馈的循环', '## 方法是什么\\n\\n反复刷新点赞、评论、在线状态和数据后台，常由“不检查就无法确定是否安全”的冲动推动。延迟检查不是永久禁止查看，而是在冲动与动作之间加入可控间隔，观察焦虑是否能够在不立即确认的情况下自然变化。\\n\\n## 怎么使用\\n\\n1. 记录平时发布后多久检查一次。\\n2. 设定略长但可完成的间隔，例如从每2分钟改为10分钟。\\n3. 冲动出现时记录强度，不立刻争辩，也不马上打开。\\n4. 到约定时间再查看一次，而不是连续刷新。\\n5. 稳定后逐步延长间隔，或减少每日固定检查次数。\\n\\n## 社交媒体场景示例\\n\\n发布内容后，你预测“十分钟不看就会错过重要评论”。练习时把手机放在视线外，记录焦虑从80变化到多少，再在约定时间统一查看。\\n\\n## 使用边界\\n\\n工作值班、紧急联络和需要及时处理的客服任务不适合机械延迟。若检查行为已经占用大量时间、影响睡眠或具有明显强迫性质，应寻求专业评估。\\n\\n补充提醒：练习应从可承受的短间隔开始；目标是增加选择空间，而不是用另一套严格规则惩罚自己。', '发布后不断刷新点赞、评论、在线状态或后台数据，明知疲惫却停不下来时。', '参考：Curtiss等，2021，焦虑CBT中的行为实验与暴露原则；NICE CG159。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (241, 4, '外部注意训练：把注意从自我监控移回交流', '## 方法是什么\\n\\n评价焦虑时，人可能把大量注意放在“我看起来怎样、这句话会不会很蠢、别人是否发现我紧张”，导致交流信息反而进入不了大脑。外部注意训练把注意重新放回对方内容、任务和环境线索。\\n\\n## 怎么使用\\n\\n在线交流前设定一个外部任务：\\n\\n- 找出对方表达的两个核心观点。\\n- 注意聊天中实际出现的语气与信息，而不是想象中的评价。\\n- 回应内容本身，而不是不断检查自己的措辞形象。\\n- 交流后列出三个真实观察，不写推测。\\n\\n还可以在低风险对话中比较“高度自我监控”和“关注交流内容”两种状态的体验差异。\\n\\n## 社交媒体场景示例\\n\\n参加线上会议时，你一直盯着自己的摄像头画面。练习可以隐藏自我预览，把注意放到发言者的论点，并在会后记录自己实际记住了什么。\\n\\n## 使用边界\\n\\n注意训练不是忽略真实危险或他人的明确攻击。它主要适用于因过度自我聚焦而加重的评价焦虑。注意偏向矫正的独立疗效证据有限，不应宣传为通用治疗。', '线上开会、群聊或发言时，全部注意都放在自己表现是否难看上时。', '参考：McManus等，2009；Furukawa等，2009；Heeren等，2015注意偏向矫正元分析。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (242, 4, '视频或录音反馈：校准过度负面的自我印象', '## 方法是什么\\n\\n评价焦虑会让人凭内部感受判断外在表现：心跳很快，就觉得所有人都看出自己失控；说话卡顿一下，就记成“整段表现都很糟”。视频或录音反馈用于比较预测、主观感受和真实记录。\\n\\n## 怎么使用\\n\\n在低风险场景中完成一段短发言或语音，事前写下具体预测，例如“我会停顿超过十次、声音明显发抖”。观看或收听前，先尝试以中性观察者角度记录可见事实，再与预测比较。\\n\\n观察时只描述：\\n\\n- 实际停顿次数\\n- 声音是否能听清\\n- 内容是否表达完整\\n- 他人是否出现明确负面反应\\n\\n避免反复放大外貌细节或无限回看。\\n\\n## 社交媒体场景示例\\n\\n你认为自己的线上发言“紧张得无法看”。回看后可能发现有两次停顿，但内容完整、语速基本正常。新的结论不是“我完美”，而是“内部紧张感比外部表现更强”。\\n\\n## 使用边界\\n\\n身体意象困扰、外貌强迫检查或创伤相关问题可能因录像加重，不宜自行反复观看。最好限定次数，严重焦虑时由专业人员引导。', '总觉得自己在视频、语音或直播中表现得极其糟糕，却主要依据内部感觉判断时。', '参考：McManus等，2009；Furukawa等，2009，视频反馈与社会焦虑实验。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (243, 4, '行为激活：从刷屏后的回避中重新行动', '## 方法是什么\\n\\n被比较内容打击后，有些人会停止学习、运动、社交和基本照顾，转而继续刷屏或躺着回避。行为激活不是等待心情好了再做事，而是安排小而具体、与生活价值相关的活动，让行动重新带来环境反馈。\\n\\n## 怎么使用\\n\\n先记录一天中的活动与情绪，找出“刷屏—低落—回避—更低落”的循环。随后分别安排：\\n\\n- **必要活动**：洗澡、吃饭、完成一个最小任务。\\n- **愉悦活动**：散步、音乐、线下兴趣。\\n- **掌控活动**：整理桌面、回复一封邮件、学习15分钟。\\n\\n任务要小到当下能开始，完成后记录情绪和掌控感，而不是只看是否“效率很高”。\\n\\n## 社交媒体场景示例\\n\\n看到同龄人成就后，你放弃原定学习并继续刷两小时。行为激活可以是先离开床铺、完成十分钟复习，再决定下一步，而不是制定极端逆袭计划。\\n\\n## 使用边界\\n\\n行为激活对抑郁的证据更充分，对焦虑也可能有帮助，但不能替代对严重抑郁、自伤风险或功能明显受损的专业治疗。', '刷完比较内容后陷入低落和瘫痪，越不行动越觉得自己失败时。', '参考：Stein等，2021，行为激活对抑郁、焦虑及活动水平的元分析。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (244, 4, '结构化问题解决：区分能处理的问题与情绪噪声', '## 方法是什么\\n\\n结构化问题解决适用于现实中确实存在、可以采取行动的问题，例如账号被骚扰、合作边界不清、社交媒体占用学习时间。它避免把所有困扰都当成“想法问题”，也避免在焦虑中同时解决十件事。\\n\\n## 怎么使用\\n\\n1. 用一句话定义问题，避免写成“我的人生很失败”。\\n2. 区分可控制、可影响和暂时不可控制的部分。\\n3. 不评判地列出多个方案。\\n4. 比较成本、风险和可行性。\\n5. 选择一个最小步骤，规定时间。\\n6. 执行后复盘结果，再调整方案。\\n\\n## 社交媒体场景示例\\n\\n问题不是“我自控力太差”，而是“睡前一小时反复打开短视频，导致入睡推迟”。可选方案包括调整充电位置、使用系统限制、替换睡前活动或请同住者协助。具体设置属于行动建议，问题解决法负责选择和评估。\\n\\n## 使用边界\\n\\n无法控制的事情不适合无限制定方案，例如要求所有人喜欢自己。涉及网暴、诈骗、隐私泄漏或现实威胁时，应优先使用平台、法律和安全资源。', '困扰中既有真实可处理问题，也有大量反复担忧，导致不知道先做什么时。', '参考：Zhang等，2018，问题解决治疗系统综述与元分析；Curtiss等，2021。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (245, 4, '复发预防：为再次被触发提前写计划', '## 方法是什么\\n\\n情绪改善不等于以后再也不会被触发。复发预防把波动视为可以预期的过程：识别早期信号、总结有效方法、规定何时升级求助。它能减少“我又焦虑了，所以之前所有努力都白费”的二次打击。\\n\\n## 怎么使用\\n\\n建立一页维持计划：\\n\\n- **高风险情境**：考试季、失眠、关系冲突、发布重要内容后。\\n- **早期信号**：刷新次数增加、睡前刷屏、开始搜索比较对象。\\n- **已验证有效的方法**：四步记录、证据检查、延迟检查、线下活动。\\n- **需要避免的旧循环**：通宵搜索、冲动删号、与陌生人持续争辩。\\n- **升级标准**：连续多久影响睡眠或功能时联系谁、寻求何种帮助。\\n\\n## 社交媒体场景示例\\n\\n你已经减少数据检查，但重要作品发布时又开始频繁刷新。计划提醒你：先按固定时间查看，若两天内严重失眠或无法工作，就联系可信任的人或专业支持，而不是解释成彻底失败。\\n\\n## 使用边界\\n\\n维持计划不是保证不会复发，也不能替代危机处理。若出现自伤想法、明显危险或无法维持基本生活，应立即寻求当地紧急和专业帮助。', '状态好转后担心以后再次被社交媒体触发，或一次反复就觉得全部失败时。', '参考：Levy等，2021，焦虑CBT复发率元分析；Lorimer等，2021，复发预测因素综述。', 1, 1, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (246, 5, '先停两分钟：把信息流从眼前移开', '## 什么时候使用\\n\\n刚看到一条让你强烈比较、愤怒、恐慌或羞耻的内容，手已经在继续下滑、搜索或点进评论区时。\\n\\n## 立即步骤\\n\\n1. 停止继续刷，不急着分析内容对不对。\\n2. 把手机屏幕扣下、锁屏或放到伸手够不到的位置。\\n3. 双脚接触地面，慢慢说出当前地点和时间，例如：“我现在在宿舍，晚上十点，这条内容已经结束了。”\\n4. 环顾周围，找出三个不会移动的物体。\\n5. 两分钟后再决定是退出、保存稍后看，还是继续处理。\\n\\n## 为什么这样做\\n\\n情绪被快速内容勾住时，继续输入往往会增加刺激量，让大脑更难分辨“眼前信息”和“现实环境”。短暂停止并重新定向，不是逃避问题，而是先把选择权拿回来。\\n\\n## 使用边界\\n\\n这一步不要求你永久戒掉平台，也不保证情绪立刻消失。若内容涉及现实威胁、隐私泄露或需要及时保存的证据，应先完成必要取证，再离开信息流。', '被一条内容明显触发后，仍在机械下滑、搜同类内容或反复看评论时。', '参考：WHO，2020《Doing What Matters in Times of Stress》中的着陆与减速练习。', 1, 1, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (247, 5, '5-4-3-2-1五感着陆法', '## 什么时候使用\\n\\n脑中不断重播社交媒体画面、感觉“整个人被吸进去了”、注意力很难回到现实环境时。\\n\\n## 立即步骤\\n\\n按顺序寻找并说出：\\n\\n1. **5样看见的东西**：颜色、形状、位置。\\n2. **4样身体接触到的感觉**：脚底、衣服、椅背、手心。\\n3. **3种听见的声音**：近处、远处、持续的声音。\\n4. **2种闻到的气味**：没有明显气味时，可以注意空气或衣物气味。\\n5. **1种尝到的味道**：也可以喝一小口水，注意口腔感觉。\\n\\n每一步只描述感觉，不解释它好不好。\\n\\n## 为什么这样做\\n\\n五感着陆把注意从脑内的预测、比较和回放，重新连接到此刻可观察的环境。它的目标是增加“我在这里”的感觉，而不是证明焦虑不合理。\\n\\n## 使用边界\\n\\n如果某一种感官会引发不适，可以跳过或改用其他感官。出现明显解离、创伤闪回或无法确认自身安全时，应寻求他人和专业帮助。', '焦虑画面在脑中循环、注意力飘离现实，或感觉周围不够真实时。', '参考：WHO压力管理指南；Royal Berkshire NHS，2024，焦虑着陆技巧。', 1, 1, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (248, 5, '双脚着地与接触点确认', '## 什么时候使用\\n\\n刷到刺激内容后心里发飘、身体僵住、手脚发紧，或者很难把注意力从手机移开时。\\n\\n## 立即步骤\\n\\n1. 坐稳或站稳，把双脚完整放在地面。\\n2. 轻轻向下施力5秒，感受脚底受力，再放松。\\n3. 注意三个接触点，例如脚底与地面、背部与椅背、手掌与大腿。\\n4. 用一句话描述每个感觉：“脚底有压力”“椅背在支撑我”“手掌是温热的”。\\n5. 轻轻移动脚趾和手指，让身体确认自己可以主动行动。\\n\\n## 为什么这样做\\n\\n强烈焦虑常把注意推向手机内容、未来预测或身体异常感。确认支撑点和主动动作，可以帮助重新建立对当前位置与身体边界的感知。\\n\\n## 使用边界\\n\\n不需要用力踩地或让身体疼痛。若有受伤、眩晕或站立不稳，应坐下进行。持续胸痛、晕厥或严重呼吸困难不能仅按焦虑处理，应及时求助医疗服务。', '感觉发飘、身体僵硬，或心神完全被屏幕内容拖走时。', '参考：WHO，2020，Grounding；VA关于当下定向与身体感觉的建议。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (249, 5, '舒适慢呼吸：不憋气、不强迫深呼吸', '## 什么时候使用\\n\\n焦虑上升后呼吸变快、肩膀抬高、胸口紧，越想“深呼吸”越觉得喘不过来时。\\n\\n## 立即步骤\\n\\n1. 坐稳，放松肩膀和上胸部。\\n2. 让气息自然进入，不追求吸得特别满。\\n3. 用鼻子轻轻吸气，用鼻子或嘴缓慢呼气。\\n4. 可以舒适地数“吸1、2、3，呼1、2、3”，无法数到3也没有关系。\\n5. 连续做1—3分钟；若头晕或更不舒服，立即恢复自然呼吸。\\n\\n## 为什么这样做\\n\\n焦虑时用力吸气、频繁叹气或过快呼吸可能让头晕和胸闷更明显。练习重点是把呼吸恢复为舒适、规律的节奏，而不是吸入尽可能多的空气。\\n\\n## 使用边界\\n\\n不要套用必须憋气的固定节奏，也不要强迫自己坚持。首次出现的严重胸痛、明显呼吸困难、晕厥或疑似医疗急症，应及时就医。', '焦虑后呼吸越来越急，或越刻意深呼吸越头晕、胸闷时。', '参考：NHS呼吸练习；Cambridge University Hospitals，过度换气呼吸指导。', 1, 1, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (250, 5, '肩膀、下颌与手掌三点放松', '## 什么时候使用\\n\\n看完评论争论或比较内容后，发现自己咬紧牙、耸肩、攥拳，身体一直保持“准备应战”的姿势时。\\n\\n## 立即步骤\\n\\n1. **肩膀**：吸气时轻轻抬起，呼气时让肩膀自然下落，不要猛压。\\n2. **下颌**：上下牙齿稍微分开，让舌头自然放松。\\n3. **手掌**：先轻握拳2—3秒，再慢慢展开手指。\\n4. 比较紧张和放松时的感觉差异。\\n5. 重复两轮，然后让呼吸恢复自然。\\n\\n## 为什么这样做\\n\\n情绪急升时，身体紧张可能持续向大脑传递“危险仍在”的信号。先处理最常见的三个紧张部位，可以降低身体负荷，为后续判断和行动留出空间。\\n\\n## 使用边界\\n\\n动作应轻柔，不要在疼痛、关节受伤或肌肉痉挛处用力。身体放松不能替代对现实骚扰、威胁或医疗问题的处理。', '刷完争议内容后肩颈发硬、咬紧牙关或双手一直攥紧时。', '参考：NHS渐进性肌肉放松资源；VA创伤压力应对建议。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (251, 5, '一分钟迷你渐进性肌肉放松', '## 什么时候使用\\n\\n焦虑主要表现为全身绷紧、坐立不安，单纯告诉自己“放松”没有效果时。\\n\\n## 立即步骤\\n\\n依次选择三个部位，每个部位只做一次：\\n\\n1. 双手轻握拳3秒，然后放开6秒。\\n2. 双肩轻轻抬起3秒，然后放下6秒。\\n3. 双脚轻压地面3秒，然后完全松开6秒。\\n4. 每次放松时，注意紧张和松弛之间的差别。\\n5. 最后安静坐10秒，不再继续用力。\\n\\n## 为什么这样做\\n\\n渐进性肌肉放松通过主动制造轻微紧张，再体验释放，帮助人识别自己原本没有觉察到的身体用力。迷你版本适合当下稳定，不代替完整训练。\\n\\n## 使用边界\\n\\n不要屏住呼吸，也不要用最大力量。疼痛、肌肉损伤、抽筋风险或医生要求避免用力的部位应跳过。若练习让身体感觉更不舒服，可改用被动放松。', '全身绷紧、坐立不安，又很难直接让肌肉松下来时。', '参考：Royal Brompton NHS放松资源；Birmingham and Solihull NHS渐进性肌肉放松指南。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (252, 5, '给情绪一个准确名字', '## 什么时候使用\\n\\n只觉得“很难受”或“我要炸了”，分不清是焦虑、羞耻、嫉妒、愤怒、委屈还是孤独时。\\n\\n## 立即步骤\\n\\n1. 先写：“我现在感到……”\\n2. 从最接近的词中选一个，不要求完美准确。\\n3. 再补充强度：轻微、中等、强烈，或0—100分。\\n4. 写出身体位置：“焦虑在胸口，羞耻像脸发热。”\\n5. 最后加一句：“我正在经历这种情绪，不等于我就是这种情绪。”\\n\\n## 为什么这样做\\n\\n把感受转化成词语，能让混在一起的体验变得更清晰。实验研究提示，情绪命名可能帮助调节部分人的主观痛苦，但效果会受到时机和强度影响。\\n\\n## 使用边界\\n\\n情绪命名不是要求你分析原因，也不保证命名后立即平静。若找不到准确词，可以写“混乱、过载、不确定”。强烈创伤反应时，不要强迫自己详细描述。', '被内容触发后只剩一团强烈难受，不知道自己到底在怕什么或气什么时。', '参考：Lieberman等，2011；Levy-Gigi等，2022，情绪命名实验研究。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (253, 5, '三句现实定向：我在哪、发生了什么、现在安全吗', '## 什么时候使用\\n\\n信息流中的灾难、网暴或关系内容让你感觉事情正在眼前发生，身体进入强烈警报状态时。\\n\\n## 立即步骤\\n\\n缓慢说出三句话：\\n\\n1. **我在哪里**：“我现在坐在自己的房间里。”\\n2. **实际发生了什么**：“我刚刚在手机上看到一段内容。”\\n3. **此刻的安全状况**：“现在没有人正在房间里攻击我；我可以关掉屏幕并寻求帮助。”\\n\\n然后再说出日期、时间和身边一个可信任的人或可用资源。\\n\\n## 为什么这样做\\n\\n强烈内容可能压缩时间和距离，让大脑把屏幕信息体验成正在发生的直接威胁。现实定向通过地点、时间和事实重新建立当前情境。\\n\\n## 使用边界\\n\\n如果你此刻确实处在现实危险、被跟踪、被威胁或需要紧急医疗帮助的环境中，不要用“我很安全”强行覆盖事实，应立即转移到安全地点并联系相应支持。', '看完灾难、冲突或网暴内容后，身体像危险正在身边发生一样高度警觉时。', '参考：VA National Center for PTSD，当下定向与安全提醒；WHO着陆练习。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (254, 5, 'ABC环境搜索：用字母找回注意力', '## 什么时候使用\\n\\n脑中反复想同一条评论、同一个人或同一场争论，五感练习又显得太复杂时。\\n\\n## 立即步骤\\n\\n1. 环顾房间，寻找一个以A音或A字母开头的物品。\\n2. 再找B、C，依次继续。\\n3. 找不到时可以跳过，也可以改成按颜色搜索：红色、蓝色、绿色。\\n4. 每找到一件，就描述一个客观特征，例如“蓝色杯子，圆形”。\\n5. 做到注意力不再完全黏在原内容上即可，不必完成全部字母。\\n\\n## 为什么这样做\\n\\n环境搜索给大脑一个简单而具体的外部任务，减少对内部画面和预测的持续加工。它适合不想闭眼、也不想关注呼吸的人。\\n\\n## 使用边界\\n\\n这不是测试记忆力，找不到不代表失败。若你正在驾驶、过马路或操作设备，应优先确保现实安全，不要分散必要注意力。', '脑中不断重播评论和争论，需要一个简单外部任务打断循环时。', '参考：Kent Community Health NHS，2024，A-B-C around the room。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (255, 5, '冷静事实卡：只写三条可确认的信息', '## 什么时候使用\\n\\n情绪上来后，脑中同时出现大量“他一定”“所有人”“以后永远”等推断，短时间内无法做完整认知分析时。\\n\\n## 立即步骤\\n\\n打开纸张或备忘录，只写三条：\\n\\n1. **我确认发生的事实**：例如“对方两小时没有回复。”\\n2. **我无法确认的部分**：例如“我不知道原因，也不知道对方此刻在做什么。”\\n3. **现在不必决定的事**：例如“我不用今晚决定这段关系是否结束。”\\n\\n读一遍后，把进一步判断推迟到情绪下降之后。\\n\\n## 为什么这样做\\n\\n急性焦虑时不适合完成复杂的证据表。三条事实卡用最少文字区分已知、未知和暂缓决定的部分，减少在高唤醒状态下作出永久结论。\\n\\n## 使用边界\\n\\n如果存在明确的现实危险或必须立即处理的时限，不应一概推迟。事实卡也不是替对方不当行为辩护，而是避免在信息不足时扩大结论。', '已读不回、低互动或争议内容让你想立刻删号、绝交或公开回击时。', '参考：WHO，2020，脱钩与当下行动原则；VA心理急救中的稳定与实际帮助框架。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (256, 5, '十分钟延迟回应：先不回怼、不删帖、不做重大决定', '## 什么时候使用\\n\\n看到恶评、冲突消息或低数据后，强烈想立即回怼、删帖、拉黑所有人、冲动消费或做其他不可逆决定时。\\n\\n## 立即步骤\\n\\n1. 告诉自己：“我不是永远不处理，只延迟十分钟。”\\n2. 把要发送的话先写在草稿，不点击发送。\\n3. 在十分钟内完成一项身体或感官练习，例如慢呼吸、脚底着地或环境搜索。\\n4. 十分钟后重新读草稿，删除攻击性和无法证实的推断。\\n5. 若情绪仍在80分以上，再延迟一次，或请可信任的人帮助查看。\\n\\n## 为什么这样做\\n\\n高唤醒会缩小注意范围，让人更重视立即释放而忽略长期后果。短延迟为情绪自然波动和重新评估留下时间，不等于压抑表达。\\n\\n## 使用边界\\n\\n正在遭受持续骚扰时，可以立即使用平台的屏蔽、举报和证据保存功能；延迟的是冲动性公开回应，不是必要的安全保护。', '被恶评或冲突信息激怒，手已经放在发送、删帖或冲动操作按钮上时。', '参考：WHO压力管理中的减速、脱钩与微小行动；VA压力急救稳定原则。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (257, 5, '短暂身体移动：站起、伸展、走到另一个位置', '## 什么时候使用\\n\\n坐在原地刷屏越刷越僵，情绪和身体姿势像被固定住，继续思考也没有新信息时。\\n\\n## 立即步骤\\n\\n1. 锁屏并确认周围安全。\\n2. 缓慢站起，伸展手臂或转动肩膀。\\n3. 走到房间另一端、窗边或洗手台。\\n4. 注意脚步、地面和视野变化，不需要剧烈运动。\\n5. 到达新位置后，再做一次事实确认：“我已经离开刚才的刷屏位置。”\\n\\n## 为什么这样做\\n\\n改变姿势和位置可以打断“同一屏幕—同一姿势—同一想法”的循环，也能帮助注意回到身体与环境。这里的目标是短暂重置，不是靠运动压掉所有情绪。\\n\\n## 使用边界\\n\\n眩晕、受伤或站立不稳时应坐着伸展。不要在极度激动时进行高强度运动，也不要把移动当成逃避必须处理的现实安全问题。\\n\\n补充提醒：练习只需做到注意力稍微回到现实，不必追求立刻完全平静；不适合时可以直接更换另一种方法。', '长时间盯着屏幕、身体僵硬，情绪和想法都卡在原地时。', '参考：WHO着陆练习中的身体移动与伸展；VA创伤压力应对中的伸展和活动建议。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (258, 5, '找一个人陪你三分钟：只连接，不急着分析', '## 什么时候使用\\n\\n情绪已经很强，一个人反复刷、反复想，越分析越孤立，希望有人帮助你稳定下来时。\\n\\n## 立即步骤\\n\\n给可信任的人发一条具体请求：\\n\\n> “我刚被网上的内容触发了，现在有点慌。你不用分析对错，可以陪我通话或发消息三分钟吗？”\\n\\n连接后可以：\\n\\n1. 告诉对方你现在在哪里。\\n2. 请对方用平稳语气和你聊现实中的简单事情。\\n3. 一起做一次缓慢呼气或环境搜索。\\n4. 情绪稍降后，再决定要不要讲完整经过。\\n\\n## 为什么这样做\\n\\n社会连接是压力恢复的重要保护因素。急救阶段的重点不是立刻得到完美建议，而是减少孤立感、恢复安全和现实联系。\\n\\n## 使用边界\\n\\n选择尊重边界、不会羞辱或煽动你的人。若身边没有合适对象，可以联系学校、单位或当地专业支持。出现自伤想法或现实危险时，不应只依赖普通朋友。', '一个人越刷越慌、越想越失控，需要现实中的人帮助稳定时。', '参考：VA Stress First Aid与Psychological First Aid中的连接和社会支持原则。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (259, 5, '恐慌浪潮提示卡：提醒自己它会变化', '## 什么时候使用\\n\\n突然心跳很快、发抖、胸闷、强烈想逃离，担心自己会立刻失控或永远停不下来时。\\n\\n## 立即步骤\\n\\n提前或当下读一张简短提示卡：\\n\\n- “我现在正经历一阵强烈焦虑。”\\n- “感觉很可怕，但感觉会变化。”\\n- “我先让呼吸保持舒适，不用吸得很深。”\\n- “我可以坐稳、看周围、联系一个人。”\\n- “十分钟后再评估，不在最高点做重大决定。”\\n\\n同时使用双脚着地或环境搜索，不必同时完成很多技巧。\\n\\n## 为什么这样做\\n\\n恐慌时，大脑容易把身体感觉解释成不断升级的灾难。提示卡减少现场组织语言的负担，并帮助你把注意放在当下可做的步骤。\\n\\n## 使用边界\\n\\n不能把所有胸痛、呼吸困难或晕厥都归因于恐慌。症状首次出现、明显异常、持续加重或伴随医疗危险信号时，应及时求助医疗服务。', '突然出现强烈身体警报，担心自己马上失控或症状永远不会结束时。', '参考：VA创伤压力反应应对；Kent NHS恐慌发作患者指南。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (260, 5, '稳定后的一个最小动作', '## 什么时候使用\\n\\n情绪已经从最高点稍微下降，但仍然发空、无力，不知道接下来该继续刷、躺着还是处理事情时。\\n\\n## 立即步骤\\n\\n从以下类别只选一个两分钟内能开始的动作：\\n\\n- **照顾身体**：喝水、洗脸、吃一小份正常食物。\\n- **恢复环境**：打开灯、拉开窗帘、整理桌面一小块。\\n- **恢复任务**：打开文档，只写标题；拿出书，只读一页。\\n- **恢复连接**：回复一个安全、简单的现实消息。\\n\\n动作完成后先停，不要求立刻恢复高效率。\\n\\n## 为什么这样做\\n\\n急救后的空档很容易再次回到信息流。一个最小动作把稳定感连接到现实生活，让“我能做一点事情”的体验重新出现。\\n\\n## 使用边界\\n\\n这不是效率挑战，也不要因为只完成很小的动作而批评自己。若基本进食、睡眠、学习或工作长期无法维持，应考虑寻求专业支持。', '情绪稍微稳定后仍感到空白，容易重新打开平台继续刷时。', '参考：WHO，2020，着陆后按价值采取小行动；VA压力急救中的效能与实际帮助。', 1, 0, NULL, NULL, '2026-06-17 15:19:38', '2026-06-17 15:19:38');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (261, 6, '先做三天使用基线，不凭感觉定目标', '## 要解决什么\\n\\n很多人只知道自己“刷得太多”，却不知道问题集中在哪个平台、哪个时段和哪种触发情境。直接设极端限额容易失败，也难判断真正需要调整的部分。\\n\\n## 怎么做\\n\\n连续三天只记录，不急着改变：\\n\\n1. 查看系统屏幕使用时间和各应用时长。\\n2. 记录最常打开平台的三个时段。\\n3. 标记每次使用目的：联系、查信息、放松、逃避任务、比较或反复确认。\\n4. 写下使用后的状态：更轻松、无变化、疲惫或焦虑。\\n5. 三天后只选择一个最明显的问题作为首轮目标。\\n\\n## 判断是否有效\\n\\n你能说清“我要减少什么”，而不是笼统地责怪自己缺乏自控。例如：目标可以是“睡前短视频从45分钟降到25分钟”，而不是“以后绝不玩手机”。\\n\\n## 注意事项\\n\\n屏幕时间是线索，不是健康分数。学习、工作、导航和与重要的人联系也会产生时长；重点应放在是否干扰睡眠、任务、关系和情绪。\\n\\n## 实施建议\\n\\n一次只改一个设置，连续观察至少七天，并记录睡眠、任务完成、情绪和必要联络是否受到影响。若使用时间减少却焦虑、孤独或工作负担明显增加，不要继续加码；先恢复必要功能，再缩小目标或调整方法。', '觉得自己手机用得失控，却不知道究竟哪个平台、时段或行为最需要调整时。', '参考：Olson等，2022，基于反馈与轻推的手机使用干预；WHO/Europe，2025。', 1, 1, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (262, 6, '把目标改成小幅减少，而不是一次清零', '## 要解决什么\\n\\n从每天数小时直接降到零，容易带来强烈不适、错过必要联系或短期反弹。行动建议更适合从可持续的小幅改变开始。\\n\\n## 怎么做\\n\\n1. 用基线确定当前平均使用量。\\n2. 首轮只减少约15%—25%，或减少一个最容易失控的时段。\\n3. 保留必要功能，例如工作群、家人联系和学习资料。\\n4. 连续执行一周，再根据睡眠、情绪和任务完成情况调整。\\n5. 没完成时查看障碍，而不是立刻把目标加倍。\\n\\n## 判断是否有效\\n\\n目标应当让你仍能完成必要联络，同时减少机械刷新、无目的滚动或使用后的明显后悔。有效不等于每天完全一致，而是总体趋势更可控。\\n\\n## 注意事项\\n\\n研究对减少使用的平均效果总体谨慎积极，但不同干预、不同人群结果并不完全一致。不要把单一时长阈值当作所有人的标准，也不要因偶尔超时认定计划失败。\\n\\n## 实施建议\\n\\n一次只改一个设置，连续观察至少七天，并记录睡眠、任务完成、情绪和必要联络是否受到影响。若使用时间减少却焦虑、孤独或工作负担明显增加，不要继续加码；先恢复必要功能，再缩小目标或调整方法。', '多次尝试彻底戒断后迅速反弹，开始怀疑自己没有自制力时。', '参考：Plackett等，2023系统综述；Pieh等，2025随机试验；Wadsley等，2023。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (263, 6, '设置固定查看窗口，代替全天候随时检查', '## 要解决什么\\n\\n持续在线不一定来自单次使用很久，而可能来自一天中反复、短促地打开平台。固定窗口把“随时可能检查”改为“我知道下一次何时查看”。\\n\\n## 怎么做\\n\\n1. 根据工作和关系需求选择每天2—4个查看窗口。\\n2. 每个窗口集中处理消息、动态和必要通知。\\n3. 窗口之外出现冲动时，把要查的事情记在备忘录，而不是立刻打开。\\n4. 对重要联系人保留电话或其他紧急通道。\\n5. 一周后调整窗口数量，不必机械保持。\\n\\n## 判断是否有效\\n\\n工作、学习或休息时的自发解锁次数下降，同时没有明显错过必须处理的信息。重点是减少不可预测的中断，不是故意延迟所有回复。\\n\\n## 注意事项\\n\\n需要值班、客服或照护责任的人不适合完全固定时段。可以按联系人和应用设置例外，让真正紧急的信息保留即时通道。\\n\\n## 实施建议\\n\\n一次只改一个设置，连续观察至少七天，并记录睡眠、任务完成、情绪和必要联络是否受到影响。若使用时间减少却焦虑、孤独或工作负担明显增加，不要继续加码；先恢复必要功能，再缩小目标或调整方法。', '每隔几分钟就想看一次消息，全天都感觉自己在等通知时。', '参考：Fitz等，2019，通知分批研究；Ohly与Bastin，2023，通知中断实验。', 1, 1, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (264, 6, '把通知分批送达，而不是全部关闭', '## 要解决什么\\n\\n所有通知实时出现会持续打断注意；但一次性完全关闭也可能让部分人更焦虑，转而主动检查得更频繁。分批送达提供了中间方案。\\n\\n## 怎么做\\n\\n1. 保留电话、家人、重要工作等紧急通知。\\n2. 将社交平台、资讯和购物通知设为定时摘要或集中查看。\\n3. 若系统没有摘要功能，可以只保留角标，关闭声音和震动。\\n4. 每天选择固定时段统一处理。\\n5. 观察一周：注意力、FOMO和主动解锁是否变化。\\n\\n## 判断是否有效\\n\\n通知造成的即时打断减少，同时你不会因为完全失去提醒而更加紧张。若主动检查明显增加，可以缩短批次间隔，而不是立即恢复全部推送。\\n\\n## 注意事项\\n\\n通知管理本身未必自动减少屏幕时间。随机试验显示，单纯关闭通知可能改变主观控制感，却不一定改变使用行为，因此最好与查看窗口和访问摩擦同时使用。\\n\\n## 实施建议\\n\\n一次只改一个设置，连续观察至少七天，并记录睡眠、任务完成、情绪和必要联络是否受到影响。若使用时间减少却焦虑、孤独或工作负担明显增加，不要继续加码；先恢复必要功能，再缩小目标或调整方法。', '通知太多影响专注，但全部关闭后又更担心错过消息时。', '参考：Fitz等，2019；Dekker等，2025，关闭通知随机试验。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (265, 6, '用专注模式保护学习和工作时段', '## 要解决什么\\n\\n临时靠意志力抵抗每一次通知，会让注意力不断在任务和手机之间切换。专注模式通过环境设置预先减少选择次数。\\n\\n## 怎么做\\n\\n1. 选择一个明确时段，例如45分钟学习或90分钟深度工作。\\n2. 只允许电话、日历和必要工作应用。\\n3. 把社交平台、资讯和购物应用设为静默。\\n4. 手机放到视线外，但保留紧急联系例外。\\n5. 时段结束后集中查看，而不是任务中途“只看一眼”。\\n\\n## 判断是否有效\\n\\n任务中断和解锁次数减少，结束后也不需要用更长时间补偿性刷屏。可以从短时段开始，不必一上来设置半天。\\n\\n## 注意事项\\n\\n专注模式不能解决任务本身过难、焦虑或疲劳。若你总在同一任务上逃向手机，还需要缩小任务、休息或使用问题解决方法。\\n\\n## 实施建议\\n\\n一次只改一个设置，连续观察至少七天，并记录睡眠、任务完成、情绪和必要联络是否受到影响。若使用时间减少却焦虑、孤独或工作负担明显增加，不要继续加码；先恢复必要功能，再缩小目标或调整方法。', '学习和工作时总被消息拉走，重新进入状态需要很久时。', '参考：Ohly与Bastin，2023，减少通知中断与任务表现；Olson等，2022。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (266, 6, '睡前留出30分钟无社交媒体缓冲区', '## 要解决什么\\n\\n睡前信息流会延长使用时间，也可能让比较、争论和未完成消息继续占据大脑。设置缓冲区比要求整晚不用手机更具体。\\n\\n## 怎么做\\n\\n1. 选择固定的“最后查看时间”，先从睡前30分钟开始。\\n2. 在此之前处理必要消息，并告知重要联系人夜间联系方式。\\n3. 到点后退出社交平台，不再打开推荐流和评论区。\\n4. 用固定替代活动衔接，例如洗漱、纸质阅读、音乐或简单整理。\\n5. 连续尝试两周，再决定是否延长。\\n\\n## 判断是否有效\\n\\n入睡前的刷屏时间、脑内争论和临时回复减少。评估时关注入睡速度、睡眠时长和第二天精神，不只看是否百分之百遵守。\\n\\n## 注意事项\\n\\n一项小型随机试验发现睡前30分钟限制手机使用改善了部分睡眠指标，但样本有限。持续严重失眠仍应按睡眠问题寻求专业帮助。\\n\\n## 实施建议\\n\\n一次只改一个设置，连续观察至少七天，并记录睡眠、任务完成、情绪和必要联络是否受到影响。若使用时间减少却焦虑、孤独或工作负担明显增加，不要继续加码；先恢复必要功能，再缩小目标或调整方法。', '本来准备睡觉，却因动态、消息或评论区不断推迟入睡时。', '参考：He等，2020睡前手机限制试验；APA，2023健康建议。', 1, 1, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (267, 6, '让手机离开床铺和枕边', '## 要解决什么\\n\\n手机放在枕边会让夜间查看变得几乎没有成本。即使已经设定睡前时间，伸手就能打开也容易恢复旧循环。\\n\\n## 怎么做\\n\\n1. 将充电位置移到床外、房间另一侧或门口。\\n2. 若需要闹钟，可使用独立闹钟，或把手机放到必须起身才能关闭的位置。\\n3. 夜间保留重要联系人的铃声例外。\\n4. 上床后不在被窝里处理普通消息。\\n5. 早晨先完成起床和洗漱，再查看推荐流。\\n\\n## 判断是否有效\\n\\n床上解锁次数减少，夜间醒来后不再自动打开平台。若焦虑明显增加，可以先从“离枕头一臂远”逐步移动，而不是一次放到很远。\\n\\n## 注意事项\\n\\n需要夜间照护、医疗监测或紧急值班的人应保留必要设备和通道。目标是增加非必要查看的摩擦，不是牺牲安全。\\n\\n## 实施建议\\n\\n一次只改一个设置，连续观察至少七天，并记录睡眠、任务完成、情绪和必要联络是否受到影响。若使用时间减少却焦虑、孤独或工作负担明显增加，不要继续加码；先恢复必要功能，再缩小目标或调整方法。', '睡前和夜间醒来时会无意识摸到手机继续刷时。', '参考：Tu等，2023，限制床上手机使用；He等，2020。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (268, 6, '建立一个明确的无手机空间', '## 要解决什么\\n\\n如果所有地点都允许刷平台，使用会和吃饭、学习、聊天、洗漱等活动自动绑定。无手机空间通过环境线索建立清晰边界。\\n\\n## 怎么做\\n\\n1. 只选择一个空间，例如餐桌、书桌或卫生间。\\n2. 进入该空间前把手机放在固定位置。\\n3. 对同住者说明规则，避免被误解为故意不回复。\\n4. 必要时保留电话铃声或把紧急联系人加入例外。\\n5. 连续执行一周，再考虑扩展到其他空间。\\n\\n## 判断是否有效\\n\\n该空间中的自动解锁减少，原本被手机打断的活动更完整。无手机区不需要覆盖整个家庭，也不要求所有人使用同一规则。\\n\\n## 注意事项\\n\\n若边界太大导致无法坚持，应缩小到一个具体活动，例如“吃饭前15分钟不看推荐流”。环境设计应降低难度，而不是制造新的道德标准。\\n\\n## 实施建议\\n\\n一次只改一个设置，连续观察至少七天，并记录睡眠、任务完成、情绪和必要联络是否受到影响。若使用时间减少却焦虑、孤独或工作负担明显增加，不要继续加码；先恢复必要功能，再缩小目标或调整方法。', '吃饭、学习和聊天都习惯性拿着手机，活动很难完整进行时。', '参考：Olson等，2022，轻推与环境摩擦；WHO/Europe，2025。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (269, 6, '把高触发应用移出首页并增加打开步骤', '## 要解决什么\\n\\n应用图标、角标和固定手势会让打开平台变成自动动作。增加一两个步骤，可以让“我真的要打开吗”重新进入意识。\\n\\n## 怎么做\\n\\n1. 将最容易失控的应用移出首屏和快捷栏。\\n2. 关闭角标，放进普通文件夹或只通过搜索打开。\\n3. 退出自动登录或使用系统应用限额，增加轻微摩擦。\\n4. 保留必要通讯工具，不要把所有功能同时封锁。\\n5. 每周检查：打开次数是否下降，还是转移到其他应用。\\n\\n## 判断是否有效\\n\\n无目的打开和肌肉记忆式点击减少；需要使用时仍能正常进入。若你只是改刷另一个平台，应重新识别真正的使用目的。\\n\\n## 注意事项\\n\\n增加摩擦比完全删除温和，但也不会对所有人有效。研究显示减少持续联网或使用轻推工具可能改善部分指标，效果仍受个人习惯和替代行为影响。\\n\\n## 实施建议\\n\\n一次只改一个设置，连续观察至少七天，并记录睡眠、任务完成、情绪和必要联络是否受到影响。若使用时间减少却焦虑、孤独或工作负担明显增加，不要继续加码；先恢复必要功能，再缩小目标或调整方法。', '经常在没有明确目的时，仅凭手指习惯打开同一个平台时。', '参考：Olson等，2022；Castelo等，2025，阻断移动互联网随机干预。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (270, 6, '整理关注列表：先静音，再决定是否取关', '## 要解决什么\\n\\n某些账号并非有害，却会在你当前阶段反复触发外貌、学业、消费或关系比较。立即取关可能带来内疚，静音可以先测试影响。\\n\\n## 怎么做\\n\\n1. 列出最近一周刷完后明显变差的账号。\\n2. 区分内容类型：比较触发、灾难信息、营销、冲突或前任动态。\\n3. 先静音7—14天，不需要公开解释。\\n4. 观察情绪、搜索冲动和是否主动回看。\\n5. 到期后决定恢复、继续静音或取关。\\n\\n## 判断是否有效\\n\\n信息流更符合你的实际需要，刷完后的自我攻击或情绪耗竭下降。判断重点是内容对你的影响，不是发布者是否“坏”。\\n\\n## 注意事项\\n\\n静音可能让人主动搜索对方，尤其在关系焦虑中。若出现这种情况，可以把静音与延迟搜索、固定查看或CBT方法结合。\\n\\n## 实施建议\\n\\n一次只改一个设置，连续观察至少七天，并记录睡眠、任务完成、情绪和必要联络是否受到影响。若使用时间减少却焦虑、孤独或工作负担明显增加，不要继续加码；先恢复必要功能，再缩小目标或调整方法。', '某些账号每次出现都会触发比较，但又因人情或关系不想立刻取关时。', '参考：APA，2023，关注内容与个体脆弱性的匹配；Seekis等，2025。', 1, 1, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (271, 6, '主动使用“不感兴趣”、关键词屏蔽和内容过滤', '## 要解决什么\\n\\n推荐流会根据停留、点击、搜索和互动继续学习。只是愤怒观看或反复点开，也可能让同类内容持续出现。\\n\\n## 怎么做\\n\\n1. 遇到明确不想继续接收的内容，使用“不感兴趣”或减少推荐。\\n2. 屏蔽反复触发的关键词、话题或账号。\\n3. 不在触发内容下长时间阅读评论或争辩，以免继续提供行为信号。\\n4. 主动搜索并关注更符合需求的内容，重建信息输入。\\n5. 给调整留出几天，不期待一次操作立刻改变全部推荐。\\n\\n## 判断是否有效\\n\\n推荐流中高触发内容比例逐渐下降，主动搜索和停留也更有目的。若平台过滤能力有限，可改用关注页、收藏夹或暂时退出推荐流。\\n\\n## 注意事项\\n\\n算法具体规则不透明，不应承诺某个操作一定有效。本建议强调减少你主动提供的兴趣信号，并利用平台已有控制选项。\\n\\n## 实施建议\\n\\n一次只改一个设置，连续观察至少七天，并记录睡眠、任务完成、情绪和必要联络是否受到影响。若使用时间减少却焦虑、孤独或工作负担明显增加，不要继续加码；先恢复必要功能，再缩小目标或调整方法。', '主页连续出现同类焦虑内容，明明不喜欢却总会点开或停留时。', '参考：WHO/Europe，2025，数字环境保护；APA，2023，内容风险与数字素养。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (272, 6, '灾难和热点信息只保留少量可靠来源', '## 要解决什么\\n\\n同一事件在多个平台、账号和评论区重复出现，会制造信息很多、但有效信息很少的状态，并不断提高情绪刺激。\\n\\n## 怎么做\\n\\n1. 为重要事件只选择1—2个可靠新闻或官方来源。\\n2. 规定每日查看次数和时间，例如午间、晚间各一次。\\n3. 不把评论区、未经核实截图和二次剪辑当作同等证据。\\n4. 需要行动时，直接查看权威通知或求助渠道。\\n5. 达到当天信息目标后退出，不继续搜索情绪更强的版本。\\n\\n## 判断是否有效\\n\\n你能够获得必要信息，同时减少重复刷新、阴谋推测和情绪化视频输入。目标不是与世界隔绝，而是把“知道发生了什么”与“持续围观”分开。\\n\\n## 注意事项\\n\\n处于真实灾害地区时，应优先关注当地应急、天气、交通和安全通知。本建议不适用于必须实时监测事件的工作职责。\\n\\n## 实施建议\\n\\n一次只改一个设置，连续观察至少七天，并记录睡眠、任务完成、情绪和必要联络是否受到影响。若使用时间减少却焦虑、孤独或工作负担明显增加，不要继续加码；先恢复必要功能，再缩小目标或调整方法。', '同一灾难或热点刷了很多小时，却没有获得新的可行动信息时。', '参考：APA，2023内容风险建议；WHO/Europe，2025数字环境政策简报。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (273, 6, '把短期暂停做成一次有起止点的实验', '## 要解决什么\\n\\n短期暂停可以帮助观察没有平台时的情绪和习惯，但模糊的“我要戒掉”容易变成无限期承诺或失败测试。\\n\\n## 怎么做\\n\\n1. 明确暂停对象：一个平台、推荐流或全部非必要社交媒体。\\n2. 明确时长：24小时、三天或一周。\\n3. 提前保存必要联系人和替代联络方式。\\n4. 写下想观察的指标：焦虑、睡眠、FOMO、专注、孤独和替代活动。\\n5. 到期后复盘，而不是自动永久退出或全部恢复。\\n\\n## 判断是否有效\\n\\n你获得了关于自己使用模式的新信息，例如最难受的时段、真正需要的功能和可以舍弃的内容。结果可以是“暂停有帮助”，也可以是“完全停用增加孤独，需要改为限时使用”。\\n\\n## 注意事项\\n\\n研究显示暂停的平均效应较小且不完全一致，部分人会体验FOMO或连接减少。暂停不是道德测试，也不能替代心理治疗。\\n\\n## 实施建议\\n\\n一次只改一个设置，连续观察至少七天，并记录睡眠、任务完成、情绪和必要联络是否受到影响。若使用时间减少却焦虑、孤独或工作负担明显增加，不要继续加码；先恢复必要功能，再缩小目标或调整方法。', '想知道社交媒体究竟如何影响自己，但不确定是否适合长期停用时。', '参考：Lambert等，2022；Lemahieu等，2025元分析；Wadsley等，2023。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (274, 6, '暂停后分阶段恢复，而不是一次装回全部应用', '## 要解决什么\\n\\n短期暂停结束后若一次恢复所有平台、通知和关注内容，旧环境会迅速回来，也难判断哪个部分真正造成压力。\\n\\n## 怎么做\\n\\n1. 先恢复必要通讯功能。\\n2. 每隔两三天只恢复一个平台或一种功能。\\n3. 首周保持通知关闭或分批送达。\\n4. 记录每个平台恢复后对睡眠、比较和时间的影响。\\n5. 没有明确价值的平台可以继续停用，而不是因“大家都在用”自动恢复。\\n\\n## 判断是否有效\\n\\n你能区分哪些功能带来连接和信息价值，哪些主要制造被动滚动和焦虑。恢复过程越慢，越容易识别真正的触发点。\\n\\n## 注意事项\\n\\n分阶段恢复是行为实验，不要求永久删除。若平台与工作、学习或关系强绑定，可只调整推荐流、通知和查看窗口，而非停用整个应用。\\n\\n## 实施建议\\n\\n一次只改一个设置，连续观察至少七天，并记录睡眠、任务完成、情绪和必要联络是否受到影响。若使用时间减少却焦虑、孤独或工作负担明显增加，不要继续加码；先恢复必要功能，再缩小目标或调整方法。', '暂停结束后担心一恢复就回到原来的刷屏状态时。', '参考：de Hesselle等，2024；Ramadhan等，2024；Plackett等，2023。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (275, 6, '为减少的刷屏时间安排替代活动', '## 要解决什么\\n\\n单纯移除社交媒体会留下空白。若没有替代活动，人在无聊、焦虑或疲惫时往往会重新安装、换平台或用其他屏幕填满时间。\\n\\n## 怎么做\\n\\n1. 找出原本使用平台的主要功能：放松、连接、逃避、获取信息或打发等待。\\n2. 为每种功能准备一个低门槛替代：\\n   - 放松：音乐、散步、洗澡。\\n   - 连接：给一个具体朋友发消息或见面。\\n   - 信息：固定新闻来源。\\n   - 等待：电子书、离线文章或简单游戏。\\n3. 把替代活动提前放在容易看到的位置。\\n4. 每次只要求先做五分钟，再决定是否打开平台。\\n\\n## 判断是否有效\\n\\n减少使用后，不会只剩强烈空虚和无聊；现实活动、睡眠或任务得到实际时间。替代活动应满足原本需求，而不是只被认为“更高尚”。\\n\\n## 注意事项\\n\\n若刷屏主要用于逃避强烈焦虑、抑郁或现实困境，仅更换活动可能不够，需要结合CBT、问题解决或专业支持。\\n\\n## 实施建议\\n\\n一次只改一个设置，连续观察至少七天，并记录睡眠、任务完成、情绪和必要联络是否受到影响。若使用时间减少却焦虑、孤独或工作负担明显增加，不要继续加码；先恢复必要功能，再缩小目标或调整方法。', '删掉应用后很快因无聊或空虚重新下载，或者转去刷另一个平台时。', '参考：Plackett等，2023；Olson等，2022，行为轻推与替代环境设计。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (276, 6, '发布后设定固定反馈检查时间', '## 要解决什么\\n\\n发布内容后不断刷新点赞、评论和阅读量，会把整个等待过程变成持续警报。预先设定检查时间可以减少临时决策。\\n\\n## 怎么做\\n\\n1. 发布前决定第一次查看时间，例如30分钟或1小时后。\\n2. 关闭该条内容的即时互动推送。\\n3. 到点后集中查看和回复一次。\\n4. 下一次查看放在更晚的固定时段，例如当天晚上。\\n5. 数据不佳时，至少等到预定复盘时间再决定是否删除或修改。\\n\\n## 判断是否有效\\n\\n发布后的刷新次数和情绪波动下降，你能继续完成原来的任务。检查时间应根据工作需要调整，商业账号不必照搬个人账号标准。\\n\\n## 注意事项\\n\\n这是一项环境和时间设置，不是要求忽视真实反馈。需要审核违法、隐私或危机评论的账号，应建立值班和关键词预警，而不是完全延迟处理。\\n\\n## 实施建议\\n\\n一次只改一个设置，连续观察至少七天，并记录睡眠、任务完成、情绪和必要联络是否受到影响。若使用时间减少却焦虑、孤独或工作负担明显增加，不要继续加码；先恢复必要功能，再缩小目标或调整方法。', '动态或作品发布后，几分钟内反复查看数据，无法做其他事情时。', '参考：Fitz等，2019，通知分批；Dekker等，2025；Olson等，2022。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (277, 6, '创作者只在固定窗口查看数据后台', '## 要解决什么\\n\\n创作者需要数据进行工作，但实时监控容易把短期波动变成全天候压力。固定数据窗口能保留分析价值，同时减少反复确认。\\n\\n## 怎么做\\n\\n1. 根据发布频率设置每日1—3个后台查看窗口。\\n2. 每次只记录预先确定的指标，例如完播、收藏、转化和评论质量。\\n3. 不在单次波动后立即全面改版，至少等待足够样本。\\n4. 将创作时段与数据分析时段分开。\\n5. 对异常流量先记录可能因素，再决定是否采取行动。\\n\\n## 判断是否有效\\n\\n后台查看更像工作分析，而不是情绪确认；创作过程不再被每小时数据波动打断。有效指标应服务具体目标，而不是只看最醒目的数字。\\n\\n## 注意事项\\n\\n平台运营、客服和危机公关可能需要更高频监测，可以由团队轮班或设置必要预警。固定窗口不是忽视业务风险。\\n\\n## 实施建议\\n\\n一次只改一个设置，连续观察至少七天，并记录睡眠、任务完成、情绪和必要联络是否受到影响。若使用时间减少却焦虑、孤独或工作负担明显增加，不要继续加码；先恢复必要功能，再缩小目标或调整方法。', '作品发布后全天盯着后台，每次数据变化都会影响创作和情绪时。', '参考：Fitz等，2019通知分批原则；Ohly与Bastin，2023，减少中断。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (278, 6, '给社交媒体购物增加24小时等待期', '## 要解决什么\\n\\n直播、短视频和种草内容把情绪唤起、社交证明和便捷支付放在同一界面中，容易缩短比较需求与付款之间的时间。\\n\\n## 怎么做\\n\\n1. 非必需品先加入普通清单，不立即付款。\\n2. 关闭免密支付或取消平台自动绑定的快捷付款。\\n3. 记录商品、价格和“我希望它证明什么”。\\n4. 至少等待24小时，再检查预算、替代品和真实使用场景。\\n5. 若仍决定购买，明确从哪项预算支出。\\n\\n## 判断是否有效\\n\\n冲动付款减少，购买决定与直播倒计时、博主身份和当下情绪分离。重点不是禁止消费，而是恢复思考时间。\\n\\n## 注意事项\\n\\n本条属于一般消费行为建议，不构成财务规划。若已经出现无法控制的负债、隐瞒消费或明显影响生活，应寻求财务和心理专业支持。\\n\\n## 实施建议\\n\\n一次只改一个设置，连续观察至少七天，并记录睡眠、任务完成、情绪和必要联络是否受到影响。若使用时间减少却焦虑、孤独或工作负担明显增加，不要继续加码；先恢复必要功能，再缩小目标或调整方法。', '刷到限时带货或精致生活内容后，明知预算紧张仍想立刻付款时。', '参考：APA，2023数字素养与商业内容建议；WHO/Europe，2025数字环境保护框架。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (279, 6, '提前说明回复边界，并保留紧急联系方式', '## 要解决什么\\n\\n很多在线警觉来自“别人会不会觉得我必须秒回”。若关系中没有约定，关闭通知和固定查看窗口可能带来新的内疚与误解。\\n\\n## 怎么做\\n\\n1. 对重要的人说明自己的普通回复节奏。\\n2. 明确真正紧急时使用电话、特定关键词或其他通道。\\n3. 工作群可设置状态说明或固定在线时段。\\n4. 不需要向所有联系人逐一解释，只对高频、重要关系沟通。\\n5. 若对方有特殊照护需要，共同制定例外规则。\\n\\n## 判断是否有效\\n\\n你在离线时更少担心错过关键事情，对方也知道如何在紧急情况下找到你。边界应同时保护联系和休息，而不是单方面消失。\\n\\n## 注意事项\\n\\n边界不会让所有人满意，也不适合用于逃避已经承诺的职责。遇到控制、威胁或强迫在线的关系，需要进一步评估现实安全和人际边界。\\n\\n## 实施建议\\n\\n一次只改一个设置，连续观察至少七天，并记录睡眠、任务完成、情绪和必要联络是否受到影响。若使用时间减少却焦虑、孤独或工作负担明显增加，不要继续加码；先恢复必要功能，再缩小目标或调整方法。', '想减少随时在线，却担心朋友、伴侣或同事把延迟回复理解为冷落时。', '参考：APA，2023，促进健康社交媒体使用与家庭沟通；WHO/Europe，2025。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (280, 6, '每周只复盘一次设置，不要每天改规则', '## 要解决什么\\n\\n频繁更改限额、屏蔽列表和使用规则，会让计划变成另一种焦虑监控。固定复盘周期有助于根据趋势调整，而不是被一天的波动牵着走。\\n\\n## 怎么做\\n\\n每周选一个固定时间，回答五个问题：\\n\\n1. 哪个调整最容易坚持？\\n2. 哪个时段仍然最容易失控？\\n3. 哪些内容带来价值，哪些主要消耗？\\n4. 睡眠、任务、关系和情绪有什么变化？\\n5. 下周只保留、增加或修改哪一项？\\n\\n其余时间不因一次超时就重做全部方案。\\n\\n## 判断是否有效\\n\\n行动设置逐渐稳定，你能看见一周趋势，而不是每天在“成功”和“失败”之间摇摆。每次只修改一个变量，更容易知道改变来自哪里。\\n\\n## 注意事项\\n\\n复盘不是给自己打分。若所有设置都难以执行，先降低目标或检查背后的焦虑、抑郁、工作压力与睡眠问题。\\n\\n## 实施建议\\n\\n一次只改一个设置，连续观察至少七天，并记录睡眠、任务完成、情绪和必要联络是否受到影响。若使用时间减少却焦虑、孤独或工作负担明显增加，不要继续加码；先恢复必要功能，再缩小目标或调整方法。', '每天根据情绪更改限额和屏蔽设置，结果计划越来越复杂、越来越难坚持时。', '参考：Olson等，2022，使用反馈与持续干预；Plackett等，2023系统综述。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (281, 8, '案例：看到同学上岸后，小林觉得自己的人生停住了', '## 案例背景\\n\\n小林正在准备研究生考试。晚上休息时，他连续刷到三位高中同学发布录取、实习和旅行动态。几分钟后，他把手机扔到一边，却再也看不进书。\\n\\n## 触发链\\n\\n- **事实**：三位同学发布了近期成果。\\n- **自动想法**：“同龄人都已经进入下一阶段，只有我还在原地。”\\n- **情绪**：焦虑、羞耻、嫉妒和前途感下降。\\n- **行为**：继续搜索更多“上岸帖”，随后制定极端学习表，又因无法完成而自暴自弃。\\n\\n## 容易忽略的机制\\n\\n熟人和同龄人是更有冲击力的参照对象；信息流还会把不同人的高光压缩到同一晚，制造“所有人同时成功”的错觉。小林没有看到这些人的等待、资源、失败和日常，也把三个案例扩大成了整个群体。\\n\\n## 调整过程\\n\\n小林先停止继续搜同类内容，写下事实与解释。他把“所有人都领先”改成“我今晚看到了三个人的成果，自己的考试尚未完成”。之后他整理了过去三个月的进步证据，只保留第二天能完成的两个学习任务，并将相关账号静音一周。\\n\\n## 结果与提醒\\n\\n焦虑没有立即归零，但小林重新开始学习，也不再用一个晚上的信息流判决全部人生。案例中的调整并不证明比较一定是错误的，而是让外部成果回到有限信息的位置。\\n\\n## 案例边界\\n\\n本案例为虚构情境，不构成对任何人的诊断。持续严重的失眠、功能受损或抑郁需要专业评估。', '刷到同学升学、就业或其他人生进展后，觉得自己被整个同龄群体落下时。', '参考：Festinger，1954；Vogel等，2014；McComb等，2023向上比较元分析。', 1, 1, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (282, 8, '案例：健身视频刷了一小时，阿宁开始讨厌自己的身体', '## 案例背景\\n\\n阿宁原本只是想搜索一个肩颈拉伸动作，平台随后连续推荐身材展示、体脂挑战和“七天变化”视频。她照镜子时突然觉得自己的腿、皮肤和腰线都无法接受。\\n\\n## 触发链\\n\\n- **事实**：她连续接触了大量经过筛选的身体图像。\\n- **自动想法**：“正常人都应该是这样的，我的身体说明我不自律。”\\n- **情绪**：羞耻、焦虑和身体厌恶。\\n- **行为**：反复照镜子、搜索极端节食方案，并取消了第二天与朋友的见面。\\n\\n## 容易忽略的机制\\n\\n高颜值和健身内容通常包含构图、姿势、光线、筛选与商业目的；高频推荐还会让少数审美模板显得极其普遍。阿宁把“看见很多”误认成“现实中大多数人都是这样”，又把外貌状态道德化为意志品质。\\n\\n## 调整过程\\n\\n她先停止镜前检查，把触发账号静音，并写下三项身体功能：走路、跳舞和拥抱朋友。第二天，她没有开始惩罚性节食，而是恢复正常吃饭和原定见面。之后每周练习两次身体中性描述，不强迫自己立刻喜欢外貌。\\n\\n## 结果与提醒\\n\\n她仍会羡慕某些身材，但不再把这种羡慕直接变成对身体的攻击。重点不是说所有图片都虚假，而是承认屏幕提供的是高度选择后的审美样本。\\n\\n## 案例边界\\n\\n若出现持续限制进食、暴食、催吐、频繁称重或明显身体检查，应尽快寻求进食障碍或身体意象专业支持。', '搜索健康内容后被大量身材展示包围，开始讨厌身体或产生极端饮食冲动时。', '参考：Tiggemann与Zaccardo，2015；Gobin等，2022；Gordon等，2021。', 1, 1, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (283, 8, '案例：消息显示已读，小周在脑中完成了一次分手', '## 案例背景\\n\\n小周向伴侣发了一段关于近期委屈的长消息。软件显示已经阅读，但两个小时没有回复。期间，他看到对方给共同好友的动态点了赞。\\n\\n## 触发链\\n\\n- **事实**：消息已读、暂未回复，对方完成过其他线上互动。\\n- **自动想法**：“他有时间点赞却不回我，说明他故意惩罚我，已经不爱我了。”\\n- **情绪**：恐慌、愤怒、屈辱和被抛弃感。\\n- **行为**：不断查看在线状态，连续补发消息，最后写下分手长文。\\n\\n## 容易忽略的机制\\n\\n即时通讯提供了活动痕迹，却没有提供对方的情绪容量、环境和回复计划。小周用最威胁性的解释填补信息空白，并把短时延迟扩展成对整段关系的判决。\\n\\n## 调整过程\\n\\n他先把分手长文留在草稿中，使用三句事实卡：“消息已读；原因未知；今晚不必决定关系结局。”之后列出几种替代解释，并约定十分钟后再检查手机。伴侣晚些时候说明需要整理情绪再回应。第二天，两人讨论了长消息的回复方式和紧急联系边界。\\n\\n## 结果与提醒\\n\\n小周学会区分“对方的延迟让我难受”和“延迟已经证明关系结束”。替代解释不等于替对方找借口；若长期冷暴力或控制确实存在，仍需要现实边界。\\n\\n## 案例边界\\n\\n案例不用于判断依恋类型或诊断关系。反复出现的强烈恐慌、控制检查或关系伤害可考虑寻求专业支持。', '重要的人没有及时回复，而对方其他在线痕迹让你迅速推断关系已经破裂时。', '参考：Curtiss等，2021认知重构；NICE CG159关于负面解释和行为实验。', 1, 1, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (284, 8, '案例：群聊无人回应，小孟决定以后再也不说话', '## 案例背景\\n\\n小孟在班级群提议周末一起打球。消息发出后两个小时无人回应，随后老师发布通知，把他的消息顶了上去。\\n\\n## 触发链\\n\\n- **事实**：群里暂时没有人回应邀约。\\n- **自动想法**：“大家都觉得我自作多情，我在这个班没有朋友。”\\n- **情绪**：羞耻、尴尬和社交退缩。\\n- **行为**：反复点开群聊，想撤回却超过时间，之后在线下也回避同学。\\n\\n## 容易忽略的机制\\n\\n群聊沉默可能来自责任扩散、时间不合适、消息被覆盖或成员不知道是否能参加。数字界面会把沉默长期固定在屏幕上，让小孟感觉自己正在被所有人公开围观。\\n\\n## 调整过程\\n\\n小孟把“没人回应”与“所有人否定我”分开，列出多个可能原因。他私下问了一位熟悉同学，对方说当时在上课，后来忘记回复。小孟没有重新群发自嘲，而是把邀约改成具体时间和地点，再询问三位可能参加的人。\\n\\n## 结果与提醒\\n\\n最后只有两个人参加，但这次经历不再被理解为全班的集体拒绝。小孟也发现，具体邀约比宽泛提议更容易得到回应。\\n\\n## 案例边界\\n\\n如果群体中存在持续、明确和有组织的排挤，不能只用认知调整解释，应保留证据并向学校、单位或可信任的人求助。', '在群里发言或邀约无人回应后，决定彻底退出群体和现实社交时。', '参考：NICE CG159社会焦虑CBT；Curtiss等，2021认知和行为方法。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (285, 8, '案例：自律博主的早晨，让雨桐放弃了当天学习', '## 案例背景\\n\\n期末周，雨桐早上睡过头，打开平台后刷到“凌晨五点起床、晨跑、背单词、连续学习十二小时”的视频。她觉得自己已经失去当天翻盘的资格。\\n\\n## 触发链\\n\\n- **事实**：她晚起了，也看到一段高度压缩的自律内容。\\n- **自动想法**：“真正优秀的人不会浪费早晨；我今天已经失败。”\\n- **情绪**：内疚、无力和学业焦虑。\\n- **行为**：制定从中午开始的高强度计划，迟迟不敢开始，最终继续刷视频。\\n\\n## 容易忽略的机制\\n\\n内容把漫长生活压缩为流畅镜头，也没有呈现休息、失败和拍摄成本。雨桐的非黑即白思维把“晚起”变成“整天作废”，完美标准反而增加回避。\\n\\n## 调整过程\\n\\n她写出三层标准：最低维持是复习一章；当前够好是完成两项重点；理想探索才是额外刷题。她把手机放到书桌外，先学习十五分钟，并在晚上记录“晚起后仍然重新开始”这项微小胜利。\\n\\n## 结果与提醒\\n\\n她没有完成极端计划，但完成了当天最重要的复习，也减少了“必须像视频一样完美才能开始”的条件。\\n\\n## 案例边界\\n\\n案例不否定规律作息和努力，也不意味着所有自律内容都是表演。关键在于是否把他人的展示直接转成对自己的最低要求。', '看到极致学习或自律内容后，因为自己没有完美开局而放弃整天计划时。', '参考：McComb等，2023向上比较元分析；Curtiss等，2021；Festinger，1954。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (286, 8, '案例：职场捷报刷满首页，老陈怀疑自己被行业淘汰', '## 案例背景\\n\\n老陈刚经历项目失利，打开职场平台时连续看到前同事晋升、获得奖项和加入大公司的公告。他开始反复修改简历，却不敢真正投递。\\n\\n## 触发链\\n\\n- **事实**：多位联系人公开了职业成果。\\n- **自动想法**：“行业里所有人都在高速上升，只有我能力不足。”\\n- **情绪**：职业羞耻、焦虑和冒充者感。\\n- **行为**：长时间浏览他人履历，夸大自己的简介，同时回避实际求职和能力盘点。\\n\\n## 容易忽略的机制\\n\\n职场平台天然鼓励公开成果和专业身份管理；普通工作日、失败项目和停滞期较少成为公告。老陈把公开率较高的成功事件当成行业整体基线，又把宏观环境和岗位差异全部内归因。\\n\\n## 调整过程\\n\\n他停止继续浏览，做了一张责任饼图，加入市场环境、岗位匹配、项目资源和自身可改进部分。之后把求职拆成两项：向一位同行了解市场情况，完成一份针对岗位的真实简历，而不是继续美化公开主页。\\n\\n## 结果与提醒\\n\\n职业不确定仍然存在，但老陈开始处理现实问题，而不是通过浏览和包装确认价值。他也把职场平台的使用限定为信息搜索和联系人沟通。\\n\\n## 案例边界\\n\\n职场焦虑可能来自真实就业压力，不能全部归为认知偏差。现实资源、职业咨询和经济支持同样重要。', '职场平台中的晋升和成功公告让你怀疑自己已经失去行业竞争力时。', '参考：Festinger，1954；McComb等，2023；Curtiss等，2021问题解决与认知重构。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (287, 8, '案例：完美情侣视频让小雅把一次争吵理解成选错了人', '## 案例背景\\n\\n小雅与伴侣因家务分配争吵。冷静期间，她刷到多个“被伴侣宠上天”的纪念日视频，开始觉得自己的关系处处失败。\\n\\n## 触发链\\n\\n- **事实**：两人有一次尚未解决的家务冲突。\\n- **自动想法**：“真正爱我的人不会让我受委屈；别人关系都比我的好。”\\n- **情绪**：失望、嫉妒、孤独和关系不安全感。\\n- **行为**：继续搜索情侣内容，翻旧账，并要求伴侣公开发动态证明爱意。\\n\\n## 容易忽略的机制\\n\\n公开视频更容易展示浪漫事件，而不是长期分工、冲突和修复过程。小雅把“别人展示的高光”与“自己的冲突时刻”直接比较，也用公开表达替代了具体需要。\\n\\n## 调整过程\\n\\n她先列出自己真正需要的是家务分工和被理解，而不是复刻视频。情绪下降后，两人讨论了具体任务，并约定每周一次检查分工。小雅将高触发情侣账号静音，同时建立关系支持证据簿，记录线下的可靠行为。\\n\\n## 结果与提醒\\n\\n一次争吵没有因此被美化，但问题从“伴侣不够像视频”变成了可以协商的现实分工。小雅也减少了用公开展示检验关系的习惯。\\n\\n## 案例边界\\n\\n若关系中存在暴力、威胁、控制或长期贬低，应优先考虑安全与专业支持，不能只靠比较调整维持关系。', '现实关系刚发生冲突，又刷到完美情侣内容，马上觉得自己选错了人时。', '参考：社会比较理论；McComb等，2023；Curtiss等，2021问题解决框架。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (288, 8, '案例：视频流量突然下跌，阿哲一夜刷新了两百次', '## 案例背景\\n\\n阿哲经营知识类账号，一条投入很多时间的视频发布后，数据远低于过去平均值。他每隔几分钟刷新后台，直到凌晨仍无法入睡。\\n\\n## 触发链\\n\\n- **事实**：单条视频早期数据较低。\\n- **自动想法**：“账号被限流了，我已经失去创作能力和收入来源。”\\n- **情绪**：失控、羞耻、恐慌和职业不安全感。\\n- **行为**：频繁检查、删除重发、临时更改选题，第二天无法继续创作。\\n\\n## 容易忽略的机制\\n\\n平台分发具有不确定性，单条内容的早期样本也可能受主题、时段和受众匹配影响。实时数据界面把短期波动持续暴露给创作者，检查暂时缓解不确定，却又强化下一次检查。\\n\\n## 调整过程\\n\\n阿哲将后台查看改为每天三个固定窗口，只记录预先选定的完播、收藏和评论质量。他把“账号完了”写成待检验预测，等待足够样本后再复盘。创作时段手机不显示后台通知，异常情况才启用预警。\\n\\n## 结果与提醒\\n\\n数据最终没有达到预期，但阿哲能够区分“这条内容表现较差”和“我作为创作者彻底失败”。他据此调整选题，而不是用整晚刷新寻找安全感。\\n\\n## 案例边界\\n\\n依赖平台收入的人面临真实经济风险，个体心理技巧不能替代商业规划、多渠道收入和劳动保障。', '作品早期数据不佳后，反复刷新后台并把一次波动理解为职业终结时。', '参考：Andreassen等，2017反馈依赖；Reinecke等，2018在线警觉；Curtiss等，2021。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (289, 8, '案例：灾难新闻越刷越多，小敏觉得世界已经没有安全处', '## 案例背景\\n\\n一次重大灾害发生后，小敏从新闻进入短视频和评论区，又搜索了各种预测和现场画面。她连续几晚睡前刷新，白天也无法集中注意。\\n\\n## 触发链\\n\\n- **事实**：现实中发生了严重事件，网络上存在大量相关信息。\\n- **自动想法**：“灾难随时会发生在所有人身上，生活已经没有意义。”\\n- **情绪**：恐惧、无力、悲伤和内疚。\\n- **行为**：重复观看、通宵搜索、无法进行普通活动，并因自己仍能吃饭休息而自责。\\n\\n## 容易忽略的机制\\n\\n负面信息能够激活威胁监测，而平台会不断提供更新和更具冲击力的版本。不同地点、时间和来源的内容被压缩在同一屏幕，也会放大事件无处不在的感觉。\\n\\n## 调整过程\\n\\n小敏先用现实定向确认自己当下的位置和安全状况，随后只保留两个可靠信息源，每天固定两次查看。她停止观看未经核实的现场剪辑，并把关心转化为一项现实行动，例如核验后捐助或关注当地官方通知。\\n\\n## 结果与提醒\\n\\n悲伤仍然存在，但不再通过无休止围观维持。小敏能够在关注公共事件与保护自身功能之间建立边界。\\n\\n## 案例边界\\n\\n处在真实灾区的人需要优先遵循当地安全与应急信息。持续闪回、严重失眠或明显创伤反应应寻求专业帮助。', '公共灾难发生后连续搜索现场画面和推测，越来越觉得世界不再安全时。', '参考：Satici等，2023；Taskin等，2024；末日刷屏与心理痛苦研究。', 1, 1, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (290, 8, '案例：朋友聚会没叫安安，她把周末变成了调查行动', '## 案例背景\\n\\n安安在家刷到朋友们的聚餐合照，自己没有被邀请。她立刻翻看每个人的动态，试图确认他们是否有另一个群。\\n\\n## 触发链\\n\\n- **事实**：一场聚会中没有安安。\\n- **自动想法**：“他们已经把我排除在朋友圈之外，我必须马上弄清楚。”\\n- **情绪**：嫉妒、落寞、焦虑和被抛弃感。\\n- **行为**：反复查看定位、合照和评论，发模糊动态试探，并取消了原本的个人安排。\\n\\n## 容易忽略的机制\\n\\nFOMO把缺席解释成归属威胁，并推动更多信息搜寻。搜索短期提供控制感，却可能不断扩大细节，使一场活动被理解为整个关系网络的秘密重组。\\n\\n## 调整过程\\n\\n安安先停止调查，给情绪命名为“被排除感和嫉妒”。她列出关系支持证据，确认这些朋友过去仍有联系。第二天，她直接问一位关系较近的人，得知聚会是临时讨论某个项目。她也保留了原定的运动安排，没有用整晚搜索证明自己的重要性。\\n\\n## 结果与提醒\\n\\n即使解释并不总是令人满意，安安开始学会把“我缺席了这一次”与“我从所有关系中被删除”分开。\\n\\n## 案例边界\\n\\n现实排挤确实可能存在。若多次明确被排除，应进行沟通、调整投入或建立新支持网络，而不是无限自我安慰。', '看到朋友聚会却没有自己，开始翻遍所有人的动态寻找排斥证据时。', '参考：Przybylski等，2013 FOMO研究；Curtiss等，2021；社会比较理论。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (291, 8, '案例：种草视频让小琪在付款前觉得“不买就落后”', '## 案例背景\\n\\n小琪在深夜刷到一位喜欢的博主推荐新款相机。直播间反复强调限时价格和“记录精致生活必备”，她的预算却已经很紧张。\\n\\n## 触发链\\n\\n- **事实**：商品正在促销，博主展示了高质量成片。\\n- **自动想法**：“没有这台相机，我永远拍不出好内容，也显得不够专业。”\\n- **情绪**：兴奋、焦虑、匮乏感和错失恐惧。\\n- **行为**：打开分期付款，反复比较他人的设备，并忽略已有相机的实际使用情况。\\n\\n## 容易忽略的机制\\n\\n内容把产品与身份、创作能力和生活方式绑定；限时设计压缩了思考时间。小琪比较的是博主完成后的图像和自己的设备焦虑，却没有检查拍摄经验、合作利益和真实需求。\\n\\n## 调整过程\\n\\n她关闭免密支付，把商品放入24小时等待清单，并写下“我希望它证明什么”。第二天，她用现有设备完成一次拍摄测试，发现主要困难在构图和剪辑。她最终没有购买，把部分预算用于一门实际课程。\\n\\n## 结果与提醒\\n\\n这并不意味着新设备永远不值得买，而是把购买从身份抢救变成了预算和用途决策。\\n\\n## 案例边界\\n\\n若已出现无法控制的负债、隐瞒消费或持续冲动购物，需要财务和心理方面的进一步支持。\\n\\n案例提醒：重点是识别相似的触发、想法与行为循环，不要求现实经历完全相同。', '社交媒体商品推荐让你觉得不立刻购买就会失去身份、能力或生活资格时。', '参考：套路拆解中的社会证明与稀缺机制；Przybylski等，2013 FOMO框架。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (292, 8, '案例：通讯录里有领导和家人，阿泽发什么都像在答辩', '## 案例背景\\n\\n阿泽的朋友圈同时有同事、领导、客户、亲戚和好友。他想分享一张演出照片，却担心领导觉得不务正业、长辈觉得不稳重、客户觉得不专业。\\n\\n## 触发链\\n\\n- **事实**：同一条内容可能被不同关系的人看到。\\n- **自动想法**：“每个人都会从最不利的角度解释我，我必须让所有人都满意。”\\n- **情绪**：紧张、疲惫和表达窒息。\\n- **行为**：反复修改分组，最终删除内容，并大面积清理旧动态。\\n\\n## 容易忽略的机制\\n\\n网络把现实中原本分开的受众合并在同一空间。阿泽面对的是一个真实的界面和关系难题，但焦虑又进一步提出了不可能目标：完全控制所有人的理解。\\n\\n## 调整过程\\n\\n他把账号功能重新划分：公开账号主要放专业信息，私人内容只对较小熟人组可见；不敏感的日常允许存在一定误读。他还写下自己的发布底线，例如不泄露工作信息、不攻击他人，而不是预测每个人的看法。\\n\\n## 结果与提醒\\n\\n阿泽没有恢复无边界分享，而是形成了更符合关系现实的表达结构。减少发布也可以是合理选择，只要不是完全由恐惧决定。\\n\\n## 案例边界\\n\\n涉及职业保密、隐私或现实安全时，应遵守明确规则。案例不鼓励为了“克服焦虑”公开敏感信息。', '朋友圈包含多种关系，发任何内容都担心被不同人误解时。', '参考：boyd与Marwick，2011网络公共空间隐私研究；NICE CG159。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (293, 8, '案例：手机没有响，小舟却每五分钟确认一次', '## 案例背景\\n\\n小舟最近负责社团活动，也在等待实习通知。即使手机静音，他仍会不断解锁检查群聊和邮箱，吃饭时也无法听清朋友说话。\\n\\n## 触发链\\n\\n- **事实**：确实可能出现需要处理的消息，但多数时段没有新通知。\\n- **自动想法**：“如果我晚几分钟看到，就会错过机会或让所有人失望。”\\n- **情绪**：持续紧张和无法离线的不安全感。\\n- **行为**：高频解锁、任务切换、睡前检查，注意力长期处于后台监控。\\n\\n## 容易忽略的机制\\n\\n在线警觉不只表现为屏幕总时长，还包括脑中持续想着“网上有没有新情况”。每次检查可能短暂降低不确定，但也训练大脑把不检查理解为危险。\\n\\n## 调整过程\\n\\n小舟和社团明确了真正紧急事件使用电话，其他消息每天集中处理。学习时启用专注模式，每四十五分钟查看一次。他记录三天基线后逐步延长间隔，而不是一次完全关机。\\n\\n## 结果与提醒\\n\\n小舟仍会在重要结果前紧张，但能够区分必要值守和焦虑性监控。朋友交流和学习任务也不再被每次解锁切碎。\\n\\n## 案例边界\\n\\n真实值班、照护或紧急职责需要保留即时通道。若检查行为严重影响睡眠、学习或带有强迫性质，应寻求专业评估。\\n\\n案例提醒：重点是识别相似的触发、想法与行为循环，不要求现实经历完全相同。', '即使没有提示，也不断确认消息，担心几分钟离线就会造成严重后果时。', '参考：Reinecke等，2018在线警觉量表；Yildirim与Correia，2015。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (294, 8, '案例：喜欢的博主突然停更，佳佳像失去了一位朋友', '## 案例背景\\n\\n佳佳长期关注一位陪伴型博主。她在备考和失恋期间每天看直播，逐渐形成固定生活节奏。博主突然宣布无限期停更后，佳佳反复刷新旧账号，感到空洞和被抛弃。\\n\\n## 触发链\\n\\n- **事实**：稳定的内容和互动突然中断。\\n- **自动想法**：“我唯一理解我的人消失了，我以后没有地方可去。”\\n- **情绪**：哀伤、失落、愤怒和孤独。\\n- **行为**：反复看旧视频，在粉丝群寻找解释，并减少现实社交。\\n\\n## 容易忽略的机制\\n\\n拟社会关系是单向但可能真实投入情感的关系体验。摄像头直视、固定更新和直播回应会增强熟悉与陪伴感；中断后出现哀伤并不荒谬。但公开形象仍不是完整、互惠的现实关系。\\n\\n## 调整过程\\n\\n佳佳允许自己承认失落，而不是嘲笑自己“为陌生人难过”。她限制每天回看时间，整理博主曾给她的实际启发，同时联系了一位现实朋友恢复晚间散步。她没有强迫自己立刻取关，而是逐渐建立新的生活锚点。\\n\\n## 结果与提醒\\n\\n几周后，旧视频仍有意义，但不再承担她全部的情绪支持。佳佳把“这段陪伴对我真实”与“它不能替代互惠关系”同时保留下来。\\n\\n## 案例边界\\n\\n若中断引发长期严重抑郁、完全退出现实生活或自伤想法，应尽快寻求专业支持。', '长期陪伴自己的博主、主播或虚拟角色停更后，感到像现实关系断裂一样痛苦时。', '参考：拟社会关系与自我呈现研究框架；自我同情和社会连接相关研究。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (295, 8, '案例：评论区争论结束了，维维的身体还在继续应战', '## 案例背景\\n\\n维维在热点评论区与陌生人争论了两个小时。退出应用后，他仍咬紧牙、肩膀僵硬，脑中不断组织下一条反驳。\\n\\n## 触发链\\n\\n- **事实**：他与多个匿名账号发生了观点冲突。\\n- **自动想法**：“如果我不把他们说服，就是默认错误和恶意获胜。”\\n- **情绪**：愤怒、焦虑和强烈责任感。\\n- **行为**：持续刷新回复、搜索更多证据，线下交流时仍心不在焉。\\n\\n## 容易忽略的机制\\n\\n高冲突内容容易获得互动和可见度，评论区也缺少语气与关系背景。维维把“不再回复”理解成价值投降，使争论没有自然终点；身体则在内容结束后仍保持警报姿势。\\n\\n## 调整过程\\n\\n他先做肩膀、下颌和手掌放松，把要回复的内容留在草稿。十分钟后，他判断这场讨论没有明确目标，于是保存必要资料并退出。之后为热点设置固定查看窗口，只在能说明具体事实、且对方愿意交流时参与。\\n\\n## 结果与提醒\\n\\n维维并没有放弃公共表达，而是区分了表达价值和无限对线。他也发现，退出一场无效争论不等于承认失败。\\n\\n## 案例边界\\n\\n涉及明确仇恨、骚扰和威胁时，应使用平台举报、证据保存和现实支持，不必通过继续争论证明自己。\\n\\n补充提醒：阅读案例时应寻找与自己相似的机制，而不是要求经历完全一致。 相似点可以是触发方式、自动想法、行为循环或现实边界。', '网络争论已经结束，身体和脑中却持续处在反驳与应战状态时。', '参考：情绪急救的身体放松与延迟回应；NICE CG159注意和安全行为框架。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (296, 8, '案例：十年前的旧帖子，让小珊害怕新工作毁于一旦', '## 案例背景\\n\\n小珊即将入职新公司，偶然搜索自己的旧账号，发现十年前发表过幼稚、情绪化的帖子。她开始通宵删除所有历史痕迹，担心同事已经看到。\\n\\n## 触发链\\n\\n- **事实**：旧内容仍可被检索，其中部分表达与现在不同。\\n- **自动想法**：“只要有人看到，我的工作和关系都会彻底结束。”\\n- **情绪**：羞耻、恐慌和身份暴露感。\\n- **行为**：反复搜索姓名、删除账号、检查缓存和他人转发，无法完成入职准备。\\n\\n## 容易忽略的机制\\n\\n数字痕迹确实可能长期存在，担忧不是完全虚构；但小珊把“存在被看到的可能”迅速推成“所有人已经看到并会作最坏判断”。反复搜索又持续提供新的不确定性。\\n\\n## 调整过程\\n\\n她先区分必须处理和无法完全控制的部分：修改公开隐私设置、删除可管理内容、保存必要记录，不再无限搜索。她写出若被问及的简短回应：“那是多年以前的表达，我的观点和行为已经发生变化。”随后把注意转回入职材料。\\n\\n## 结果与提醒\\n\\n不确定性没有被彻底消除，但小珊不再以整夜检查换取短暂安全。她也承认成长意味着过去与现在可能不一致。\\n\\n## 案例边界\\n\\n若旧内容涉及真实法律、职业合规或他人隐私问题，应寻求专业法律或单位合规建议，不能只做心理调整。', '求职或关系变化时发现旧账号内容，开始无限搜索和删除以避免想象中的全面暴露时。', '参考：boyd与Marwick，2011数字隐私研究；Curtiss等，2021去灾难化与问题解决。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (297, 7, '三步自我同情停顿：看见、连接、友善回应', '## 训练目标\\n\\n比较发生后，很多人的第一反应是责骂自己“怎么又嫉妒、又脆弱”。三步停顿不是让你否认落差，而是训练一种更稳定的自我回应：先承认痛苦，再把自己放回普通人的共同处境，最后给出不羞辱自己的支持。\\n\\n## 练习步骤\\n\\n每周练习3—5次，也可以在轻度触发后使用：\\n\\n1. **看见**：“我现在因为比较而难受，胸口紧、很失落。”\\n2. **连接**：“人在看到别人高光时产生落差很常见，我并不是唯一这样的人。”\\n3. **友善回应**：“我可以先不判决自己，给自己十分钟，再决定下一步。”\\n\\n最后写下一句真正能相信的话，例如：“这次刺激了我，但它不能概括我的全部生活。”\\n\\n## 反比较重点\\n\\n自我同情不是告诉自己“我比别人好”，而是减少必须通过胜过别人才能获得尊重的条件。长期目标是让痛苦不再自动升级成自我攻击。\\n\\n## 练习边界\\n\\n元分析显示自我同情干预对焦虑、压力和抑郁的平均效果多为小到中等，研究质量也存在差异。它不是危机处理或正式治疗；若自我友善语言让你明显反感，可以先从中性、不攻击的表达开始。\\n\\n## 训练建议\\n\\n先连续练习两到四周，再根据真实体验决定是否保留。每次只选择一种训练，不要同时完成整套清单。若练习引发明显羞耻、反刍或强迫感，应缩短、暂停，或在专业支持下调整。', '看到他人高光后不仅失落，还开始责骂自己嫉妒、没用或太敏感时。', '参考：Han与Kim，2023自我同情干预元分析；Neff与Germer，2013随机试验。', 1, 1, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (298, 7, '给受触发的自己写一封支持信', '## 训练目标\\n\\n把内心关系从“审判者对失败者”调整为“一个可靠的人在陪伴另一个正在受挫的人”。书信形式能让支持语言更完整，也比临时喊口号更容易容纳真实困难。\\n\\n## 练习步骤\\n\\n选择一次典型的社交媒体触发，用10—15分钟写信：\\n\\n1. 客观描述发生了什么，不夸大也不淡化。\\n2. 承认你最难受的部分，例如落后感、被排除感或羞耻。\\n3. 写出这种反应为什么可以理解，包括当前压力和重要需要。\\n4. 像写给亲近朋友一样，提出一到两个温和、现实的建议。\\n5. 以一句不附加条件的支持结尾：“无论这次表现怎样，你仍值得被认真对待。”\\n\\n隔一天再读，圈出最能安抚你的两句话。\\n\\n## 反比较重点\\n\\n信中不要证明“别人其实也不好”，而是练习在不贬低比较对象的情况下，仍然维护自己的尊严和完整性。\\n\\n## 练习边界\\n\\n支持信不必写得感人，也不应变成强迫性的长篇分析。若书写持续引发创伤记忆或强烈绝望，应停止并寻求专业支持。\\n\\n## 训练建议\\n\\n先连续练习两到四周，再根据真实体验决定是否保留。每次只选择一种训练，不要同时完成整套清单。若练习引发明显羞耻、反刍或强迫感，应缩短、暂停，或在专业支持下调整。', '一次比较或公开反馈在心里停留很久，普通安慰很快被自我批评推翻时。', '参考：自我同情干预框架；Han与Kim，2023；Neff与Germer，2013。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (299, 7, '把内心批评改写成教练式语言', '## 训练目标\\n\\n长期比较会让内在语言变成绝对判决：“你永远赶不上”“你就是懒”。教练式语言既不纵容，也不羞辱，重点是描述现状、指出可控部分并保留成长空间。\\n\\n## 练习步骤\\n\\n每周挑三句常见自我批评，按以下结构改写：\\n\\n- 原句：“别人都在进步，你就是废物。”\\n- **事实**：“我今天看到几个人发布成果，而我的计划没有完成。”\\n- **理解**：“我最近睡眠不足，也被比较刺激了。”\\n- **方向**：“今晚先完成一个最小步骤，明天再调整计划。”\\n\\n判断新句子是否满足三个条件：具体、可执行、不会用人格羞辱推动行动。\\n\\n## 反比较重点\\n\\n教练式语言不需要把失误美化成成功。它只是把“整体人格很差”改成“某个行为和环境需要调整”，让行动不再依赖自我憎恨。\\n\\n## 练习边界\\n\\n如果改写后只剩“必须更努力”，说明批评仍然只是换了温和包装。真正的教练语言也允许休息、重新评估目标和承认资源限制。\\n\\n## 训练建议\\n\\n先连续练习两到四周，再根据真实体验决定是否保留。每次只选择一种训练，不要同时完成整套清单。若练习引发明显羞耻、反刍或强迫感，应缩短、暂停，或在专业支持下调整。', '刷到自律或成功内容后，脑中反复用羞辱性语言逼迫自己行动时。', '参考：Han与Kim，2023自我同情干预元分析；Kross等，2014自我对话研究。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (300, 7, '共同人性记录：把不完美放回普通人的生活', '## 训练目标\\n\\n信息流容易让人产生“只有我停滞、混乱、会嫉妒”的孤立感。共同人性训练不是假设每个人经历相同，而是提醒自己：失败、等待、关系波动和精力不足都是人类生活的一部分，只是较少被公开。\\n\\n## 练习步骤\\n\\n每周完成一张记录：\\n\\n1. 写下本周最想隐藏的一次不完美。\\n2. 写出这个经历反映了什么普遍处境，例如“重要结果不完全由努力控制”。\\n3. 想象三种不同背景的人可能如何经历相似困难。\\n4. 写一句不比较轻重的连接语：“我的处境有独特部分，但受挫并不让我脱离人群。”\\n5. 最后写下你愿意向现实中的谁透露一点真实状态。\\n\\n## 反比较重点\\n\\n不要用“别人也很惨”获得安慰，也不要否认结构性差异。练习的核心是减少“不完美意味着我不配属于群体”的孤立解释。\\n\\n## 练习边界\\n\\n共同人性不能替代对现实不公、排斥或伤害的处理。若某段关系确实不断羞辱你，除了自我安抚，也需要现实边界和支持。\\n\\n## 训练建议\\n\\n先连续练习两到四周，再根据真实体验决定是否保留。每次只选择一种训练，不要同时完成整套清单。若练习引发明显羞耻、反刍或强迫感，应缩短、暂停，或在专业支持下调整。', '信息流让你觉得别人都稳定顺利，只有自己混乱、失败或情绪很多时。', '参考：Neff与Germer，2013；Marsh等，2018，自我同情与心理痛苦元分析。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (301, 7, '用自己的名字进行第三人称自我对话', '## 训练目标\\n\\n情绪强烈时，第一人称反思容易变成反刍：“我怎么这样、我完了”。用自己的名字或“你”来对话，可以暂时拉开一点心理距离，让语言更像对一个具体的人提出帮助。\\n\\n## 练习步骤\\n\\n遇到比较后，写下三个问题：\\n\\n1. “俊一现在最难受的是什么？”\\n2. “俊一掌握了哪些事实，哪些只是预测？”\\n3. “如果要保护他今晚的生活，下一步最合适的是什么？”\\n\\n回答时避免写成长篇分析，只用三到五句话。也可以想象一个月后的自己回看今天，会如何概括这次事件。\\n\\n## 反比较重点\\n\\n自我距离不是假装事情与自己无关，而是从“我就是失败”转为“这个人正在经历一次失败感”。比较对象仍然存在，但不再占据全部视野。\\n\\n## 练习边界\\n\\n第三人称语言对部分人自然，对部分人会显得别扭。若感到疏离或不真实，可以改成“我最信任的朋友会怎样对我说”。它不适合用来压住必须表达的情绪。\\n\\n## 训练建议\\n\\n先连续练习两到四周，再根据真实体验决定是否保留。每次只选择一种训练，不要同时完成整套清单。若练习引发明显羞耻、反刍或强迫感，应缩短、暂停，或在专业支持下调整。', '比较后不断在第一人称里循环“我不行、我完了”，越想越陷进去时。', '参考：Kross等，2014；Kross与Ayduk，2011，自我距离与适应性反思研究。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (302, 7, '个人进步证据簿：记录微小胜利与长期变化', '## 训练目标\\n\\n社交媒体不断提供更强、更快、更漂亮的外部参照，而个人成长往往由许多不可发布的小行动组成。进步证据簿同时记录短期微小胜利和较长时间的变化，帮助你建立自己的纵向参照。\\n\\n## 练习步骤\\n\\n平时随手记录以下内容，每月集中整理一次：\\n\\n1. 我开始、坚持或完成了什么。\\n2. 我停止、拒绝或放下了什么不适合的事。\\n3. 我在困难状态下维持住了什么。\\n4. 哪项能力比三个月前更熟练或更稳定。\\n5. 哪些现实限制影响了速度，但没有抹掉努力。\\n\\n月末画一条简单时间线，选出三项具体证据，并写出下个月只想推进的一个方向。\\n\\n## 反比较重点\\n\\n证据簿不按点赞价值选择，也不要求每个月都进步。停滞、恢复、维持和放弃错误目标都可以被记录。它让你拥有自己的时间轴，而不是只能依赖同龄人提供的横向排名。\\n\\n## 练习边界\\n\\n若记录变成新的绩效考核，可以减少到每周一项，并加入“我允许自己休息了什么”。没有增长不等于没有价值。\\n\\n## 训练建议\\n\\n连续练习四周后再回看，不要每天用它评判自己。若记录明显增加焦虑或完美主义压力，应暂停并缩小范围。', '看到同龄人成果后，完全忘记自己最近几个月已经完成、维持或改变了什么时。', '参考：Gander等，2016，成就与意义干预；优势干预相关系统综述。', 1, 1, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (303, 7, '多维身份拼图：不让一个指标定义全部自我', '## 训练目标\\n\\n比较焦虑会把身份压缩成单一排行：收入、外貌、学校、恋爱状态或粉丝数。多维身份拼图训练重新看见一个人同时拥有多种角色、关系、能力和价值，任何单一指标都只是其中一块。\\n\\n## 练习步骤\\n\\n画一个圆并分成8—12块，填写可能的身份领域：\\n\\n- 学习者、朋友、家人、创作者、运动者。\\n- 好奇、幽默、可靠、审美、照顾能力。\\n- 兴趣、文化、社区和未来想探索的方向。\\n\\n然后标记：最近哪个区域被信息流放得过大？哪个区域长期没有被看见？本周选择一个被忽略领域，安排一次真实行动。\\n\\n## 反比较重点\\n\\n拼图不是为了证明自己“其他方面更强”，而是拒绝接受单维度总排名。别人某一块突出，不等于你的整张图失去价值。\\n\\n## 练习边界\\n\\n身份领域可以变化，也不必每块都发展。若某些角色来自他人强迫或让你持续受伤，可以把它移出拼图，而不是为了完整勉强保留。\\n\\n## 训练建议\\n\\n先连续练习两到四周，再根据真实体验决定是否保留。每次只选择一种训练，不要同时完成整套清单。若练习引发明显羞耻、反刍或强迫感，应缩短、暂停，或在专业支持下调整。', '因为外貌、收入、学校或关系状态中的一个差距，就觉得整个人都输掉时。', '参考：自我肯定理论与价值干预元分析；Zhang等，2025；Epton等，2015。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (304, 7, '价值排序卡：确认点赞之外真正重要的方向', '## 训练目标\\n\\n当平台不断提供可量化指标时，人容易把“被看见”误当成唯一方向。价值排序训练帮助区分：什么是我愿意长期靠近的生活品质，什么只是为了避免落后而临时追逐的信号。\\n\\n## 练习步骤\\n\\n从以下词中选择10个，再缩减为5个：学习、创造、亲密、自由、健康、诚实、勇气、稳定、贡献、探索、审美、玩乐、责任。对每个核心价值回答：\\n\\n1. 它对我意味着什么，不引用社会标准。\\n2. 过去一个月我在哪个行为中体现过它？\\n3. 社交媒体怎样帮助或干扰了它？\\n4. 下周一个可观察的小行动是什么？\\n\\n每三个月重做一次，允许排序变化。\\n\\n## 反比较重点\\n\\n价值没有统一排行榜。别人选择财富、旅行或高曝光，并不能自动决定你的优先级。训练不是否定成就，而是让成就服务于自己的方向。\\n\\n## 练习边界\\n\\n价值不是任务清单，也不应变成新的完美人格要求。若“健康”被写成必须瘦到某个标准，需要回到它对生活功能和照顾的真实含义。\\n\\n## 训练建议\\n\\n先连续练习两到四周，再根据真实体验决定是否保留。每次只选择一种训练，不要同时完成整套清单。若练习引发明显羞耻、反刍或强迫感，应缩短、暂停，或在专业支持下调整。', '追逐流行目标和平台指标很久，却越来越不知道自己真正想过怎样的生活时。', '参考：Han与Kim，2022互联网ACT元分析；A-Tjak等，2015 ACT元分析。', 1, 1, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (305, 7, '价值一致的一小步：用行动而非排名确认方向', '## 训练目标\\n\\n价值如果只停留在文字上，很容易在下一次比较中被覆盖。价值一致行动训练让自我评价逐渐建立在“我是否向重要方向迈步”，而不是“我是否比别人快”。\\n\\n## 练习步骤\\n\\n从一个核心价值出发，设计十分钟内能开始的行动：\\n\\n- 价值是学习：整理一个问题并学习15分钟。\\n- 价值是亲密：认真回复一个重要的人。\\n- 价值是创造：写下四句草稿，不公开。\\n- 价值是健康：准备一顿正常饮食或出门散步。\\n\\n行动完成后只记录“做了什么、感受怎样、下一次何时继续”，不评价它够不够厉害。\\n\\n## 反比较重点\\n\\n同一个价值可以有很多表达方式。别人通过创业体现创造，你也可以通过写作、做饭或解决实际问题体现创造。价值行动没有统一可见度。\\n\\n## 练习边界\\n\\n小步行动不是强迫自己在所有情绪下保持生产力。休息、求助和停止不合适的承诺也可能是价值一致的行动。\\n\\n## 训练建议\\n\\n先连续练习两到四周，再根据真实体验决定是否保留。每次只选择一种训练，不要同时完成整套清单。若练习引发明显羞耻、反刍或强迫感，应缩短、暂停，或在专业支持下调整。', '知道自己重视什么，却总被别人更快、更大的成果打断，难以持续行动时。', '参考：Han与Kim，2022；Levin等，2012，心理灵活模型成分元分析。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (306, 7, '核心价值自我肯定写作', '## 训练目标\\n\\n当某个领域受到威胁时，人容易把全部自我价值押在这次比较上。价值肯定写作通过回忆对自己重要的价值和具体经历，扩大自我视野，而不是重复“我很棒”这种缺少依据的口号。\\n\\n## 练习步骤\\n\\n1. 从价值清单中选一个与当前比较不同的核心价值。\\n2. 写出它为什么重要。\\n3. 回忆一次你真正按这个价值行动的具体事件。\\n4. 写出这段经历说明了你怎样选择和承担，而不是说明你比谁优秀。\\n5. 最后写：“当前领域的挫败很重要，但它不是我唯一的价值来源。”\\n\\n每次写10分钟即可，不要同时肯定十个领域。\\n\\n## 反比较重点\\n\\n自我肯定不是用其他优点抵消缺点，也不是回避现实反馈。它帮助你在受到威胁时，不把一个数字或一次落后升级为整体身份崩塌。\\n\\n## 练习边界\\n\\n元分析显示自我肯定的效应通常较小，并受到情境和实施方式影响。若写作变成夸大自我或否认问题，应回到具体行为和价值。\\n\\n## 训练建议\\n\\n先连续练习两到四周，再根据真实体验决定是否保留。每次只选择一种训练，不要同时完成整套清单。若练习引发明显羞耻、反刍或强迫感，应缩短、暂停，或在专业支持下调整。', '某个领域落后后，开始觉得自己所有方面都没有价值时。', '参考：Zhang等，2025幸福感元分析；Epton等，2015；Escobar-Soler等，2023。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (307, 7, '优势识别与使用日志', '## 训练目标\\n\\n社交媒体比较常聚焦容易展示的结果，却忽略促成生活质量的稳定能力，如好奇、坚持、幽默、审慎、善意和团队合作。优势日志训练识别自己已经在使用的资源，并寻找不过度表演的应用方式。\\n\\n## 练习步骤\\n\\n每周选择一项优势：\\n\\n1. 写出它在你生活中的具体表现，不只写标签。\\n2. 记录本周哪一次使用得恰当。\\n3. 写出哪一次使用过度或不足。\\n4. 设计一次新的、小范围使用，例如用好奇心学习一个问题，用勇气完成一次必要沟通。\\n5. 周末记录结果，不要求得到外部赞美。\\n\\n## 反比较重点\\n\\n优势不是天赋排行榜，也不需要拥有所有优势。别人的可见成就可能依赖某些优势，你可以发展不同组合，而不必复制其路径。\\n\\n## 练习边界\\n\\n优势语言不能遮盖资源不足、疾病或结构性限制。若“坚持”已经变成过度消耗，也需要练习审慎、休息和求助。\\n\\n## 训练建议\\n\\n先连续练习两到四周，再根据真实体验决定是否保留。每次只选择一种训练，不要同时完成整套清单。若练习引发明显羞耻、反刍或强迫感，应缩短、暂停，或在专业支持下调整。', '只看见别人拥有的能力，完全说不出自己日常依靠哪些品质生活时。', '参考：Yan等，2020优势干预系统综述；Green，2022大学生优势干预。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (308, 7, '三件“已经拥有”的具体事', '## 训练目标\\n\\n比较把注意力持续拉向缺少的东西。感恩练习不是要求对痛苦说谢谢，而是训练注意系统同时保留生活中已经存在的支持、资源和体验，避免“别人有、我什么都没有”的绝对化总结。\\n\\n## 练习步骤\\n\\n每周三次，每次写三件具体的事：\\n\\n- 一个人做了什么，让你得到一点支持。\\n- 身体或环境提供了什么基本帮助。\\n- 你自己完成或维护了什么。\\n- 一次普通但真实的舒适体验。\\n\\n每项补充“为什么对我有意义”，并尽量避免长期重复同一句话。\\n\\n## 反比较重点\\n\\n不要把感恩变成“我已经够幸运，所以不许难受”。你可以同时感谢一顿饭，也承认经济压力；感谢朋友，也承认关系中的失望。它增加视野，而不是取消问题。\\n\\n## 练习边界\\n\\n元分析显示感恩干预平均效果较小，跨文化和个体差异明显。若练习引发愧疚或被迫积极，可以暂停，改写成“今天有什么对我有一点帮助”。\\n\\n## 训练建议\\n\\n先连续练习两到四周，再根据真实体验决定是否保留。每次只选择一种训练，不要同时完成整套清单。若练习引发明显羞耻、反刍或强迫感，应缩短、暂停，或在专业支持下调整。', '连续比较后觉得自己一无所有，看不见生活中仍然存在的支持和资源时。', '参考：Diniz等，2023；Choi等，2025感恩干预元分析；Wong等，2018。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (309, 7, '品味一个真实好时刻，不急着发布', '## 训练目标\\n\\n当每个好时刻都立刻被转化为拍摄、发布和等待反馈，体验本身容易退到后台。品味训练让积极体验先在身体和记忆中停留，再决定是否分享。\\n\\n## 练习步骤\\n\\n每天选一个很小的真实时刻，例如好吃的一口、夕阳、完成任务后的放松或一次笑声：\\n\\n1. 停留20—60秒，不立刻拿手机。\\n2. 注意感官、情绪和身体变化。\\n3. 用一句话描述“这一刻对我好在哪里”。\\n4. 若拍照，先体验再拍，并允许不发布。\\n5. 晚上回忆一次，观察细节是否仍然清晰。\\n\\n## 反比较重点\\n\\n品味不需要证明生活精彩，也不需要与别人的体验相比。一个时刻的价值来自你真实经历了它，而不是有多少人看见。\\n\\n## 练习边界\\n\\n品味不是持续追求快乐，也不要求在悲伤时寻找亮点。系统综述提示品味干预可能提升幸福感，但研究异质性较高，应把它当练习而非疗效承诺。\\n\\n## 训练建议\\n\\n先连续练习两到四周，再根据真实体验决定是否保留。每次只选择一种训练，不要同时完成整套清单。若练习引发明显羞耻、反刍或强迫感，应缩短、暂停，或在专业支持下调整。', '好事情发生时第一反应总是拍照发布，之后却很少记得自己真正感受了什么时。', '参考：Smith等，2024，品味干预系统综述与元分析；Gander等，2016。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (310, 7, '关系支持证据簿：记录现实中的连接', '## 训练目标\\n\\n点赞、已读和群聊反应容易成为关系质量的替代指标。关系支持证据簿记录现实中更有分量的连接证据，减少一次线上冷淡对整体归属感的垄断。\\n\\n## 练习步骤\\n\\n每周记录三类具体事件：\\n\\n1. **被支持**：谁认真听过你、提供过帮助或记得你的需要。\\n2. **我支持别人**：你怎样回应、陪伴或承担。\\n3. **关系可以修复**：一次误会、延迟回复或冲突后来怎样发展。\\n\\n只记录行为事实，不要求关系完美。每月回看：哪些关系值得继续投入，哪些只是通讯录里的存在？\\n\\n## 反比较重点\\n\\n别人公开的合照和互动数量不能替代你对关系质量的真实观察。深度连接往往低频、私密，也不适合被平台完整呈现。\\n\\n## 练习边界\\n\\n证据簿不应强迫你为伤害性关系寻找优点。若记录长期只有单向付出、控制或贬低，这可能提示需要边界和现实支持，而不是继续自我安抚。\\n\\n## 训练建议\\n\\n先连续练习两到四周，再根据真实体验决定是否保留。每次只选择一种训练，不要同时完成整套清单。若练习引发明显羞耻、反刍或强迫感，应缩短、暂停，或在专业支持下调整。', '一次已读不回或群聊冷场，就让你怀疑自己根本没有任何可靠关系时。', '参考：Gander等，2016，积极关系干预；自我同情与社会连接相关研究框架。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (311, 7, '身体功能欣赏书写：从“看起来怎样”转向“能做什么”', '## 训练目标\\n\\n外貌比较把身体变成被观看和排名的对象。功能欣赏训练关注身体能够完成、感受和承载的事情，例如移动、呼吸、学习、表达、休息和与人连接，从而扩展身体价值。\\n\\n## 练习步骤\\n\\n每周进行两到三次短写作，每次选择一个领域：\\n\\n- 身体帮助我完成了什么行动。\\n- 感官让我体验了什么。\\n- 身体如何与别人连接。\\n- 身体怎样恢复、保护或提醒我需要休息。\\n- 我可以怎样更实际地照顾这一功能。\\n\\n使用具体语言，如“腿让我走到教室”，而不是要求自己赞美外貌。\\n\\n## 反比较重点\\n\\n练习不需要否认外貌在社会中的影响，也不需要喜欢身体所有部分。目标是减少外貌成为身体唯一价值来源的状态。\\n\\n## 练习边界\\n\\n身体功能也存在疾病、残障和限制，不能用“感恩身体能做什么”否定真实痛苦。研究支持功能导向干预具有潜力，但人群和效果存在差异。\\n\\n## 训练建议\\n\\n先连续练习两到四周，再根据真实体验决定是否保留。每次只选择一种训练，不要同时完成整套清单。若练习引发明显羞耻、反刍或强迫感，应缩短、暂停，或在专业支持下调整。', '刷到高颜值或身材内容后，只能用外貌标准看待自己的身体时。', '参考：Linardon等，2023元分析；Alleva等，2018随机试验；Guest等，2019综述。', 1, 1, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (312, 7, '中性身体描述：停止每天给外貌打总分', '## 训练目标\\n\\n从强烈外貌厌恶直接跳到“我很美”可能让人难以相信。中性描述训练先减少持续评价，用颜色、形状、状态和功能等观察性语言替代“丑、失败、不能见人”的整体判决。\\n\\n## 练习步骤\\n\\n在镜子前或穿衣时，选择一个低敏感部位，练习三类句子：\\n\\n1. **观察**：“我的头发今天比较蓬松。”\\n2. **状态**：“皮肤有一些痘印，今天比昨天干。”\\n3. **功能或照顾**：“双手让我写字，我可以给它们涂护手霜。”\\n\\n发现评价词时，不必批评自己，只改写为可观察描述。每次1—2分钟即可。\\n\\n## 反比较重点\\n\\n中性语言不需要比别人好，也不要求从外貌获得自信。它训练身体不必每天参加一场内部评分。\\n\\n## 练习边界\\n\\n若照镜子会引发长时间检查、进食问题或强烈痛苦，不建议自行增加镜前练习，应寻求身体意象或进食障碍专业支持。\\n\\n## 训练建议\\n\\n先连续练习两到四周，再根据真实体验决定是否保留。每次只选择一种训练，不要同时完成整套清单。若练习引发明显羞耻、反刍或强迫感，应缩短、暂停，或在专业支持下调整。', '每天照镜子都自动给外貌打总分，且很难相信积极肯定语时。', '参考：积极身体意象干预综述；Guest等，2019；Liu等，2025数字干预元分析。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (313, 7, '把向上比较转化为可选信息，而不是人格判决', '## 训练目标\\n\\n向上比较既可能带来灵感，也可能变成“他做到了，所以我不行”。本训练保留可用信息，同时切断别人结果与自身整体价值之间的自动等号。\\n\\n## 练习步骤\\n\\n选一条让你羡慕或受挫的内容，回答四个问题：\\n\\n1. 我具体羡慕的是什么：资源、技能、体验、认可还是自由？\\n2. 其中哪些是我真正重视的，哪些只是看起来有地位？\\n3. 对方路径中有哪些条件我并不了解或无法复制？\\n4. 我可以借鉴一个什么小元素，而不复制整套生活？\\n\\n最后写一句：“这是一个可能的方向，不是我的统一标准。”\\n\\n## 反比较重点\\n\\n训练既不贬低对方，也不要求把嫉妒变成动力。你可以得出“我现在不想行动”或“这并不是我的价值”的结论。\\n\\n## 练习边界\\n\\n若每次分析都让你继续搜索、研究对方和扩大比较，应停止使用该内容作为材料，转而练习价值澄清或关注管理。\\n\\n## 训练建议\\n\\n先连续练习两到四周，再根据真实体验决定是否保留。每次只选择一种训练，不要同时完成整套清单。若练习引发明显羞耻、反刍或强迫感，应缩短、暂停，或在专业支持下调整。', '看到优秀内容后，既有一点启发，又迅速把它变成对自己整个人的否定时。', '参考：社交媒体素养与自我同情干预；Buehler等，2026；Liu等，2025。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
INSERT INTO `knowledge_items` (`id`, `category_id`, `title`, `body`, `applicable_scene`, `source_note`, `is_enabled`, `is_home_recommended`, `updated_by_admin_id`, `deleted_at`, `created_at`, `updated_at`) VALUES (314, 7, '建立自己的“够好标准”，减少平台式无限升级', '## 训练目标\\n\\n平台不断呈现更高水平，使任何成果都可以被下一条内容立即压过。“够好标准”不是降低所有要求，而是提前定义在当前资源和阶段下，什么程度已经满足核心需要，防止目标无限升级。\\n\\n## 练习步骤\\n\\n选择一个容易比较的领域，例如学习、健身、穿搭或创作，写出三层标准：\\n\\n- **最低维持**：状态差时仍能保护生活的程度。\\n- **当前够好**：在现阶段资源下可持续、能满足核心目标。\\n- **理想探索**：有余力时尝试，不完成也不影响自我价值。\\n\\n每月检查一次标准是否仍符合现实，而不是看到别人后当天提高。\\n\\n## 反比较重点\\n\\n别人的理想水平不能直接变成你的最低标准。够好不是停滞，而是让成长拥有边界、成本意识和阶段性。\\n\\n## 练习边界\\n\\n标准不能用来忽视明确的安全、职业或学业底线。若你总把“够好”写成接近完美，说明需要重新评估资源、代价和价值优先级。\\n\\n## 训练建议\\n\\n先连续练习两到四周，再根据真实体验决定是否保留。每次只选择一种训练，不要同时完成整套清单。若练习引发明显羞耻、反刍或强迫感，应缩短、暂停，或在专业支持下调整。', '无论做到什么，刷到更优秀的人后就立刻提高要求，永远感觉不够时。', '参考：ACT价值生活与心理灵活性元分析；Han与Kim，2022；A-Tjak等，2015。', 1, 0, NULL, NULL, '2026-06-17 15:19:39', '2026-06-17 15:19:39');
